window.CQE_META={"version":"2.0","domains":{"1":{"title":{"ar":"الإدارة والقيادة","en":"Management and Leadership"},"weight":17,"desc":{"ar":"الفلسفات والاستراتيجية والقيادة والعملاء والموردون وأخلاقيات المهنة.","en":"Philosophies, strategy, leadership, customers, suppliers, and professional ethics."}},"2":{"title":{"ar":"نظام الجودة","en":"The Quality System"},"weight":18,"desc":{"ar":"تصميم QMS والوثائق والمعايير والتدقيق وتكلفة الجودة والتدريب.","en":"QMS design, documentation, standards, auditing, cost of quality, and training."}},"3":{"title":{"ar":"تصميم المنتج والعملية والخدمة","en":"Product, Process, and Service Design"},"weight":21,"desc":{"ar":"CTQ وDFX وGD&T والتحقق والتصديق والاعتمادية وتحليل الفشل.","en":"CTQs, DFX, GD&T, verification, validation, reliability, and failure analysis."}},"4":{"title":{"ar":"ضبط المنتج والعملية","en":"Product and Process Control"},"weight":23,"desc":{"ar":"خطط التحكم والمواد والعينات والقياس والمترولوجيا وMSA.","en":"Control plans, material control, sampling, measurement, metrology, and MSA."}},"5":{"title":{"ar":"التحسين المستمر","en":"Continuous Improvement"},"weight":26,"desc":{"ar":"أدوات الجودة وLean وSix Sigma وRCA والإجراءات التصحيحية والوقاية.","en":"Quality tools, Lean, Six Sigma, RCA, corrective action, and prevention."}},"6":{"title":{"ar":"الطرق الكمية والأدوات","en":"Quantitative Methods and Tools"},"weight":34,"desc":{"ar":"الإحصاء والاحتمالات والفرضيات وSPC والقدرة وDOE.","en":"Statistics, probability, hypothesis tests, SPC, capability, and DOE."}},"7":{"title":{"ar":"إدارة المخاطر","en":"Risk Management"},"weight":21,"desc":{"ar":"تحديد المخاطر وتقييمها ومعالجتها ومراقبتها واستمرارية الأعمال.","en":"Risk identification, assessment, treatment, monitoring, and business continuity."}}},"glossary":[{"term":"AQL","def":{"ar":"حد الجودة المقبول لسلسلة دفعات","en":"Acceptable quality limit for a continuing series of lots"}},{"term":"LTPD","def":{"ar":"مستوى جودة رديء يرغب العميل في رفضه غالبًا","en":"Poor quality level the consumer wants rejected most of the time"}},{"term":"Producer's Risk","def":{"ar":"احتمال رفض دفعة جيدة ويرمز له α","en":"Probability of rejecting a good lot, denoted α"}},{"term":"Consumer's Risk","def":{"ar":"احتمال قبول دفعة سيئة ويرمز له β","en":"Probability of accepting a bad lot, denoted β"}},{"term":"CTQ","def":{"ar":"خاصية قابلة للقياس مرتبطة بحاجة حرجة أو خطر","en":"Measurable characteristic tied to a critical need or risk"}},{"term":"QMS","def":{"ar":"منظومة العمليات والسياسات والموارد لتحقيق نتائج الجودة","en":"System of processes, policies, and resources used to achieve quality outcomes"}},{"term":"QIS","def":{"ar":"نظام جمع وإدارة وتحليل وعرض معلومات الجودة","en":"System for collecting, managing, analyzing, and presenting quality information"}},{"term":"RACI","def":{"ar":"مصفوفة Responsible, Accountable, Consulted, Informed","en":"Matrix defining Responsible, Accountable, Consulted, and Informed roles"}},{"term":"Verification","def":{"ar":"إثبات أن مخرجات التصميم تحقق المدخلات","en":"Confirmation that design outputs meet design inputs"}},{"term":"Validation","def":{"ar":"إثبات أن الاستخدام المقصود واحتياج المستخدم محققان","en":"Confirmation that intended use and user needs are fulfilled"}},{"term":"IQ","def":{"ar":"إثبات تركيب المعدات أو النظام بصورة صحيحة","en":"Confirmation that equipment or a system is installed correctly"}},{"term":"OQ","def":{"ar":"إثبات التشغيل خلال النطاقات المحددة","en":"Confirmation of operation across specified ranges"}},{"term":"PQ","def":{"ar":"إثبات الأداء المتكرر في ظروف الإنتاج الفعلية","en":"Confirmation of repeatable performance under actual production conditions"}},{"term":"FMEA","def":{"ar":"تحليل استباقي لأنماط الفشل وآثارها وأسبابها وضوابطها","en":"Proactive analysis of failure modes, effects, causes, and controls"}},{"term":"FMECA","def":{"ar":"FMEA مع تحليل إضافي للحرجية","en":"FMEA with added criticality analysis"}},{"term":"FTA","def":{"ar":"تحليل Top-down يبدأ بحدث علوي غير مرغوب","en":"Top-down analysis beginning with an undesired top event"}},{"term":"RPN","def":{"ar":"حاصل ضرب Severity × Occurrence × Detection","en":"Product of Severity × Occurrence × Detection"}},{"term":"MTBF","def":{"ar":"متوسط الزمن بين الأعطال لنظام قابل للإصلاح","en":"Mean time between failures for a repairable system"}},{"term":"MTTR","def":{"ar":"متوسط زمن الإصلاح","en":"Mean time to repair"}},{"term":"Availability","def":{"ar":"نسبة الزمن الذي يكون فيه الأصل قادرًا على العمل","en":"Proportion of time an asset is capable of operating"}},{"term":"Repeatability","def":{"ar":"تباين القياس لنفس المقيم والجهاز والجزء","en":"Measurement variation for the same appraiser, instrument, and part"}},{"term":"Reproducibility","def":{"ar":"تباين القياس بين المقيمين أو الظروف","en":"Measurement variation among appraisers or conditions"}},{"term":"Bias","def":{"ar":"فرق متوسط القياسات عن القيمة المرجعية","en":"Difference between average measurement and reference value"}},{"term":"Linearity","def":{"ar":"تغير الانحياز عبر نطاق القياس","en":"Change in bias across the measurement range"}},{"term":"Stability","def":{"ar":"تغير أداء نظام القياس مع الزمن","en":"Change in measurement-system performance over time"}},{"term":"Traceability","def":{"ar":"سلسلة موثقة غير منقطعة إلى مرجع معترف به","en":"Unbroken documented chain to a recognized reference"}},{"term":"Control Limit","def":{"ar":"حد إحصائي مشتق من بيانات العملية","en":"Statistical limit calculated from process data"}},{"term":"Specification Limit","def":{"ar":"حد يحدده التصميم أو العميل","en":"Limit defined by design or customer requirements"}},{"term":"Common Cause","def":{"ar":"تباين متأصل في النظام","en":"Variation inherent in the system"}},{"term":"Special Cause","def":{"ar":"تباين ناتج عن حدث أو مصدر غير معتاد","en":"Variation caused by an unusual event or source"}},{"term":"Cp","def":{"ar":"قدرة محتملة تقارن عرض المواصفة بالتباين قصير المدى","en":"Potential capability comparing specification width with short-term variation"}},{"term":"Cpk","def":{"ar":"قدرة تأخذ تمركز المتوسط وأقرب حد مواصفة","en":"Capability considering process centering and nearest specification limit"}},{"term":"Pp","def":{"ar":"أداء محتمل باستخدام التباين الكلي طويل المدى","en":"Potential performance using overall long-term variation"}},{"term":"Ppk","def":{"ar":"أداء فعلي يأخذ التمركز والتباين الكلي","en":"Actual performance considering centering and overall variation"}},{"term":"OEE","def":{"ar":"حاصل ضرب Availability × Performance × Quality","en":"Product of Availability × Performance × Quality"}},{"term":"Takt Time","def":{"ar":"الوقت المتاح مقسومًا على طلب العميل","en":"Available production time divided by customer demand"}},{"term":"DPMO","def":{"ar":"عدد العيوب لكل مليون فرصة","en":"Defects per million opportunities"}},{"term":"Poka-Yoke","def":{"ar":"منع الخطأ أو كشفه فورًا عند المصدر","en":"Error prevention or immediate detection at the source"}},{"term":"SMED","def":{"ar":"منهج تقليل زمن تغيير الإعداد","en":"Method for reducing setup or changeover time"}},{"term":"Kanban","def":{"ar":"إشارة سحب تحد WIP وتربط الإنتاج بالاستهلاك","en":"Pull signal that limits WIP and links production to consumption"}},{"term":"PDCA/PDSA","def":{"ar":"دورة تعلم وتحسين: Plan, Do, Check/Study, Act","en":"Learning and improvement cycle: Plan, Do, Check/Study, Act"}},{"term":"DMAIC","def":{"ar":"Define, Measure, Analyze, Improve, Control","en":"Define, Measure, Analyze, Improve, Control"}},{"term":"DOE","def":{"ar":"تصميم منظم لتجارب عوامل متعددة وتفاعلاتها","en":"Structured design for studying multiple factors and interactions"}},{"term":"Type I Error","def":{"ar":"رفض H0 وهي صحيحة","en":"Rejecting a true null hypothesis"}},{"term":"Type II Error","def":{"ar":"عدم رفض H0 وهي خاطئة","en":"Failing to reject a false null hypothesis"}},{"term":"Power","def":{"ar":"احتمال كشف أثر موجود ويساوي 1−β","en":"Probability of detecting a real effect, equal to 1−β"}},{"term":"p-value","def":{"ar":"احتمال نتيجة مساوية أو أشد تطرفًا بافتراض صحة H0","en":"Probability of an equally or more extreme result assuming H0 is true"}},{"term":"Confidence Interval","def":{"ar":"فترة تقدير لمعلم باستخدام طريقة ذات تغطية محددة","en":"Interval estimate produced by a method with stated coverage"}},{"term":"Tolerance Interval","def":{"ar":"فترة تهدف لتغطية نسبة من المجتمع بثقة محددة","en":"Interval intended to cover a population proportion with stated confidence"}},{"term":"RTO","def":{"ar":"الزمن المستهدف لاستعادة الخدمة","en":"Target time to restore a service"}},{"term":"RPO","def":{"ar":"النقطة الزمنية المقبولة لفقد البيانات","en":"Acceptable time-based data-loss point"}},{"term":"Residual Risk","def":{"ar":"الخطر المتبقي بعد تطبيق الضوابط","en":"Risk remaining after controls are applied"}},{"term":"Inherent Risk","def":{"ar":"الخطر قبل تطبيق الضوابط","en":"Risk before controls are applied"}},{"term":"MRB","def":{"ar":"فريق مخول لتقييم والتصرف في المنتج غير المطابق","en":"Authorized body that evaluates and disposes nonconforming product"}},{"term":"Rework","def":{"ar":"إعادة المنتج إلى المواصفة الأصلية","en":"Action restoring product to original conformity"}},{"term":"Repair","def":{"ar":"جعل المنتج صالحًا دون استعادة المواصفة الأصلية بالكامل","en":"Action making product usable without fully restoring original conformity"}}],"extraQuestions":[{"domain":1,"q":{"ar":"أي أسلوب قرار يناسب طوارئ سلامة تتطلب استجابة فورية؟","en":"Which decision style best fits an urgent safety emergency?"},"options":{"ar":["Consensus طويل","Autocratic/Directive مؤقت","NGT فقط","Benchmarking"],"en":["Extended consensus","Temporary autocratic/directive decision","NGT only","Benchmarking"]},"answer":1,"rationale":{"ar":"الطوارئ قد تحتاج توجيهًا سريعًا مع مراجعة لاحقة.","en":"Emergencies may require rapid direction followed by review."}},{"domain":1,"q":{"ar":"ما الخطوة الأولى في Cost-Benefit Analysis؟","en":"What is the first step in cost-benefit analysis?"},"options":{"ar":["تغيير الأرقام","تحديد البدائل وحالة الأساس","حساب Cpk","إغلاق المشروع"],"en":["Change the numbers","Define alternatives and the baseline","Calculate Cpk","Close the project"]},"answer":1,"rationale":{"ar":"لا يمكن مقارنة المنافع دون Baseline وبدائل محددة.","en":"Benefits cannot be compared without a baseline and defined alternatives."}},{"domain":1,"q":{"ar":"أي عامل يمثل عائقًا نظاميًا للتحسين؟","en":"Which factor represents a systemic barrier to improvement?"},"options":{"ar":["عامل أخطأ مرة","حافز يكافئ الكمية ويتجاهل الجودة","سؤال في اجتماع","أداة معايرة"],"en":["One worker made one error","An incentive that rewards output and ignores quality","A meeting question","A calibration tool"]},"answer":1,"rationale":{"ar":"نظام الحوافز قد يدفع سلوكًا غير مرغوب عبر المنظمة.","en":"The incentive system may drive undesirable behavior organization-wide."}},{"domain":2,"q":{"ar":"أي عنصر يعد Appraisal Cost؟","en":"Which item is an appraisal cost?"},"options":{"ar":["FMEA قبل التصميم","الفحص النهائي","ضمان العميل","خردة"],"en":["FMEA before design","Final inspection","Customer warranty","Scrap"]},"answer":1,"rationale":{"ar":"الفحص والاختبار والتدقيق ضمن التقييم.","en":"Inspection, testing, and auditing are appraisal activities."}},{"domain":2,"q":{"ar":"متى يكون تدقيق العملية أنسب من تدقيق النظام؟","en":"When is a process audit more appropriate than a system audit?"},"options":{"ar":["عند تقييم فعالية تدفق تصنيع محدد","عند تقييم المنظمة كلها","عند تسجيل براءة اختراع","عند حساب OEE فقط"],"en":["When evaluating effectiveness of a specific manufacturing flow","When evaluating the entire organization","When registering a patent","When only calculating OEE"]},"answer":0,"rationale":{"ar":"Process audit يتبع خطوات وضوابط ومخرجات عملية محددة.","en":"A process audit follows the steps, controls, and outputs of a specific process."}},{"domain":2,"q":{"ar":"ما الذي يثبت إغلاق عدم مطابقة تدقيق بصورة صحيحة؟","en":"What demonstrates proper closure of an audit nonconformity?"},"options":{"ar":["كتابة الإجراء فقط","التحقق من التنفيذ والفعالية","مرور أسبوع","تغيير المدقق"],"en":["Writing the action only","Verification of implementation and effectiveness","One week passing","Changing the auditor"]},"answer":1,"rationale":{"ar":"الإغلاق يتطلب دليلًا أن السبب عولج وأن النتيجة فعالة.","en":"Closure requires evidence that the cause was addressed and the action is effective."}},{"domain":3,"q":{"ar":"في Series Reliability، إذا R1=0.9 وR2=0.8 فما Rsystem؟","en":"For a series system with R1=0.9 and R2=0.8, what is Rsystem?"},"options":{"ar":["0.72","0.98","1.70","0.10"],"en":["0.72","0.98","1.70","0.10"]},"answer":0,"rationale":{"ar":"في Series تضرب الموثوقيات: 0.9×0.8=0.72.","en":"For a series system, reliabilities multiply: 0.9×0.8=0.72."}},{"domain":3,"q":{"ar":"أي نشاط يمثل Validation؟","en":"Which activity represents validation?"},"options":{"ar":["مراجعة الرسم مقابل المدخلات","اختبار مستخدمين فعليين للغرض المقصود","تدقيق الوثيقة","معايرة الميكرومتر"],"en":["Reviewing a drawing against inputs","Testing actual users for intended use","Auditing the document","Calibrating a micrometer"]},"answer":1,"rationale":{"ar":"Validation يثبت ملاءمة الاستخدام المقصود.","en":"Validation demonstrates suitability for intended use."}},{"domain":3,"q":{"ar":"أي FMEA يركز على أخطاء الاستخدام المتوقع؟","en":"Which FMEA focuses on foreseeable use errors?"},"options":{"ar":["dFMEA","pFMEA","uFMEA","FMECA فقط"],"en":["dFMEA","pFMEA","uFMEA","FMECA only"]},"answer":2,"rationale":{"ar":"uFMEA يركز على الاستخدام وسوء الاستخدام المتوقع.","en":"uFMEA focuses on use and foreseeable misuse."}},{"domain":4,"q":{"ar":"إذا كانت الخطة n=30,c=0 ووجد عيب واحد، فالقرار؟","en":"For a plan n=30,c=0 with one nonconforming unit found, what is the decision?"},"options":{"ar":["قبول","رفض","إعادة حساب Cp","لا قرار"],"en":["Accept","Reject","Recalculate Cp","No decision"]},"answer":1,"rationale":{"ar":"c=0 يسمح بصفر وحدات غير مطابقة فقط.","en":"c=0 allows zero nonconforming units."}},{"domain":4,"q":{"ar":"أي حالة تصف Bias؟","en":"Which situation describes bias?"},"options":{"ar":["اختلاف المقيمين","متوسط القياس يبعد ثابتًا عن المرجع","تغير مع الزمن","عدم ثبات القطع"],"en":["Differences among appraisers","Average measurement is consistently offset from reference","Change over time","Part instability"]},"answer":1,"rationale":{"ar":"Bias هو الانحراف المتوسط عن القيمة المرجعية.","en":"Bias is the average offset from the reference value."}},{"domain":4,"q":{"ar":"إذا اختلف Bias عند القيم الصغيرة والكبيرة، فالمشكلة؟","en":"If bias differs at low and high values, what is the issue?"},"options":{"ar":["Linearity","Repeatability","Traceability","AQL"],"en":["Linearity","Repeatability","Traceability","AQL"]},"answer":0,"rationale":{"ar":"Linearity هي تغير الانحياز عبر النطاق.","en":"Linearity is change in bias across the range."}},{"domain":4,"q":{"ar":"أي تصرف يحتاج غالبًا موافقة عميل أو سلطة هندسية؟","en":"Which disposition often requires customer or engineering authorization?"},"options":{"ar":["Rework مطابق","Use-as-is/Concession","إعادة الفحص الروتيني","وسم العينة"],"en":["Conforming rework","Use-as-is/concession","Routine reinspection","Sample labeling"]},"answer":1,"rationale":{"ar":"القبول الاستثنائي يغير قرار المطابقة ويحتاج سلطة مناسبة.","en":"Concession changes the conformity decision and needs appropriate authority."}},{"domain":5,"q":{"ar":"أي هدر يصف انتظار المشغل موافقة؟","en":"Which waste describes an operator waiting for approval?"},"options":{"ar":["Motion","Waiting","Overprocessing","Transportation"],"en":["Motion","Waiting","Overprocessing","Transportation"]},"answer":1,"rationale":{"ar":"الزمن دون إضافة قيمة بسبب تأخر الموافقة Waiting.","en":"Time without value addition due to delayed approval is waiting."}},{"domain":5,"q":{"ar":"أي أداة تستخدم لتقليل زمن تغيير القالب؟","en":"Which tool is used to reduce die-change time?"},"options":{"ar":["SMED","QFD","ANOVA","Z1.4"],"en":["SMED","QFD","ANOVA","Z1.4"]},"answer":0,"rationale":{"ar":"SMED يركز على فصل وتحويل وتبسيط أنشطة الإعداد.","en":"SMED separates, converts, and simplifies setup activities."}},{"domain":5,"q":{"ar":"Correction تعني:","en":"Correction means:"},"options":{"ar":["إزالة السبب الجذري","إصلاح الحالة الحالية","تغيير كل النظام","قبول الخطر"],"en":["Remove root cause","Fix the current condition","Change the whole system","Accept risk"]},"answer":1,"rationale":{"ar":"Correction تعالج الحالة؛ Corrective Action تعالج السبب.","en":"Correction addresses the condition; corrective action addresses the cause."}},{"domain":5,"q":{"ar":"أي مكون OEE يتأثر بالخردة؟","en":"Which OEE component is affected by scrap?"},"options":{"ar":["Availability","Performance","Quality","Takt"],"en":["Availability","Performance","Quality","Takt"]},"answer":2,"rationale":{"ar":"الخردة تقلل Good Count وبالتالي Quality.","en":"Scrap reduces good count and therefore quality."}},{"domain":5,"q":{"ar":"في 5S، ماذا يعني Sustain؟","en":"In 5S, what does Sustain mean?"},"options":{"ar":["تنظيف مرة واحدة","تحويل المعيار إلى عادة ومراجعة مستمرة","شراء معدات","زيادة المخزون"],"en":["One-time cleaning","Making the standard a habit with ongoing review","Buying equipment","Increasing inventory"]},"answer":1,"rationale":{"ar":"Sustain يثبت الانضباط والمعيار على المدى الطويل.","en":"Sustain embeds discipline and the standard over time."}},{"domain":5,"q":{"ar":"ما أفضل تصرف بعد Pilot ناجح؟","en":"What is the best action after a successful pilot?"},"options":{"ar":["التعميم دون توثيق","تقييم المخاطر وتوحيد المعيار وخطة السيطرة","إلغاء القياس","تغيير الهدف"],"en":["Deploy without documentation","Assess risk, standardize, and establish a control plan","Stop measurement","Change the objective"]},"answer":1,"rationale":{"ar":"التحسين يحتاج Standardization وControl للحفاظ على المكاسب.","en":"Improvement requires standardization and control to sustain gains."}},{"domain":6,"q":{"ar":"ما المتوسط للقيم 2,4,6,8؟","en":"What is the mean of 2, 4, 6, and 8?"},"options":{"ar":["4","5","6","20"],"en":["4","5","6","20"]},"answer":1,"rationale":{"ar":"المجموع 20 مقسومًا على 4 يساوي 5.","en":"The sum is 20 divided by 4, equal to 5."}},{"domain":6,"q":{"ar":"إذا p=0.03 وα=0.05، فالقرار المعتاد؟","en":"If p=0.03 and α=0.05, what is the usual decision?"},"options":{"ar":["لا نرفض H0","نرفض H0","نثبت H1 100%","نغير α"],"en":["Fail to reject H0","Reject H0","Prove H1 with 100% certainty","Change α"]},"answer":1,"rationale":{"ar":"p≤α يعطي دليلًا كافيًا لرفض H0 ضمن الافتراضات.","en":"p≤α provides sufficient evidence to reject H0 under the assumptions."}},{"domain":6,"q":{"ar":"أي مخطط يناسب عدد العيوب مع فرصة ثابتة؟","en":"Which chart fits defect counts with constant opportunity?"},"options":{"ar":["p","np","c","u"],"en":["p","np","c","u"]},"answer":2,"rationale":{"ar":"c Chart لعدد العيوب عندما تكون الفرصة ثابتة.","en":"A c chart is for defect counts with constant opportunity."}},{"domain":6,"q":{"ar":"إذا زاد المتوسط قرب USL وبقي σ ثابتًا، ماذا يحدث غالبًا لـCpk؟","en":"If the mean moves toward the USL while σ stays constant, what generally happens to Cpk?"},"options":{"ar":["يزداد","ينخفض","لا يتغير","يصبح Cp"],"en":["It increases","It decreases","It does not change","It becomes Cp"]},"answer":1,"rationale":{"ar":"المسافة إلى أقرب حد تقل، فينخفض Cpk.","en":"Distance to the nearest limit decreases, lowering Cpk."}},{"domain":6,"q":{"ar":"ما احتمال المكمل إذا P(A)=0.35؟","en":"What is the complement probability if P(A)=0.35?"},"options":{"ar":["0.35","0.65","1.35","0.1225"],"en":["0.35","0.65","1.35","0.1225"]},"answer":1,"rationale":{"ar":"P(Aᶜ)=1−0.35=0.65.","en":"P(Aᶜ)=1−0.35=0.65."}},{"domain":6,"q":{"ar":"أي تصميم يدرس جميع تركيبات مستويات العوامل؟","en":"Which design studies all combinations of factor levels?"},"options":{"ar":["Full factorial","Check sheet","Sampling plan","Run chart"],"en":["Full factorial","Check sheet","Sampling plan","Run chart"]},"answer":0,"rationale":{"ar":"Full Factorial يشمل كل التركيبات.","en":"A full factorial includes all combinations."}},{"domain":6,"q":{"ar":"إذا كان الارتباط r≈0، ماذا نستنتج؟","en":"If correlation r≈0, what can be concluded?"},"options":{"ar":["لا توجد أي علاقة","لا توجد علاقة خطية قوية، وقد توجد علاقة غير خطية","السببية مثبتة","النموذج ممتاز"],"en":["There is no relationship of any kind","There is no strong linear relationship; a nonlinear relationship may exist","Causality is proven","The model is excellent"]},"answer":1,"rationale":{"ar":"r يقيس العلاقة الخطية فقط.","en":"r measures linear association only."}},{"domain":6,"q":{"ar":"أي مخطط يُحلل أولًا في X-bar/R؟","en":"Which chart should be evaluated first in an X-bar/R pair?"},"options":{"ar":["X-bar فقط","R chart","p chart","Histogram"],"en":["X-bar only","R chart","p chart","Histogram"]},"answer":1,"rationale":{"ar":"استقرار التشتت ضروري قبل تفسير المتوسط.","en":"Stable dispersion is necessary before interpreting the mean chart."}},{"domain":7,"q":{"ar":"أي استراتيجية خطر يمثلها التأمين؟","en":"Which risk strategy is represented by insurance?"},"options":{"ar":["Avoid","Transfer/Share","Eliminate occurrence","Poka-Yoke"],"en":["Avoid","Transfer/Share","Eliminate occurrence","Poka-Yoke"]},"answer":1,"rationale":{"ar":"التأمين ينقل جزءًا من العاقبة المالية.","en":"Insurance transfers part of the financial consequence."}},{"domain":7,"q":{"ar":"ما الأداة الأساسية لتوثيق المالك والإجراء والموعد والخطر المتبقي؟","en":"Which tool records owner, action, due date, and residual risk?"},"options":{"ar":["Risk register","Histogram","Control chart","QFD"],"en":["Risk register","Histogram","Control chart","QFD"]},"answer":0,"rationale":{"ar":"Risk Register هو السجل المركزي لتتبع المخاطر.","en":"The risk register is the central tool for tracking risks."}},{"domain":7,"q":{"ar":"أي خطة تختبر عادة بتمرين Tabletop؟","en":"Which plan is commonly tested through a tabletop exercise?"},"options":{"ar":["Business continuity/contingency plan","Calibration interval","OC curve","Cpk study"],"en":["Business continuity/contingency plan","Calibration interval","OC curve","Cpk study"]},"answer":0,"rationale":{"ar":"Tabletop يختبر الأدوار والقرارات والاتصال في سيناريو طوارئ.","en":"A tabletop exercise tests roles, decisions, and communications in an emergency scenario."}},{"domain":7,"q":{"ar":"بعد تنفيذ Mitigation، ما الخطوة التالية؟","en":"After implementing mitigation, what should be done next?"},"options":{"ar":["حذف الخطر","إعادة تقييم Residual Risk وفعالية الضبط","تغيير المالك فقط","إغلاق السجل فورًا"],"en":["Delete the risk","Reassess residual risk and control effectiveness","Only change the owner","Close immediately"]},"answer":1,"rationale":{"ar":"التنفيذ لا يثبت أن الخطر أصبح مقبولًا.","en":"Implementation does not prove the risk is acceptable."}},{"domain":7,"q":{"ar":"أي مؤشر يمكن أن يكون Early Warning لخطر جودة المنتج؟","en":"Which metric can be an early warning for product-quality risk?"},"options":{"ar":["Complaint trend أو Near Miss","النتيجة السنوية فقط","عدد صفحات الإجراء","لون الملصق"],"en":["Complaint trend or near miss","Annual result only","Number of procedure pages","Label color"]},"answer":0,"rationale":{"ar":"الاتجاهات والـNear Miss تساعد في الكشف المبكر قبل الخسارة الكبيرة.","en":"Trends and near misses support early detection before major loss."}}],"references":[{"title":"The ASQ Certified Quality Engineer Handbook, Fifth Edition","use":{"ar":"تحديد نطاق 2022 CQE Body of Knowledge، الأوزان، مستويات الإدراك، والمحتوى الجديد مثل RACI وCTQ وOEE و5 Whys وData Automation وإدارة المخاطر.","en":"Used for the 2022 CQE Body of Knowledge, exam weights, cognitive levels, and new topics such as RACI, CTQ, OEE, 5 Whys, data automation, and risk management."}},{"title":"The Certified Quality Engineer Handbook, Fourth Edition","use":{"ar":"الشرح التفصيلي والأمثلة والمعادلات والجداول في الفصول السبعة والملاحق الإحصائية.","en":"Used for detailed explanations, examples, equations, tables, and statistical appendices across the seven chapters."}},{"title":"ASQ CQE 2022 Body of Knowledge","use":{"ar":"مطابقة كل وحدة مع مستوى Remember أو Understand أو Apply أو Analyze أو Evaluate.","en":"Used to align each unit with the intended Remember, Understand, Apply, Analyze, or Evaluate level."}}],"officialDistribution":{"1":17,"2":18,"3":21,"4":23,"5":26,"6":34,"7":21}};


window.CQE_DOMAINS=window.CQE_DOMAINS||[];
window.CQE_DOMAINS.push({"id":1,"title":{"ar":"الإدارة والقيادة","en":"Management and Leadership"},"weight":17,"desc":{"ar":"الفلسفات والاستراتيجية والقيادة والعملاء والموردون وأخلاقيات المهنة.","en":"Philosophies, strategy, leadership, customers, suppliers, and professional ethics."},"lessons":[{"domain":1,"code":"1.1","title":{"ar":"تعريف الجودة وتطور المهنة","en":"Quality Definitions and Evolution"},"level":"Understand","ref":"5th ed., Ch. 1; 4th ed., pp. 2–11","concept":{"ar":"الجودة ليست الفخامة ولا الفحص النهائي فقط. ينظر مهندس الجودة إليها باعتبارها المطابقة للمتطلبات، والملاءمة للاستخدام، وتقليل التباين، وتحقيق القيمة للعميل والمجتمع طوال دورة الحياة. تطورت المهنة من التفتيش بعد الإنتاج إلى ضبط العملية إحصائيًا، ثم ضمان الجودة، ثم أنظمة الإدارة والقيادة بالجودة.","en":"Quality is not luxury and is not limited to final inspection. A quality engineer views it as conformance to requirements, fitness for use, reduction of variation, and delivery of value to customers and society throughout the life cycle. The profession evolved from post-production inspection to statistical process control, quality assurance, and finally organization-wide quality management and leadership."},"steps":{"ar":["ميّز بين حاجة العميل والمواصفة الفنية.","حدد الخاصية القابلة للقياس التي تعبّر عن الجودة.","حدد هل المشكلة اكتشاف عيب، ضبط عملية، أم ضعف في النظام.","اربط القرار بتكلفة دورة الحياة لا بنتيجة الفحص اللحظية فقط."],"en":["Separate the customer need from the technical specification.","Identify a measurable characteristic that represents quality.","Decide whether the issue is defect detection, process control, or system weakness.","Link the decision to life-cycle cost rather than a single inspection result."]},"example":{"ar":"مضخة تحقق معدل التدفق في اختبار القبول، لكنها تتعطل كل شهر. هي مطابقة لحظيًا من ناحية الأداء، لكنها ضعيفة في الاعتمادية والملاءمة للاستخدام.","en":"A pump meets the required flow rate during acceptance testing but fails every month. It is momentarily conforming in performance, yet poor in reliability and fitness for use."},"tip":{"ar":"حدود المواصفة يحددها التصميم أو العميل، أما حدود السيطرة فتُشتق من بيانات العملية؛ لا تخلط بينهما.","en":"Specification limits come from design or customer requirements; control limits are calculated from process data. Do not confuse them."},"formula":"","question":{"q":{"ar":"أي عبارة تمثل منظور Juran بصورة أدق؟","en":"Which statement best represents Juran's view of quality?"},"options":{"ar":["الفحص بنسبة 100%","الملاءمة للاستخدام","انعدام التباين تمامًا","زيادة الخصائص مهما كانت التكلفة"],"en":["100% inspection","Fitness for use","Zero variation under all conditions","Adding features regardless of cost"]},"answer":1,"rationale":{"ar":"جوران عرّف الجودة بأنها الملاءمة للاستخدام من منظور العميل.","en":"Juran defined quality as fitness for use from the customer's perspective."}}},{"domain":1,"code":"1.2","title":{"ar":"رواد الجودة وفلسفاتهم","en":"Quality Gurus and Their Philosophies"},"level":"Understand","ref":"5th ed., Ch. 1; 4th ed., pp. 4–11","concept":{"ar":"أسهم Shewhart في فهم التباين ومخططات السيطرة، وركز Deming على النظام ودورة PDSA وإزالة الخوف، وربط Juran التحسين بالمشروعات وثلاثية التخطيط والضبط والتحسين. شدد Crosby على المطابقة للمتطلبات والوقاية وتكلفة عدم المطابقة، وركز Ishikawa على مشاركة العاملين والأدوات البسيطة، بينما رأى Taguchi أن الخسارة تبدأ بمجرد الابتعاد عن القيمة المستهدفة.","en":"Shewhart established the statistical view of variation and control charts. Deming emphasized the system, PDSA, and removal of fear. Juran linked improvement to projects and the trilogy of planning, control, and improvement. Crosby emphasized conformance, prevention, and the price of nonconformance. Ishikawa promoted employee participation and simple quality tools, while Taguchi viewed loss as increasing whenever performance departs from the target."},"steps":{"ar":["حدد نوع المشكلة: نظامية، مزمنة، أم خطأ فردي خاص.","اختر فلسفة القائد التي تساعد في تفسير المشكلة.","تجنب تحويل شعارات الرواد إلى إجراءات بلا بيانات.","استخدم الفلسفة لتوجيه طريقة التحليل لا لاستبدال التحليل."],"en":["Classify the problem as systemic, chronic, or a special individual event.","Select the philosophy that best frames the issue.","Do not turn gurus' slogans into actions without data.","Use philosophy to guide analysis, not replace analysis."]},"example":{"ar":"زيادة التفتيش بعد ارتفاع العيوب قد تخفض هروب العيب مؤقتًا، لكن Deming سيطلب دراسة النظام الذي ينتج العيب، بينما Juran قد يحوله إلى مشروع تحسين محدد بعائد واضح.","en":"Increasing inspection after defects rise may reduce escapes temporarily. Deming would examine the system producing the defects, while Juran would likely structure a defined improvement project with measurable benefit."},"tip":{"ar":"أسئلة الاختبار كثيرًا ما تعرض موقفًا عمليًا وتطلب تحديد الفلسفة الأقرب، لا مجرد حفظ اسم الرائد.","en":"Exam questions often present a scenario and ask which philosophy applies, rather than asking for a simple name-definition match."},"formula":"","question":{"q":{"ar":"أي رائد يرتبط أكثر بفكرة أن الخسارة تزداد كلما ابتعد الأداء عن القيمة المستهدفة؟","en":"Which guru is most closely associated with loss increasing as performance moves away from the target?"},"options":{"ar":["Crosby","Taguchi","Juran","Ishikawa"],"en":["Crosby","Taguchi","Juran","Ishikawa"]},"answer":1,"rationale":{"ar":"Taguchi صاغ مفهوم دالة الخسارة التي تعاقب الانحراف عن الهدف حتى داخل حدود المواصفة.","en":"Taguchi's loss function assigns loss to deviation from target even when results remain within specification."}}},{"domain":1,"code":"1.3","title":{"ar":"مناهج التحسين: SPC وTQM وLean وSix Sigma","en":"Improvement Approaches: SPC, TQM, Lean, and Six Sigma"},"level":"Understand","ref":"5th ed., Ch. 1; 4th ed., pp. 10–12","concept":{"ar":"SPC يركز على فهم التباين واستقرار العملية، وTQM على الثقافة والعميل ومشاركة المنظمة، وLean على التدفق وإزالة الهدر، وSix Sigma على خفض التباين والعيوب باستخدام DMAIC والتحليل الإحصائي. لا توجد أداة واحدة مناسبة لكل مشكلة؛ يبدأ الاختيار من طبيعة الفجوة والبيانات المتاحة.","en":"SPC focuses on variation and process stability; TQM on culture, customers, and organization-wide participation; Lean on flow and waste removal; and Six Sigma on reducing variation and defects through DMAIC and statistical analysis. No single approach fits every problem; selection starts with the nature of the gap and available evidence."},"steps":{"ar":["عرّف المخرج والعميل والعيب.","تحقق أولًا من استقرار العملية.","حدد هل المشكلة تدفق، تباين، قيد، أم ضعف ثقافي.","اختر المنهج ثم الأدوات، وليس العكس."],"en":["Define the output, customer, and defect.","Check process stability first.","Determine whether the main issue is flow, variation, a constraint, or culture.","Select the approach before selecting tools."]},"example":{"ar":"خط سريع لكنه ينتج عيوبًا متغيرة يحتاج SPC/Six Sigma؛ خط مستقر لكن زمن الانتظار طويل قد يحتاج Lean؛ نظام كامل مقيد بآلة واحدة قد يحتاج Theory of Constraints.","en":"A fast line with unstable defects needs SPC/Six Sigma; a stable line with long waiting may need Lean; a whole system limited by one machine may need the Theory of Constraints."},"tip":{"ar":"الفخ الشائع هو تطبيق Lean لتسريع عملية غير مستقرة، ما قد يسرّع إنتاج العيوب.","en":"A common trap is applying Lean to accelerate an unstable process, which may simply produce defects faster."},"formula":"","question":{"q":{"ar":"أي منهج يبدأ عادةً بتمييز الأسباب العامة عن الأسباب الخاصة للتباين؟","en":"Which approach commonly starts by distinguishing common from special causes of variation?"},"options":{"ar":["TQM","SPC","Benchmarking","QFD"],"en":["TQM","SPC","Benchmarking","QFD"]},"answer":1,"rationale":{"ar":"SPC مبني على تحليل التباين واستخدام مخططات السيطرة.","en":"SPC is built around variation analysis and control charts."}}},{"domain":1,"code":"1.4","title":{"ar":"التخطيط الاستراتيجي ومسؤولية الإدارة العليا","en":"Strategic Planning and Top Management Responsibility"},"level":"Apply","ref":"5th ed., Ch. 1; 4th ed., pp. 12–16","concept":{"ar":"الإدارة العليا مسؤولة عن اتجاه نظام الجودة، السياسة، الأهداف، الموارد، والمراجعة. يجب أن تتحول الاستراتيجية إلى أهداف قابلة للقياس مرتبطة بالعميل والمخاطر والنتائج التشغيلية والمالية. الهدف الجيد يحتوي خط أساس، قيمة مستهدفة، موعدًا، ومالكًا.","en":"Top management is responsible for the direction of the QMS, policy, objectives, resources, and review. Strategy must be translated into measurable objectives connected to customer needs, risks, and operational and financial outcomes. A sound objective has a baseline, target, due date, and owner."},"steps":{"ar":["حلل السياق وأصحاب المصلحة.","حوّل الأولويات إلى أهداف SMART.","حدد المؤشرات القائدة والمتأخرة.","خصص الموارد والمسؤوليات.","راجع الانحرافات واتخذ قرارات تصحيحية."],"en":["Analyze context and stakeholders.","Translate priorities into SMART objectives.","Define leading and lagging indicators.","Assign resources and accountability.","Review deviations and make corrective decisions."]},"example":{"ar":"بدل هدف عام مثل «تحسين الجودة»، يُكتب: خفض PPM لدى العميل من 1800 إلى أقل من 600 خلال تسعة أشهر مع الحفاظ على التسليم في الوقت فوق 95%.","en":"Instead of 'improve quality,' write: reduce customer PPM from 1,800 to below 600 within nine months while keeping on-time delivery above 95%."},"tip":{"ar":"النشاط مثل «متابعة الرفض» ليس هدفًا؛ الهدف يصف نتيجة كمية محددة.","en":"An activity such as 'monitor rejection' is not an objective; an objective states a measurable result."},"formula":"","question":{"q":{"ar":"أي هدف أدناه هو الأكثر اكتمالًا؟","en":"Which objective is the most complete?"},"options":{"ar":["تحسين الجودة قريبًا","تقليل العيوب","خفض الرفض من 4% إلى 2% خلال ستة أشهر مع تحديد مالك العملية","إجراء اجتماعات أسبوعية"],"en":["Improve quality soon","Reduce defects","Reduce rejection from 4% to 2% within six months with a named process owner","Hold weekly meetings"]},"answer":2,"rationale":{"ar":"يتضمن خط أساسًا وهدفًا وزمنًا ومسؤولية واضحة.","en":"It contains a baseline, target, time frame, and clear accountability."}}},{"domain":1,"code":"1.5","title":{"ar":"المقارنة المرجعية وتحليل أصحاب المصلحة","en":"Benchmarking and Stakeholder Analysis"},"level":"Apply","ref":"5th ed., Ch. 1; 4th ed., pp. 15–22","concept":{"ar":"Benchmarking هو تعلم من أداء أو ممارسات مرجعية داخلية أو تنافسية أو وظيفية أو عامة، وليس نسخًا أعمى. تحليل أصحاب المصلحة يحدد القوة والتأثير والاهتمام والتوقعات والمخاطر الناتجة عن كل طرف، ثم يختار أسلوب المشاركة والاتصال المناسب.","en":"Benchmarking is structured learning from internal, competitive, functional, or generic reference practices; it is not blind copying. Stakeholder analysis identifies power, influence, interest, expectations, and risks, then selects the appropriate engagement and communication approach."},"steps":{"ar":["حدد العملية والنتيجة المراد مقارنتها.","اختر مرجعًا مناسبًا وقابلًا للمقارنة.","طبع البيانات لاختلاف الحجم أو المنتج.","افهم الممارسة التي أنتجت النتيجة.","حلل أصحاب المصلحة بخريطة القوة والاهتمام."],"en":["Define the process and outcome to benchmark.","Select a relevant and comparable reference.","Normalize data for differences in scale or product.","Understand the practice behind the result.","Map stakeholders by power and interest."]},"example":{"ar":"مصنع يقارن زمن تغيير القالب مع مصنع آخر. إذا اكتفى بمقارنة الدقائق فلن يتعلم؛ يجب أن يدرس فصل الإعداد الداخلي والخارجي وطريقة SMED المستخدمة.","en":"A plant compares die-change time with another plant. Comparing minutes alone teaches little; it must study how internal and external setup were separated and how SMED was applied."},"tip":{"ar":"أفضل رقم لا يعني أفضل ممارسة في سياقك؛ قارن التعريفات والقيود أولًا.","en":"The best number does not automatically mean the best practice for your context; compare definitions and constraints first."},"formula":"","question":{"q":{"ar":"ما الخطوة الأهم قبل تبني نتيجة Benchmarking؟","en":"What is the most important step before adopting a benchmarking result?"},"options":{"ar":["نسخ الإجراء كاملًا","فهم اختلاف السياق وتعريف المؤشر","شراء نفس المعدات","إخفاء بياناتك الداخلية"],"en":["Copy the entire procedure","Understand contextual and metric-definition differences","Buy identical equipment","Hide internal data"]},"answer":1,"rationale":{"ar":"المقارنة الصحيحة تتطلب تكافؤ التعريفات والسياق قبل نقل الممارسة.","en":"Valid benchmarking requires comparable definitions and context before transferring a practice."}}},{"domain":1,"code":"1.6","title":{"ar":"قياس الأداء وتحليل التكلفة والمنفعة","en":"Performance Measurement and Cost-Benefit Analysis"},"level":"Apply","ref":"5th ed., Ch. 1 new content; 4th ed., pp. 22–34","concept":{"ar":"نظام القياس الجيد يوازن بين الجودة والتكلفة والتسليم والسلامة والعميل. المؤشرات القائدة تنبّه قبل الفشل، والمتأخرة تصف نتيجة حدثت. تحليل التكلفة والمنفعة يقارن البدائل من خلال التكاليف المباشرة وغير المباشرة، المنافع المالية وغير المالية، الزمن، وعدم اليقين.","en":"A sound performance system balances quality, cost, delivery, safety, and customer outcomes. Leading indicators warn before failure; lagging indicators describe outcomes already realized. Cost-benefit analysis compares alternatives using direct and indirect costs, financial and nonfinancial benefits, timing, and uncertainty."},"steps":{"ar":["حدد البدائل وحالة الأساس.","اجمع التكاليف الكاملة والمنافع.","حدد فترة التحليل وافتراضات الحجم.","احسب Payback أو ROI أو NPV حسب الحاجة.","اختبر الحساسية للمخاطر والافتراضات."],"en":["Define alternatives and the baseline case.","Capture total costs and benefits.","Set the analysis horizon and volume assumptions.","Calculate payback, ROI, or NPV as appropriate.","Test sensitivity to assumptions and risks."]},"example":{"ar":"نظام فحص آلي يكلف 400 ألف ريال ويوفر 220 ألفًا سنويًا. فترة الاسترداد البسيطة 1.82 سنة، لكن القرار يجب أن يضيف تكلفة الصيانة وخطر التوقف ومنع شكاوى العملاء.","en":"An automated inspection system costs SAR 400,000 and saves SAR 220,000 per year. Simple payback is 1.82 years, but the decision must also consider maintenance, downtime risk, and prevention of customer complaints."},"tip":{"ar":"لا تستخدم ROI وحده عندما تختلف فترات البدائل أو مستويات المخاطر بصورة كبيرة.","en":"Do not rely on ROI alone when alternatives have very different time horizons or risk profiles."},"formula":"ROI = (Benefit - Cost) / Cost","question":{"q":{"ar":"أي مؤشر يُعد Leading Indicator؟","en":"Which metric is a leading indicator?"},"options":{"ar":["تكلفة مطالبات الضمان الماضية","عدد الاستدعاءات المكتملة","نسبة إكمال الصيانة الوقائية في موعدها","قيمة الخردة المسجلة"],"en":["Historical warranty cost","Completed recalls","Percentage of preventive maintenance completed on time","Recorded scrap value"]},"answer":2,"rationale":{"ar":"الصيانة الوقائية تنذر بإمكانية منع الفشل قبل وقوعه.","en":"Preventive maintenance completion signals the ability to prevent failure before it occurs."}}},{"domain":1,"code":"1.7","title":{"ar":"إدارة المشروعات وRACI وGantt","en":"Project Management, RACI, and Gantt"},"level":"Apply","ref":"5th ed., Ch. 1 new content; 4th ed., pp. 15–34","concept":{"ar":"مشروع الجودة يحتاج نطاقًا واضحًا، مخرجات، مخاطر، موارد، جدولًا، ومالكًا. Gantt يعرض الأنشطة والزمن والتبعيات، بينما RACI يزيل غموض الأدوار: Responsible ينفذ، Accountable مسؤول نهائيًا، Consulted يُستشار، وInformed يُبلّغ.","en":"A quality project requires a clear scope, deliverables, risks, resources, schedule, and owner. A Gantt chart displays activities, timing, and dependencies. RACI removes role ambiguity: Responsible performs the work, Accountable owns the final result, Consulted provides input, and Informed receives updates."},"steps":{"ar":["اكتب Project Charter مختصرًا.","قسم العمل إلى حزم وأنشطة.","اربط التبعيات والموارد.","ضع RACI لكل مخرج حرج.","تابع المخاطر والانحراف الزمني والقيمة المحققة."],"en":["Create a concise project charter.","Break the work into packages and activities.","Link dependencies and resources.","Assign RACI for each critical deliverable.","Monitor risks, schedule variance, and realized benefit."]},"example":{"ar":"في مشروع تخفيض الرفض، مهندس العملية قد يكون Responsible، ومدير الإنتاج Accountable، والجودة والمورد Consulted، والإدارة المالية Informed.","en":"In a rejection-reduction project, the process engineer may be Responsible, the production manager Accountable, quality and supplier representatives Consulted, and finance Informed."},"tip":{"ar":"وجود أكثر من Accountable لنفس المخرج يخلق نزاع قرار؛ الأفضل مسؤول نهائي واحد.","en":"Multiple Accountable roles for one deliverable create decision conflict; one final owner is preferred."},"formula":"","question":{"q":{"ar":"في RACI، من يتحمل المسؤولية النهائية عن المخرج؟","en":"In RACI, who has final accountability for the deliverable?"},"options":{"ar":["Responsible","Accountable","Consulted","Informed"],"en":["Responsible","Accountable","Consulted","Informed"]},"answer":1,"rationale":{"ar":"Accountable يملك النتيجة النهائية ويوافق على المخرج.","en":"The Accountable role owns the final result and approves the deliverable."}}},{"domain":1,"code":"1.8","title":{"ar":"نظام معلومات الجودة ولوحات المؤشرات","en":"Quality Information System and Dashboards"},"level":"Understand","ref":"5th ed., Ch. 1; 4th ed., pp. 34–40","concept":{"ar":"QIS يحدد من ينتج البيانات، وما تعريفها، وكيف تُجمع وتُنظف وتُحلل، ومن يملك حق الوصول، وكيف تتوسع المنظومة لاحقًا. لوحة المؤشرات الفعالة تظهر الهدف والاتجاه والانحراف والإجراء، ولا تكتفي بتجميع رسومات.","en":"A QIS defines who produces data, what each field means, how it is collected, cleaned, analyzed, and accessed, and how the system can expand. An effective dashboard shows target, trend, deviation, and action rather than merely displaying charts."},"steps":{"ar":["ضع Data Dictionary وتعريفًا موحدًا للمؤشرات.","حدد مصدرًا مرجعيًا واحدًا.","ضع قواعد تحقق وتنظيف.","صمم صلاحيات الوصول وسجل التغيير.","اعرض النسبة والعدد والسياق الزمني معًا."],"en":["Create a data dictionary and standard metric definitions.","Establish a single source of truth.","Define validation and cleaning rules.","Design access rights and change history.","Display rates, counts, and time context together."]},"example":{"ar":"انخفض معدل الرفض من 4% إلى 3% لكن الإنتاج تضاعف؛ عرض النسبة وحدها يوحي بتحسن، بينما عدد القطع المرفوضة ارتفع. يجب عرض كلاهما.","en":"The rejection rate dropped from 4% to 3%, but production doubled. The rate alone suggests improvement while the number of rejected units increased. Both should be shown."},"tip":{"ar":"المؤشر بلا تعريف للتعداد والمقام والفترة قد يعطي قرارات متناقضة.","en":"A metric without a defined numerator, denominator, and time period can lead to conflicting decisions."},"formula":"","question":{"q":{"ar":"ما العنصر الأهم لضمان اتساق مؤشر الجودة بين الأقسام؟","en":"What is most important for consistency of a quality metric across departments?"},"options":{"ar":["ألوان موحدة","Data Dictionary وتعريف موحد للمؤشر","زيادة عدد الرسومات","عرض الأرقام دون مصدر"],"en":["Consistent colors","A data dictionary and standard metric definition","More charts","Displaying numbers without a source"]},"answer":1,"rationale":{"ar":"التعريف الموحد يمنع اختلاف الحساب والتفسير.","en":"A standard definition prevents inconsistent calculation and interpretation."}}},{"domain":1,"code":"1.9","title":{"ar":"أخلاقيات مهندس الجودة","en":"Quality Engineer Ethics"},"level":"Evaluate","ref":"5th ed., Ch. 1; 4th ed., pp. 40–43","concept":{"ar":"يجب أن يحمي مهندس الجودة سلامة الجمهور، ويعرض البيانات بصدق، ويحافظ على الكفاءة والسرية، ويتجنب تضارب المصالح. الضغط الزمني أو الإداري لا يبرر إخفاء فشل أو تغيير عينة أو إعادة اختبار انتقائية للحصول على نتيجة مرغوبة.","en":"A quality engineer must protect public safety, report data truthfully, maintain competence and confidentiality, and avoid conflicts of interest. Schedule or management pressure does not justify concealing a failure, changing a sample, or selectively retesting until a desired result appears."},"steps":{"ar":["ثبّت الحقائق والأدلة.","حدد المتطلبات المهنية والقانونية.","افصح عن تضارب المصالح.","وثق حدود البيانات وعدم اليقين.","صعّد القرار عندما تتعرض السلامة أو النزاهة للخطر."],"en":["Establish facts and evidence.","Identify professional and legal obligations.","Disclose conflicts of interest.","Document data limitations and uncertainty.","Escalate when safety or integrity is threatened."]},"example":{"ar":"فشل اختبار أمان حرج، ويطلب المدير استبعاد النتيجة باعتبارها «غير ممثلة» دون دليل. القرار الصحيح هو توثيق النتيجة والتحقيق وفق إجراء معتمد، لا حذفها.","en":"A critical safety test fails, and a manager asks that it be discarded as 'unrepresentative' without evidence. The correct action is to document and investigate under an approved procedure, not delete it."},"tip":{"ar":"الاختبار قد يطلب «أفضل إجراء أول»؛ غالبًا يبدأ بجمع الحقائق والتحقق قبل التصعيد النهائي.","en":"The exam may ask for the 'best first action'; it often begins with establishing facts before final escalation."},"formula":"","question":{"q":{"ar":"ما التصرف الأخلاقي الأفضل عند اكتشاف فشل حرج قبل الشحن؟","en":"What is the best ethical action when a critical failure is found before shipment?"},"options":{"ar":["إخفاء النتيجة لتجنب التأخير","إعادة الاختبار حتى النجاح","إيقاف التصرف بالمنتج وتوثيق النتيجة والتحقيق","تغيير حد المواصفة"],"en":["Hide the result to avoid delay","Retest until it passes","Hold the product, document the result, and investigate","Change the specification limit"]},"answer":2,"rationale":{"ar":"يحمي السلامة ويحافظ على نزاهة الدليل ويتيح قرارًا مخولًا.","en":"It protects safety, preserves evidence integrity, and enables an authorized decision."}}},{"domain":1,"code":"1.10","title":{"ar":"القيادة وبناء الفرق وإدارة التغيير","en":"Leadership, Team Building, and Change Management"},"level":"Analyze","ref":"5th ed., Ch. 1; 4th ed., pp. 43–49","concept":{"ar":"القيادة في الجودة تحول الرؤية إلى سلوك وقرارات. يمر الفريق عادة بمراحل Forming وStorming وNorming وPerforming، ويحتاج القائد إلى تكييف أسلوبه، إزالة العوائق، وبناء الأمان النفسي. مقاومة التغيير قد تنتج من الخوف أو فقدان السيطرة أو غموض الفائدة.","en":"Quality leadership translates vision into behavior and decisions. Teams often progress through forming, storming, norming, and performing. The leader adapts style, removes barriers, and builds psychological safety. Resistance may arise from fear, loss of control, or unclear benefit."},"steps":{"ar":["حدد غرض الفريق والنتيجة.","اختر أعضاء بمهارات متكاملة.","اتفق على قواعد العمل والقرار.","شخّص مرحلة الفريق والصراع.","ثبّت التغيير بالقياس والتغذية الراجعة والاعتراف."],"en":["Define team purpose and outcome.","Select members with complementary skills.","Agree on working and decision rules.","Diagnose team stage and conflict.","Sustain change through measurement, feedback, and recognition."]},"example":{"ar":"فريق جديد يختلف على الأدوار والسلطة. هذا طبيعي في Storming؛ الحل ليس إنهاء الفريق، بل توضيح الأدوار وتسهيل الحوار ووضع قواعد القرار.","en":"A new team conflicts over roles and authority. This is common during storming; the answer is not to disband the team but to clarify roles, facilitate dialogue, and establish decision rules."},"tip":{"ar":"القائد لا يستخدم أسلوبًا واحدًا دائمًا؛ الطوارئ قد تحتاج توجيهًا، بينما التحسين طويل المدى يحتاج مشاركة.","en":"A leader should not use one style in all situations; emergencies may require direction, while long-term improvement needs participation."},"formula":"","question":{"q":{"ar":"في أي مرحلة من تطور الفريق يظهر الصراع حول الأدوار غالبًا؟","en":"At which team-development stage does conflict over roles commonly appear?"},"options":{"ar":["Forming","Storming","Norming","Performing"],"en":["Forming","Storming","Norming","Performing"]},"answer":1,"rationale":{"ar":"Storming تتسم باختبار السلطة والأدوار وظهور الخلافات.","en":"Storming is characterized by testing authority, roles, and open conflict."}}},{"domain":1,"code":"1.11","title":{"ar":"التيسير وحل النزاع وأدوات الفرق","en":"Facilitation, Conflict Resolution, and Team Tools"},"level":"Apply","ref":"5th ed., Ch. 1; 4th ed., pp. 49–56","concept":{"ar":"الميسّر يدير العملية وليس المحتوى؛ يضمن مشاركة متوازنة ووضوح الهدف والتوثيق والالتزام بالوقت. تشمل الأدوات Brainstorming وNominal Group Technique وMulti-voting وForce-Field Analysis وأساليب حل النزاع.","en":"A facilitator manages the process, not the technical answer. The role is to ensure balanced participation, a clear objective, documentation, and time discipline. Tools include brainstorming, nominal group technique, multi-voting, force-field analysis, and conflict-resolution methods."},"steps":{"ar":["حدد سؤال الجلسة وقرارها المتوقع.","افصل توليد الأفكار عن تقييمها.","استخدم NGT عندما تسيطر أصوات محددة.","وثق معايير الاختيار والتصويت.","حوّل القرار إلى مالك وموعد وإجراء."],"en":["Define the session question and expected decision.","Separate idea generation from evaluation.","Use NGT when a few voices dominate.","Document selection criteria and voting.","Convert the decision into an owner, due date, and action."]},"example":{"ar":"في فريق يهيمن عليه مدير خبير، يكتب الأعضاء أفكارهم فرديًا ثم تعرض بالتناوب ويجري التصويت؛ هذه NGT تقلل أثر السلطة.","en":"In a team dominated by a senior expert, members first write ideas individually, share them in turn, and vote. This NGT structure reduces authority bias."},"tip":{"ar":"Brainstorming لا يعني قبول كل فكرة؛ المنع المؤقت للنقد يخص مرحلة التوليد فقط.","en":"Brainstorming does not mean every idea is accepted; temporary suspension of criticism applies only during idea generation."},"formula":"","question":{"q":{"ar":"متى تكون Nominal Group Technique أفضل من Brainstorming المفتوح؟","en":"When is the nominal group technique preferable to open brainstorming?"},"options":{"ar":["عند حساب Cpk","عندما يهيمن بعض الأفراد على النقاش","عند معايرة جهاز","عند بناء مخطط السيطرة"],"en":["When calculating Cpk","When a few individuals dominate discussion","When calibrating an instrument","When building a control chart"]},"answer":1,"rationale":{"ar":"NGT تمنح وقتًا فرديًا وتناوبًا وتصويتًا منظمًا يقلل السيطرة الاجتماعية.","en":"NGT uses individual thinking, round-robin sharing, and structured voting to reduce social dominance."}}},{"domain":1,"code":"1.12","title":{"ar":"الاتصال والعملاء والموردون وعوائق التحسين","en":"Communication, Customers, Suppliers, and Improvement Barriers"},"level":"Analyze","ref":"5th ed., Ch. 1; 4th ed., pp. 56–74","concept":{"ar":"يختار مهندس الجودة وسيلة الاتصال بحسب الجمهور والحساسية والحاجة إلى التفاعل والتوثيق. تُحوّل احتياجات العميل إلى CTQ قابلة للقياس، وتدار علاقة المورد من التأهيل إلى التقييم والتطوير واستمرارية الإمداد. تشمل عوائق التحسين الخوف، الأهداف المتعارضة، نقص البيانات، الأنظمة التحفيزية الخاطئة، وضعف القيادة.","en":"A quality engineer selects communication methods based on audience, sensitivity, interaction needs, and documentation. Customer needs are translated into measurable CTQs. Supplier management spans qualification, evaluation, development, and supply continuity. Improvement barriers include fear, conflicting goals, poor data, misaligned incentives, and weak leadership."},"steps":{"ar":["حدد صاحب المصلحة والرسالة والقرار المطلوب.","اختر قناة تسمح بالتفاعل أو التوثيق حسب الحاجة.","حوّل VOC إلى CTQ ومقياس.","قيّم المورد في الجودة والتسليم والاستجابة والمخاطر.","عالج الحواجز النظامية قبل لوم الأفراد."],"en":["Identify the stakeholder, message, and required decision.","Choose a channel that supports interaction or documentation as needed.","Translate VOC into a CTQ and metric.","Evaluate suppliers on quality, delivery, response, and risk.","Address systemic barriers before blaming individuals."]},"example":{"ar":"العميل يقول «أريد الجهاز سهل الاستخدام». تُحوّل الحاجة إلى CTQ مثل إكمال المهمة الأساسية خلال أقل من دقيقتين وبحد أقصى خطأ واحد للمستخدم الجديد.","en":"The customer says, 'I want the device to be easy to use.' Translate this into a CTQ such as completing the primary task within two minutes with no more than one error for a new user."},"tip":{"ar":"ارتفاع تقييم المورد لا يكفي إذا كان مصدرًا وحيدًا بلا خطة استمرارية؛ الأداء الحالي والمخاطر المستقبلية بعدان مختلفان.","en":"A high supplier score is not enough if the supplier is a single source with no continuity plan; current performance and future risk are separate dimensions."},"formula":"","question":{"q":{"ar":"أي عبارة تمثل CTQ صحيحًا؟","en":"Which statement is a valid CTQ?"},"options":{"ar":["المنتج جميل","العميل سعيد","زمن بدء التشغيل أقل من 30 ثانية في 95% من الحالات","تحسين تجربة العميل"],"en":["The product is attractive","The customer is happy","Startup time below 30 seconds in 95% of cases","Improve customer experience"]},"answer":2,"rationale":{"ar":"CTQ يجب أن يكون ترجمة قابلة للقياس لحاجة العميل.","en":"A CTQ must be a measurable translation of a customer need."}}}]});


window.CQE_DOMAINS=window.CQE_DOMAINS||[];
window.CQE_DOMAINS.push({"id":2,"title":{"ar":"نظام الجودة","en":"The Quality System"},"weight":18,"desc":{"ar":"تصميم QMS والوثائق والمعايير والتدقيق وتكلفة الجودة والتدريب.","en":"QMS design, documentation, standards, auditing, cost of quality, and training."},"lessons":[{"domain":2,"code":"2.1","title":{"ar":"العناصر الأساسية لنظام إدارة الجودة","en":"Basic Elements of a Quality Management System"},"level":"Evaluate","ref":"5th ed., Ch. 2; 4th ed., pp. 75–79","concept":{"ar":"نظام إدارة الجودة هو شبكة عمليات مترابطة تحول احتياجات أصحاب المصلحة إلى نتائج. عناصره تشمل التخطيط والضبط والتحسين، المسؤوليات والموارد، إدارة المخاطر، القياس والمراجعة. تقييم النظام لا يقتصر على وجود الإجراءات؛ بل يسأل هل العمليات تحقق النتائج وتتعلم من الانحرافات.","en":"A quality management system is a network of interacting processes that converts stakeholder needs into results. Its elements include planning, control, improvement, responsibilities, resources, risk management, measurement, and review. Evaluation goes beyond the existence of procedures and asks whether processes achieve outcomes and learn from deviations."},"steps":{"ar":["حدد العمليات الأساسية والداعمة.","عرّف المدخلات والمخرجات ومالك كل عملية.","حدد الضوابط والمخاطر والمؤشرات.","اربط العمليات عبر نقاط التسليم.","راجع الفعالية لا مجرد المطابقة الورقية."],"en":["Identify core and support processes.","Define inputs, outputs, and process owners.","Specify controls, risks, and measures.","Connect processes through handoff points.","Review effectiveness, not only documentary compliance."]},"example":{"ar":"وجود إجراء لمعالجة الشكاوى لا يثبت فعالية النظام إذا كانت الشكاوى تتكرر ولا يصل التحليل إلى التصميم أو المورد.","en":"A complaint procedure does not prove an effective system if complaints recur and analysis never reaches design or supplier processes."},"tip":{"ar":"الاختبار قد يعرض نظامًا موثقًا جيدًا لكنه ضعيف النتائج؛ الإجابة الأقوى تركز على الفعالية والتكامل.","en":"The exam may present a well-documented system with poor results; the best answer focuses on effectiveness and integration."},"formula":"","question":{"q":{"ar":"أي دليل يثبت فعالية QMS بصورة أقوى؟","en":"Which evidence most strongly demonstrates QMS effectiveness?"},"options":{"ar":["عدد الإجراءات المنشورة","وجود شهادة على الحائط","تحقيق الأهداف وانخفاض التكرار بعد الإجراءات التصحيحية","طول دليل الجودة"],"en":["Number of published procedures","A certificate on the wall","Achievement of objectives and reduced recurrence after corrective actions","Length of the quality manual"]},"answer":2,"rationale":{"ar":"الفعالية تُقاس بالنتائج والقدرة على منع التكرار.","en":"Effectiveness is demonstrated by results and the ability to prevent recurrence."}}},{"domain":2,"code":"2.2","title":{"ar":"تصميم العمليات ومواءمتها مع الاستراتيجية","en":"Process Design and Strategic Alignment"},"level":"Analyze","ref":"5th ed., Ch. 2; 4th ed., pp. 79–80","concept":{"ar":"يجب أن تدعم العمليات الاستراتيجية بدل أن تعمل كجزر مستقلة. يشمل التصميم تحديد التسلسل والتفاعل، معايير القبول، نقاط القرار، المخاطر، الموارد، والبيانات. تُكشف الفجوات كثيرًا عند نقاط التسليم بين الإدارات لا داخل العملية الواحدة.","en":"Processes must support strategy rather than operate as isolated silos. Design includes sequence and interaction, acceptance criteria, decision points, risks, resources, and data. Many failures occur at cross-functional handoffs rather than within a single process."},"steps":{"ar":["ابدأ بالنتيجة الاستراتيجية والعميل.","ارسم SIPOC أو خريطة المستوى الأعلى.","حدد نقاط التسليم والمسؤوليات.","حدد CTQ والضوابط والمخاطر.","اختبر السيناريوهات غير الطبيعية والتغييرات."],"en":["Start with the strategic outcome and customer.","Map the high-level process using SIPOC or a process map.","Identify handoffs and responsibilities.","Define CTQs, controls, and risks.","Test abnormal scenarios and changes."]},"example":{"ar":"قد تكون المشتريات والمستودع والجودة كل منها مطابقًا لإجراءه، لكن المواد تدخل الإنتاج قبل اكتمال قرار القبول بسبب فجوة في نقطة التسليم.","en":"Purchasing, warehouse, and quality may each follow their own procedures, yet material enters production before acceptance because the handoff between them is poorly designed."},"tip":{"ar":"عند فشل بين قسمين، لا تبحث فقط عن «من أخطأ»؛ افحص تصميم الواجهة والسلطة والمعلومة.","en":"When a failure occurs between departments, do not only ask who made the mistake; examine interface design, authority, and information flow."},"formula":"","question":{"q":{"ar":"ما الأداة الأفضل لفهم مدخلات ومخرجات وعملاء عملية على مستوى عالٍ؟","en":"Which tool is best for understanding a process's high-level suppliers, inputs, outputs, and customers?"},"options":{"ar":["SIPOC","Histogram","OC curve","Weibull plot"],"en":["SIPOC","Histogram","OC curve","Weibull plot"]},"answer":0,"rationale":{"ar":"SIPOC يوضح حدود العملية وعلاقاتها الأساسية قبل الدخول في التفاصيل.","en":"SIPOC clarifies process boundaries and major relationships before detailed mapping."}}},{"domain":2,"code":"2.3","title":{"ar":"هرم الوثائق ومكونات المستند","en":"Documentation Hierarchy and Document Components"},"level":"Understand","ref":"5th ed., Ch. 2; 4th ed., pp. 80–82","concept":{"ar":"يجب أن يكون التوثيق مناسبًا لحجم وتعقيد ومخاطر العمل. عادةً تشمل الطبقات السياسة والأهداف، وصف النظام أو خريطة العمليات، الإجراءات، تعليمات العمل، النماذج والسجلات. المكوّن الجيد يحدد الغرض والنطاق والمسؤوليات والخطوات والمراجع والسجلات والتعريفات.","en":"Documentation should fit the size, complexity, and risk of the work. Typical layers include policy and objectives, system or process maps, procedures, work instructions, forms, and records. A good document defines purpose, scope, responsibilities, steps, references, records, and terms."},"steps":{"ar":["حدد الحاجة إلى التوثيق بناءً على المخاطر والكفاءة.","اختر مستوى التفصيل المناسب للمستخدم.","اكتب خطوات قابلة للتنفيذ والتحقق.","حدد السجلات الناتجة.","اختبر الوثيقة مع مستخدم فعلي قبل الاعتماد."],"en":["Determine the need for documentation based on risk and competence.","Choose the right detail level for the user.","Write executable and verifiable steps.","Define resulting records.","Test the document with an actual user before approval."]},"example":{"ar":"إجراء عام يقول «افحص المنتج جيدًا» لا يكفي لعملية حرجة؛ تعليمات العمل يجب أن تحدد الخاصية والأداة والعينة والحدود والتصرف.","en":"A general procedure saying 'inspect the product carefully' is insufficient for a critical process. The work instruction should state the characteristic, instrument, sample, limits, and reaction."},"tip":{"ar":"النموذج الفارغ وثيقة مضبوطة؛ بعد تعبئته يصبح سجلًا يثبت التنفيذ.","en":"A blank form is a controlled document; once completed it becomes a record demonstrating execution."},"formula":"","question":{"q":{"ar":"متى يتحول النموذج إلى سجل جودة؟","en":"When does a form become a quality record?"},"options":{"ar":["عند تصميمه","عند اعتماده","عند تعبئته واستخدامه كدليل","عند طباعته فقط"],"en":["When designed","When approved","When completed and used as evidence","When printed"]},"answer":2,"rationale":{"ar":"المعلومات المسجلة تثبت ما تم تنفيذه والنتيجة.","en":"Recorded information provides evidence of what was performed and the result."}}},{"domain":2,"code":"2.4","title":{"ar":"ضبط الوثائق وإدارة التهيئة","en":"Document Control and Configuration Management"},"level":"Evaluate","ref":"5th ed., Ch. 2; 4th ed., pp. 81–83","concept":{"ar":"ضبط الوثائق يضمن أن النسخة الصحيحة متاحة في نقطة الاستخدام وأن النسخ الملغاة لا تُستخدم. إدارة التهيئة توسع المفهوم لتحديد الحالة المعتمدة للمنتج أو النظام، والسيطرة على التغييرات، وتتبع النسخ والمكونات والتوافق بينها.","en":"Document control ensures the correct revision is available at the point of use and obsolete versions are prevented from unintended use. Configuration management extends control to the approved state of a product or system, controlling changes and tracing versions, components, and compatibility."},"steps":{"ar":["عرّف مالك الوثيقة والموافقين.","استخدم ترقيمًا ومراجعة وتاريخ سريان.","قيّم أثر التغيير قبل الاعتماد.","اسحب أو وسم النسخ الملغاة.","تحقق من تطبيق التغيير في التدريب والمعدات والسجلات."],"en":["Define the document owner and approvers.","Use identification, revision, and effective date.","Assess change impact before approval.","Remove or identify obsolete copies.","Verify implementation in training, equipment, and records."]},"example":{"ar":"تحديث رسم جزء دون تحديث خطة الفحص قد ينتج قياسات صحيحة مقابل نسخة قديمة. إدارة التهيئة تربط الرسم وخطة التحكم وتعليمات التشغيل وبرنامج CMM.","en":"Updating a part drawing without updating the inspection plan may produce accurate measurements against an obsolete revision. Configuration management links the drawing, control plan, work instruction, and CMM program."},"tip":{"ar":"المشكلة ليست فقط وجود نسختين؛ بل عدم معرفة أي حالة معتمدة وما المنتجات المتأثرة.","en":"The issue is not merely two versions existing; it is uncertainty about the approved configuration and affected product."},"formula":"","question":{"q":{"ar":"ما الإجراء الأقوى عند تغيير رسم هندسي حرج؟","en":"What is the strongest action when a critical engineering drawing changes?"},"options":{"ar":["إرسال بريد فقط","تحديث الرسم دون باقي الوثائق","تقييم أثر التغيير وتحديث كل الوثائق والبرامج المرتبطة والتحقق من التنفيذ","ترك النسخة القديمة في الموقع"],"en":["Send an email only","Update the drawing without related documents","Assess impact, update all linked documents and programs, and verify implementation","Leave the old version at the workstation"]},"answer":2,"rationale":{"ar":"التغيير الهندسي يؤثر في منظومة مترابطة ويجب التحكم فيه عبر التهيئة.","en":"Engineering change affects an interconnected configuration and must be controlled as a system."}}},{"domain":2,"code":"2.5","title":{"ar":"المعايير والجائزة الوطنية للجودة","en":"Standards and the Baldrige Framework"},"level":"Apply","ref":"5th ed., Ch. 2; 4th ed., pp. 82–90","concept":{"ar":"المعيار يحدد متطلبات أو إرشادات متفقًا عليها، لكنه لا يضمن الأداء تلقائيًا. عائلة ISO 9000 تشمل المبادئ والمصطلحات ومتطلبات ISO 9001 وإرشادات التحسين. إطار Baldrige يقيم القيادة والاستراتيجية والعملاء والقياس والقوى العاملة والعمليات والنتائج على مستوى المنظمة.","en":"A standard defines agreed requirements or guidance but does not automatically guarantee performance. The ISO 9000 family covers principles and vocabulary, ISO 9001 requirements, and improvement guidance. The Baldrige framework evaluates leadership, strategy, customers, measurement, workforce, operations, and results at the organizational level."},"steps":{"ar":["حدد المتطلب المنطبق ومصدره.","فسره في سياق العملية.","حوّله إلى ضوابط وأدلة.","قيّم الفعالية لا مجرد وجود الوثيقة.","راجع التحديثات والتعارضات بين المتطلبات."],"en":["Identify the applicable requirement and source.","Interpret it in the process context.","Translate it into controls and evidence.","Evaluate effectiveness, not only document presence.","Monitor updates and conflicts among requirements."]},"example":{"ar":"الحصول على شهادة ISO 9001 يعني أن نظامًا خضع لتقييم مطابقة، لكنه لا يعني أن كل منتج خالٍ من العيوب أو أن المنظمة الأفضل في السوق.","en":"ISO 9001 certification means a management system was assessed for conformity; it does not mean every product is defect-free or the organization is best in its market."},"tip":{"ar":"الاختبار لا يركز على معايير قطاعية محددة؛ ركز على المبادئ وتطبيق المعايير العامة.","en":"The exam does not focus on industry-specific standards; concentrate on principles and general-standard application."},"formula":"","question":{"q":{"ar":"أي عبارة صحيحة عن شهادة ISO 9001؟","en":"Which statement about ISO 9001 certification is correct?"},"options":{"ar":["تضمن صفر عيوب","تضمن أفضل منتج في السوق","تدل على تقييم نظام الإدارة مقابل متطلبات المعيار","تلغي الحاجة إلى التدقيق الداخلي"],"en":["It guarantees zero defects","It guarantees the best product in the market","It indicates that the management system was assessed against standard requirements","It eliminates internal audits"]},"answer":2,"rationale":{"ar":"الشهادة تتعلق بمطابقة نظام الإدارة، لا بضمان كل نتيجة فردية.","en":"Certification addresses management-system conformity, not a guarantee of every individual outcome."}}},{"domain":2,"code":"2.6","title":{"ar":"أنواع التدقيق وأدوار المشاركين","en":"Audit Types and Participant Roles"},"level":"Apply","ref":"5th ed., Ch. 2; 4th ed., pp. 88–90","concept":{"ar":"يمكن أن يكون التدقيق على نظام أو عملية أو منتج، وأن يكون داخليًا First-party، أو على مورد Second-party، أو مستقلًا Third-party. تشمل الأدوار عميل التدقيق، قائد الفريق، أعضاء الفريق، الخبير الفني، والجهة المدققة. الاستقلال والموضوعية والكفاءة أساس صحة النتيجة.","en":"An audit may address a system, process, or product and may be first-party, second-party, or independent third-party. Roles include audit client, team leader, auditors, technical expert, and auditee. Independence, objectivity, and competence are essential to valid conclusions."},"steps":{"ar":["حدد هدف التدقيق ومعاييره ونطاقه.","اختر نوع التدقيق المناسب.","عيّن فريقًا مستقلًا وكفؤًا.","وضح السلطة والسرية وقنوات الاتصال.","تجنب تدقيق الشخص لعمله الخاص."],"en":["Define audit objective, criteria, and scope.","Select the appropriate audit type.","Assign an independent and competent team.","Clarify authority, confidentiality, and communication.","Avoid auditors evaluating their own work."]},"example":{"ar":"تدقيق المصنع على مورده لتقييم القدرة قبل التعاقد هو Second-party supplier audit، وليس تدقيق شهادة.","en":"A manufacturer auditing a supplier's capability before contracting is a second-party supplier audit, not a certification audit."},"tip":{"ar":"كلمة «خارجي» لا تعني دائمًا Third-party؛ العميل على مورده Second-party.","en":"The word 'external' does not always mean third-party; a customer auditing a supplier is second-party."},"formula":"","question":{"q":{"ar":"تدقيق المنظمة على موردها يصنف عادةً كـ:","en":"An organization's audit of its supplier is usually classified as:"},"options":{"ar":["First-party","Second-party","Third-party","Product inspection only"],"en":["First-party","Second-party","Third-party","Product inspection only"]},"answer":1,"rationale":{"ar":"العلاقة بين العميل والمورد تجعل التدقيق Second-party.","en":"The customer-supplier relationship makes it a second-party audit."}}},{"domain":2,"code":"2.7","title":{"ar":"تخطيط التدقيق المبني على المخاطر وتنفيذه","en":"Risk-Based Audit Planning and Execution"},"level":"Apply","ref":"5th ed., Ch. 2 new content; 4th ed., pp. 90–91","concept":{"ar":"يرتب التخطيط المبني على المخاطر وقت التدقيق حسب أهمية العملية، التغييرات، الأداء السابق، الشكاوى، وتعقيد الضوابط. التنفيذ يجمع أدلة موضوعية من المقابلات والملاحظة والسجلات والاختبارات، مع أخذ عينات كافية لبلوغ استنتاج معقول.","en":"Risk-based planning allocates audit effort according to process importance, change, prior performance, complaints, and control complexity. Execution gathers objective evidence through interviews, observation, records, and tests, using sufficient sampling to reach a reasonable conclusion."},"steps":{"ar":["حدد الأهداف والمعايير والنطاق.","قيّم مخاطر العمليات وحدد الأولويات.","جهز خطة وأسئلة ومسارات تتبع.","اجمع الأدلة وحقق التناقضات.","حافظ على العينة والموضوعية وسجل القيود."],"en":["Define objectives, criteria, and scope.","Assess process risks and priorities.","Prepare the plan, questions, and audit trails.","Collect evidence and resolve inconsistencies.","Maintain sampling discipline, objectivity, and document limitations."]},"example":{"ar":"عملية مستقرة بلا تغييرات قد تحصل على وقت أقل من عملية جديدة فيها شكاوى متزايدة وتغيير مورد؛ لا يعني ذلك تجاهل الأولى بل توجيه العمق حسب المخاطر.","en":"A stable unchanged process may receive less audit time than a new process with rising complaints and a supplier change. The first is not ignored; depth is allocated according to risk."},"tip":{"ar":"قائمة التحقق أداة مساعدة وليست حدًا يمنع تتبع دليل جديد أثناء التدقيق.","en":"A checklist is a guide, not a boundary that prevents following new evidence during the audit."},"formula":"","question":{"q":{"ar":"أي عامل يبرر زيادة عمق التدقيق على عملية؟","en":"Which factor justifies increasing audit depth on a process?"},"options":{"ar":["عدم وجود أي تغيير لسنوات مع أداء ثابت","زيادة الشكاوى وتغيير مورد حرج","سهولة الوصول إلى السجلات","قلة عدد الموظفين فقط"],"en":["No change for years with stable performance","Rising complaints and a critical supplier change","Easy record access","Small staff size alone"]},"answer":1,"rationale":{"ar":"التغيير والأداء المتدهور يزيدان مخاطر العملية وأولوية التدقيق.","en":"Change and deteriorating performance increase process risk and audit priority."}}},{"domain":2,"code":"2.8","title":{"ar":"صياغة النتائج والتقرير والمتابعة","en":"Audit Findings, Reporting, and Follow-Up"},"level":"Apply","ref":"5th ed., Ch. 2; 4th ed., pp. 91–92","concept":{"ar":"النتيجة الجيدة تربط المعيار بالدليل والفجوة. يجب أن يكون التقرير دقيقًا ومفهومًا ومتوازنًا، وأن يميز عدم المطابقة عن الملاحظة وفرصة التحسين. المتابعة تتحقق من الإجراء وفعاليته، لا من إغلاق النموذج فقط.","en":"A sound finding links the criterion, objective evidence, and the gap. The report should be accurate, clear, and balanced, distinguishing nonconformity from observation and opportunity for improvement. Follow-up verifies action and effectiveness, not merely closure of a form."},"steps":{"ar":["اكتب المتطلب المحدد.","أضف الدليل القابل للتحقق.","صف الفجوة دون اقتراح حل إلزامي.","اتفق على المسؤول والموعد.","تحقق من السبب والتنفيذ والفعالية."],"en":["State the specific requirement.","Add verifiable objective evidence.","Describe the gap without prescribing a mandatory solution.","Agree on owner and due date.","Verify cause, implementation, and effectiveness."]},"example":{"ar":"صياغة قوية: «الإجراء QP-07 يتطلب مراجعة شهرية. لم توجد مراجعات لشهور مارس إلى مايو في ثلاث سجلات من أصل ثلاثة».","en":"Strong wording: 'Procedure QP-07 requires monthly review. No reviews were available for March through May in all three sampled records.'"},"tip":{"ar":"لا تكتب «الموظفون مهملون»؛ هذا حكم غير مدعوم وليس وصفًا للفجوة.","en":"Do not write 'employees are careless'; this is an unsupported judgment, not a description of the gap."},"formula":"","question":{"q":{"ar":"أي صياغة هي الأفضل لعدم مطابقة؟","en":"Which wording is best for a nonconformity?"},"options":{"ar":["الإدارة لا تهتم","يجب شراء نظام جديد","المتطلب والدليل والفجوة موثقة بوضوح","العملية سيئة جدًا"],"en":["Management does not care","A new system must be purchased","The requirement, evidence, and gap are clearly documented","The process is very poor"]},"answer":2,"rationale":{"ar":"عدم المطابقة تبنى على معيار ودليل موضوعي وفجوة محددة.","en":"A nonconformity is based on a criterion, objective evidence, and a specific gap."}}},{"domain":2,"code":"2.9","title":{"ar":"تكلفة الجودة وتحليلها","en":"Cost of Quality"},"level":"Analyze","ref":"5th ed., Ch. 2; 4th ed., pp. 92–102","concept":{"ar":"ينظم نموذج PAF التكاليف إلى الوقاية Prevention، والتقييم Appraisal، والفشل الداخلي والخارجي. Cost of Poor Quality غالبًا يشمل الفشلين، لكنه قد يشمل فرصًا خفية مثل فقدان الطاقة والوقت والسمعة. الهدف ليس خفض كل تكلفة جودة؛ بل إعادة التوازن نحو الوقاية الفعالة وتقليل الفشل.","en":"The PAF model classifies costs as prevention, appraisal, internal failure, and external failure. Cost of Poor Quality commonly includes internal and external failure, plus hidden losses such as capacity, time, and reputation. The goal is not to minimize every quality cost but to shift effort toward effective prevention and reduce failure."},"steps":{"ar":["عرّف فئات التكلفة وقواعدها.","اجمع البيانات من المالية والعمليات والجودة.","تجنب العد المزدوج.","حلل الاتجاه والنسبة إلى المبيعات أو الإنتاج.","اربط مبادرات التحسين بالتوفير المحقق."],"en":["Define cost categories and rules.","Collect data from finance, operations, and quality.","Avoid double counting.","Analyze trends and normalize to sales or output.","Link improvement actions to realized savings."]},"example":{"ar":"تدريب FMEA تكلفة وقاية، والفحص النهائي تقييم، وإعادة العمل قبل الشحن فشل داخلي، والضمان بعد الشحن فشل خارجي.","en":"FMEA training is prevention, final inspection is appraisal, rework before shipment is internal failure, and warranty after shipment is external failure."},"tip":{"ar":"زيادة الوقاية قد ترفع COQ مؤقتًا لكنها تخفض إجمالي التكلفة لاحقًا؛ لا تفسر الارتفاع منفردًا.","en":"Increased prevention may raise COQ temporarily while reducing total cost later; do not interpret the increase in isolation."},"formula":"COQ = Prevention + Appraisal + Internal Failure + External Failure","question":{"q":{"ar":"مطالبة ضمان من العميل تصنف كـ:","en":"A customer warranty claim is classified as:"},"options":{"ar":["Prevention","Appraisal","Internal failure","External failure"],"en":["Prevention","Appraisal","Internal failure","External failure"]},"answer":3,"rationale":{"ar":"حدثت التكلفة بعد وصول المنتج للعميل.","en":"The cost occurred after the product reached the customer."}}},{"domain":2,"code":"2.10","title":{"ar":"التدريب والكفاءة وقياس الفعالية","en":"Training, Competence, and Effectiveness"},"level":"Apply","ref":"5th ed., Ch. 2; 4th ed., pp. 102–106","concept":{"ar":"يبدأ التدريب بتحليل المهام والكفاءات المطلوبة والفجوة الحالية. اختيار الطريقة يعتمد على مستوى المعرفة والمهارة والخطر. لا يثبت توقيع الحضور الفعالية؛ يجب قياس التعلم ثم انتقاله إلى السلوك والنتائج.","en":"Training begins with task analysis, required competence, and the current gap. The method depends on knowledge, skill, and risk. Attendance signatures do not prove effectiveness; learning, workplace behavior, and results must be evaluated."},"steps":{"ar":["حدد الكفاءة المطلوبة ومعيار القبول.","قيّم الفجوة للفرد أو الدور.","صمم المحتوى والتطبيق العملي.","نفذ تقييمًا فوريًا وبعد فترة.","اربط النتائج بأداء العملية وأعد التدريب عند الحاجة."],"en":["Define required competence and acceptance criteria.","Assess the gap for the person or role.","Design content and practical application.","Evaluate immediately and after a period.","Link results to process performance and retrain where needed."]},"example":{"ar":"تدريب المقيمين على قياس قطر جزء ينجح في اختبار نظري، لكن Gage R&R لا يتحسن. هذا يعني أن التعلم لم ينتقل إلى السلوك أو أن السبب ليس التدريب وحده.","en":"Appraisers pass a theory test on measuring a diameter, but Gage R&R does not improve. Learning did not transfer to behavior, or training was not the only cause."},"tip":{"ar":"أفضل دليل على الفعالية هو تحسن الأداء المستمر، لا رضا المتدرب وحده.","en":"The strongest evidence of effectiveness is sustained performance improvement, not learner satisfaction alone."},"formula":"","question":{"q":{"ar":"أي دليل هو الأقوى على فعالية التدريب؟","en":"Which evidence most strongly demonstrates training effectiveness?"},"options":{"ar":["قائمة حضور كاملة","تقييم رضا مرتفع","تحسن مستدام في السلوك ونتائج العملية","عدد ساعات التدريب"],"en":["Complete attendance sheet","High satisfaction score","Sustained improvement in behavior and process results","Number of training hours"]},"answer":2,"rationale":{"ar":"الفعالية الحقيقية تظهر في التطبيق والنتائج.","en":"True effectiveness is shown through application and results."}}}]});


window.CQE_DOMAINS=window.CQE_DOMAINS||[];
window.CQE_DOMAINS.push({"id":3,"title":{"ar":"تصميم المنتج والعملية والخدمة","en":"Product, Process, and Service Design"},"weight":21,"desc":{"ar":"CTQ وDFX وGD&T والتحقق والتصديق والاعتمادية وتحليل الفشل.","en":"CTQs, DFX, GD&T, verification, validation, reliability, and failure analysis."},"lessons":[{"domain":3,"code":"3.1","title":{"ar":"تصنيف خصائص الجودة وCTQ","en":"Classification of Quality Characteristics and CTQs"},"level":"Evaluate","ref":"5th ed., Ch. 3; 4th ed., pp. 107–108","concept":{"ar":"تُصنف خصائص الجودة حسب تأثيرها ووظيفتها وقابلية قياسها: خصائص حرجة للسلامة، رئيسية للأداء، وثانوية للمظهر أو الراحة. CTQ هي ترجمة قابلة للقياس لاحتياج عميل أو خطر؛ ويجب تحديد الوحدة والحد وطريقة القياس وحالة الاستخدام.","en":"Quality characteristics are classified by impact, function, and measurability: safety-critical, major performance, and minor appearance or convenience characteristics. A CTQ is a measurable translation of a customer need or risk, with a defined unit, limit, measurement method, and use condition."},"steps":{"ar":["اجمع VOC والمتطلبات النظامية والمخاطر.","حوّل العبارات العامة إلى خصائص قابلة للقياس.","صنف الخطورة والأولوية.","حدد المواصفة وطريقة القياس.","تحقق أن CTQ يعكس الاستخدام الفعلي."],"en":["Collect VOC, regulatory requirements, and risk information.","Translate broad statements into measurable characteristics.","Classify severity and priority.","Define specification and measurement method.","Verify the CTQ reflects actual use."]},"example":{"ar":"حاجة «جهاز سهل الاستخدام» تتحول إلى: إكمال المهمة الأساسية خلال 120 ثانية للمستخدم الجديد بنسبة نجاح 95% ودون خطأ حرج.","en":"The need 'easy to use' becomes: a new user completes the primary task within 120 seconds with a 95% success rate and no critical error."},"tip":{"ar":"ليست كل خاصية قابلة للقياس CTQ؛ يجب أن ترتبط بحاجة حرجة أو خطر أو متطلب.","en":"Not every measurable feature is a CTQ; it must be linked to a critical need, risk, or requirement."},"formula":"","question":{"q":{"ar":"أي وصف هو CTQ مكتمل؟","en":"Which description is a complete CTQ?"},"options":{"ar":["جودة ممتازة","صوت منخفض","مستوى الضوضاء أقل من 45 dBA عند مسافة متر في وضع التشغيل العادي","العميل مرتاح"],"en":["Excellent quality","Low noise","Noise below 45 dBA at one meter under normal operation","The customer is comfortable"]},"answer":2,"rationale":{"ar":"يتضمن خاصية ووحدة وحدًا وظرف قياس.","en":"It includes a characteristic, unit, limit, and measurement condition."}}},{"domain":3,"code":"3.2","title":{"ar":"مدخلات التصميم: العميل والتنظيم والمخاطر","en":"Design Inputs: Customer, Regulatory, and Risk Requirements"},"level":"Analyze","ref":"5th ed., Ch. 3 new CTQ content; 4th ed., pp. 108–111","concept":{"ar":"مدخلات التصميم تشمل VOC وCTQ والمتطلبات النظامية والواجهات والبيئة والأداء والسلامة والموثوقية والمخاطر والدروس السابقة. يجب أن تكون كاملة وغير متعارضة وقابلة للتحقق والتتبع. الغموض في البداية يتحول عادة إلى إعادة تصميم أو فشل لاحق.","en":"Design inputs include VOC, CTQs, regulatory requirements, interfaces, environment, performance, safety, reliability, risks, and lessons learned. They should be complete, nonconflicting, verifiable, and traceable. Early ambiguity often becomes redesign or later failure."},"steps":{"ar":["حدد جميع مصادر المتطلبات.","حل التعارضات وحدد الأولوية.","اكتب كل متطلب بصورة قابلة للاختبار.","اربطه بخطر ووسيلة تحقق.","راجع المدخلات مع تخصصات متعددة."],"en":["Identify all requirement sources.","Resolve conflicts and set priority.","Write each requirement in a testable form.","Link it to risk and a verification method.","Review inputs with a cross-functional team."]},"example":{"ar":"عبارة «يعمل في الجو الحار» غامضة؛ المدخل الأفضل يحدد نطاق حرارة التشغيل، مدة التعرض، الرطوبة، الحمل، ومعيار الأداء المقبول.","en":"The statement 'works in hot weather' is ambiguous. A better input defines operating temperature range, exposure time, humidity, load, and acceptable performance."},"tip":{"ar":"التصميم لا يستطيع التحقق من حاجة غير قابلة للاختبار؛ راجع صياغة المدخل قبل بدء الحل.","en":"A design cannot verify an untestable need; improve the input before developing the solution."},"formula":"","question":{"q":{"ar":"ما الخاصية الأهم لمدخل تصميم جيد؟","en":"What is the most important property of a good design input?"},"options":{"ar":["أن يكون عامًا ومرنًا","أن يكون قابلاً للتحقق والتتبع","أن يكتب بعد اكتمال التصميم","أن يقتصر على رأي المصمم"],"en":["It should be broad and flexible","It should be verifiable and traceable","It should be written after design completion","It should reflect only the designer's opinion"]},"answer":1,"rationale":{"ar":"المدخل القابل للتحقق والتتبع يتيح تصميمًا ومراجعة واختبارًا منضبطًا.","en":"Verifiable, traceable inputs enable controlled design, review, and testing."}}},{"domain":3,"code":"3.3","title":{"ar":"التصميم من أجل X وDFSS والتصميم المتين","en":"DFX, DFSS, and Robust Design"},"level":"Apply","ref":"5th ed., Ch. 3; 4th ed., design sections","concept":{"ar":"DFX يدمج متطلبات دورة الحياة داخل التصميم: DFM للتصنيع، DFA للتجميع، DFR للاعتمادية، DFI للفحص، وDFS للسلامة. DFSS يستخدم مناهج مثل DMADV لتصميم منتج أو عملية تحقق CTQ من البداية. Robust Design يقلل حساسية الأداء لعوامل الضوضاء.","en":"DFX builds life-cycle needs into design: DFM for manufacturability, DFA for assembly, DFR for reliability, DFI for inspection, and DFS for safety. DFSS uses approaches such as DMADV to design products or processes that meet CTQs from the outset. Robust design reduces sensitivity to noise factors."},"steps":{"ar":["حدد CTQ وعوامل الضوضاء.","بسّط الأجزاء والواجهات.","صمم للقدرة التصنيعية والقياس.","اختبر الحساسية والتفاعلات.","وازن الأداء والتكلفة والمخاطر طوال دورة الحياة."],"en":["Define CTQs and noise factors.","Simplify parts and interfaces.","Design for manufacturability and measurement.","Test sensitivity and interactions.","Balance performance, cost, and risk across the life cycle."]},"example":{"ar":"تقليل عدد المثبتات المختلفة من ستة أنواع إلى نوعين قد يخفض أخطاء التجميع والمخزون ووقت التدريب؛ هذا تطبيق DFA/DFM.","en":"Reducing six different fastener types to two may reduce assembly errors, inventory, and training time; this is a DFA/DFM application."},"tip":{"ar":"تحقيق المتوسط المطلوب في المختبر لا يعني تصميمًا متينًا إذا انهار الأداء مع تغير الحرارة أو المورد.","en":"Meeting the target mean in a laboratory does not make a design robust if performance collapses with temperature or supplier variation."},"formula":"","question":{"q":{"ar":"أي منهج يركز على تقليل حساسية المنتج لعوامل لا يمكن التحكم بها بسهولة؟","en":"Which approach focuses on reducing product sensitivity to hard-to-control factors?"},"options":{"ar":["Robust design","Final inspection","Document control","Acceptance sampling"],"en":["Robust design","Final inspection","Document control","Acceptance sampling"]},"answer":0,"rationale":{"ar":"التصميم المتين يختار إعدادات تجعل الأداء أقل تأثرًا بعوامل الضوضاء.","en":"Robust design selects settings that make performance less sensitive to noise factors."}}},{"domain":3,"code":"3.4","title":{"ar":"تتبع المتطلبات ومراجعة التصميم","en":"Requirements Traceability and Design Review"},"level":"Apply","ref":"5th ed., Ch. 3; 4th ed., pp. 108–112","concept":{"ar":"مصفوفة التتبع تربط الحاجة بالمتطلب والتصميم والخطر والتحقق والتصديق. مراجعة التصميم نقطة قرار منهجية متعددة التخصصات لتقييم الاكتمال والمخاطر والواجهات وقابلية التصنيع والاختبار قبل الالتزام بتكلفة أكبر.","en":"A traceability matrix links customer need, requirement, design output, risk, verification, and validation. A design review is a systematic cross-functional decision point that evaluates completeness, risks, interfaces, manufacturability, and testability before greater cost is committed."},"steps":{"ar":["أنشئ معرفًا فريدًا لكل متطلب.","اربط كل متطلب بمخرج تصميم وخطر واختبار.","حدد معايير الدخول والخروج للمراجعة.","أشرك الجودة والتصنيع والخدمة والمورد حسب الحاجة.","أغلق الإجراءات قبل الانتقال للمرحلة التالية."],"en":["Assign a unique ID to every requirement.","Link each requirement to a design output, risk, and test.","Define review entry and exit criteria.","Include quality, manufacturing, service, and suppliers as appropriate.","Close actions before phase progression."]},"example":{"ar":"إذا لم يوجد اختبار لمتطلب أمان محدد، تكشف مصفوفة التتبع الفجوة قبل التصديق بدل اكتشافها عند إطلاق المنتج.","en":"If a safety requirement has no associated test, the traceability matrix reveals the gap before validation rather than after product release."},"tip":{"ar":"Design Review ليست مجرد عرض تقدم؛ يجب أن تنتهي بقرار وإجراءات ومسؤوليات.","en":"A design review is not merely a progress presentation; it should end with a decision, actions, and ownership."},"formula":"","question":{"q":{"ar":"ما الفائدة الأساسية من Requirements Traceability Matrix؟","en":"What is the primary benefit of a requirements traceability matrix?"},"options":{"ar":["زيادة عدد الوثائق","إثبات أن كل متطلب مرتبط بتصميم واختبار مناسب","إلغاء المراجعات","استبدال FMEA"],"en":["Increase document count","Demonstrate that each requirement is linked to appropriate design and testing","Eliminate reviews","Replace FMEA"]},"answer":1,"rationale":{"ar":"التتبع يمنع المتطلبات المفقودة والاختبارات غير المرتبطة.","en":"Traceability prevents missing requirements and disconnected tests."}}},{"domain":3,"code":"3.5","title":{"ar":"الرسومات الفنية وGD&T وتراكم التفاوت","en":"Technical Drawings, GD&T, and Tolerance Stack-Up"},"level":"Evaluate","ref":"5th ed., Ch. 3; 4th ed., pp. 112–115","concept":{"ar":"الرسم الفني عقد هندسي يحدد الشكل والأبعاد والمواد والتشطيب والمراجعة. GD&T يصف التفاوت الهندسي باستخدام Datum وخصائص الشكل والاتجاه والموقع والـProfile والـRunout. تحليل تراكم التفاوت يختبر قابلية التجميع والأداء عبر أسوأ حالة أو RSS.","en":"A technical drawing is an engineering contract defining geometry, dimensions, material, finish, and revision. GD&T communicates geometric tolerance through datums and controls of form, orientation, location, profile, and runout. Tolerance stack-up evaluates assembly and function using worst-case or RSS methods."},"steps":{"ar":["راجع Title Block والمراجعة والوحدات.","حدد Datums والوظيفة المقصودة.","فسر Frame والرموز والمعدلات.","اربط خاصية الرسم بطريقة القياس.","حلل تراكم التفاوت قبل تشديد حدود منفردة."],"en":["Review the title block, revision, and units.","Identify datums and functional intent.","Interpret feature-control frames and modifiers.","Link drawing characteristics to measurement methods.","Analyze tolerance stack-up before tightening individual limits."]},"example":{"ar":"تشديد كل بعد منفردًا قد يرفع التكلفة بلا حاجة. تحليل السلسلة قد يبين أن تعديل Datum أو توزيع التفاوت أفضل من تقليل كل حد.","en":"Tightening every dimension may increase cost unnecessarily. Stack analysis may show that changing the datum scheme or redistributing tolerance is better than narrowing every limit."},"tip":{"ar":"الـDatum ليس خط قياس عشوائيًا؛ هو مرجع وظيفي لمحاكاة تثبيت الجزء.","en":"A datum is not an arbitrary measurement line; it is a functional reference that simulates part restraint."},"formula":"","question":{"q":{"ar":"أي طريقة لتراكم التفاوت هي الأكثر تحفظًا؟","en":"Which tolerance stack-up method is the most conservative?"},"options":{"ar":["RSS","Worst-case arithmetic sum","Regression","ANOVA"],"en":["RSS","Worst-case arithmetic sum","Regression","ANOVA"]},"answer":1,"rationale":{"ar":"Worst-case يفترض حدوث أقصى الانحرافات معًا ويجمعها حسابيًا.","en":"Worst-case assumes all maximum deviations occur together and sums them arithmetically."}}},{"domain":3,"code":"3.6","title":{"ar":"التحقق والتصديق وIQ/OQ/PQ","en":"Verification, Validation, and IQ/OQ/PQ"},"level":"Evaluate","ref":"5th ed., Ch. 3; 4th ed., pp. 115–117","concept":{"ar":"Verification يجيب: هل مخرجات التصميم تحقق المدخلات؟ Validation يجيب: هل المنتج أو العملية يحققان الاستخدام المقصود؟ في تأهيل العمليات، IQ يثبت التركيب الصحيح، OQ يثبت التشغيل عبر النطاق المحدد، وPQ يثبت الأداء المتكرر في ظروف الإنتاج الفعلية.","en":"Verification asks whether design outputs meet inputs. Validation asks whether the product or process meets intended use. In process qualification, IQ confirms correct installation, OQ demonstrates operation across the defined range, and PQ confirms repeatable performance under actual production conditions."},"steps":{"ar":["حدد المتطلب ومعيار القبول.","اختر اختبار Verification أو Validation المناسب.","تأكد من صلاحية أدوات القياس.","نفذ بروتوكولًا معتمدًا وسجل الانحرافات.","قيّم النتائج والتغييرات قبل الموافقة."],"en":["Define the requirement and acceptance criteria.","Select the appropriate verification or validation test.","Confirm measurement-system suitability.","Execute an approved protocol and document deviations.","Evaluate results and changes before approval."]},"example":{"ar":"اختبار البرنامج مقابل مواصفات الوظائف Verification؛ تجربة مستخدم فعلي لإتمام المهمة المقصودة Validation. اختبار الآلة بعد التثبيت IQ، ثم حدود السرعة والحرارة OQ، ثم دفعات فعلية PQ.","en":"Testing software against functional specifications is verification; observing actual users perform the intended task is validation. Machine installation checks are IQ, operating ranges are OQ, and real production lots are PQ."},"tip":{"ar":"النجاح في OQ لا يغني عن PQ؛ ظروف الإنتاج والتشغيل البشري قد تكشف تباينًا غير ظاهر.","en":"Passing OQ does not replace PQ; actual production and human operation may reveal additional variation."},"formula":"","question":{"q":{"ar":"أي مرحلة تثبت الأداء المستمر في ظروف الإنتاج الفعلية؟","en":"Which qualification stage demonstrates sustained performance under actual production conditions?"},"options":{"ar":["IQ","OQ","PQ","MRB"],"en":["IQ","OQ","PQ","MRB"]},"answer":2,"rationale":{"ar":"PQ يثبت أن العملية المؤهلة تنتج باستمرار في الظروف الفعلية.","en":"PQ demonstrates that the qualified process performs consistently under actual conditions."}}},{"domain":3,"code":"3.7","title":{"ar":"الصيانة الوقائية والتنبؤية وأساسيات الاعتمادية","en":"Preventive/Predictive Maintenance and Reliability Fundamentals"},"level":"Apply","ref":"5th ed., Ch. 3; 4th ed., pp. 117–124","concept":{"ar":"الاعتمادية احتمال أداء الوظيفة المطلوبة خلال زمن وظروف محددة. الصيانة التصحيحية تحدث بعد الفشل، والوقائية حسب زمن أو استخدام، والتنبؤية حسب حالة الأصل وبيانات مثل الاهتزاز والحرارة والزيت. TPM يشارك التشغيل والصيانة لرفع الفعالية.","en":"Reliability is the probability of performing a required function for a specified time under stated conditions. Corrective maintenance follows failure, preventive maintenance is scheduled by time or usage, and predictive maintenance is condition-based using data such as vibration, temperature, or oil analysis. TPM engages operations and maintenance to improve effectiveness."},"steps":{"ar":["حدد أنماط الفشل وتأثيرها.","اختر استراتيجية الصيانة حسب الخطر ونمط الفشل.","حدد مؤشرات الحالة وحدود الإنذار.","حلل تاريخ الفشل والتوقف.","راجع فعالية الخطة والتكلفة."],"en":["Identify failure modes and effects.","Choose a maintenance strategy based on risk and failure behavior.","Define condition indicators and alarm limits.","Analyze failure and downtime history.","Review plan effectiveness and cost."]},"example":{"ar":"تغيير Bearing كل ستة أشهر وقائي؛ مراقبة الاهتزاز وتغييره عند نمط تدهور مؤكد تنبؤي. التنبؤي ليس أفضل دائمًا إذا كان حساس القياس أغلى من أثر الفشل.","en":"Replacing a bearing every six months is preventive; monitoring vibration and replacing it when degradation is detected is predictive. Predictive maintenance is not always superior if monitoring costs exceed failure impact."},"tip":{"ar":"اختر استراتيجية الصيانة بناء على نمط الفشل والمخاطر، لا على الموضة التقنية.","en":"Select maintenance strategy based on failure behavior and risk, not technology fashion."},"formula":"","question":{"q":{"ar":"أي مثال يمثل Predictive Maintenance؟","en":"Which example represents predictive maintenance?"},"options":{"ar":["استبدال الجزء بعد تعطله","تغييره كل سنة مهما كانت حالته","مراقبة الاهتزاز وتحديد التدخل حسب اتجاه التدهور","عدم إجراء صيانة"],"en":["Replace after failure","Replace every year regardless of condition","Monitor vibration and intervene based on degradation trend","Perform no maintenance"]},"answer":2,"rationale":{"ar":"التنبؤية تستخدم بيانات حالة الأصل لتحديد وقت التدخل.","en":"Predictive maintenance uses asset-condition data to determine intervention timing."}}},{"domain":3,"code":"3.8","title":{"ar":"مؤشرات الاعتمادية والتوافر","en":"Reliability and Maintainability Indices"},"level":"Apply","ref":"5th ed., Ch. 3; 4th ed., pp. 124–131","concept":{"ar":"MTTF يستخدم غالبًا للعناصر غير القابلة للإصلاح، وMTBF للفاصل المتوسط بين أعطال نظام قابل للإصلاح، وMTTR لمتوسط زمن الإصلاح. التوافر يعتمد على الاعتمادية وقابلية الصيانة، ويمكن تقريبًا حسابه بـ MTBF/(MTBF+MTTR) عندما تنطبق الافتراضات.","en":"MTTF is commonly used for nonrepairable items, MTBF for average time between failures of repairable systems, and MTTR for mean repair time. Availability depends on reliability and maintainability and can be approximated by MTBF/(MTBF+MTTR) when assumptions apply."},"steps":{"ar":["عرّف بداية ونهاية زمن التشغيل والتوقف.","نظف بيانات الفشل المخطط وغير المخطط.","اختر المؤشر المناسب لنوع الأصل.","احسب الاتجاه لا المتوسط فقط.","اربط التحسين بتقليل الفشل أو زمن الإصلاح."],"en":["Define the start and end of uptime and downtime.","Clean planned and unplanned event data.","Select the index appropriate to the asset type.","Analyze trends, not only averages.","Link improvement to fewer failures or faster repair."]},"example":{"ar":"إذا كان MTBF=900 ساعة وMTTR=100 ساعة، فالتوافر التقريبي 900/1000=90%. يمكن رفعه بزيادة MTBF أو خفض MTTR.","en":"If MTBF is 900 hours and MTTR is 100 hours, approximate availability is 900/1000 = 90%. It can improve by increasing MTBF or reducing MTTR."},"tip":{"ar":"توافر مرتفع لا يعني اعتمادية مرتفعة دائمًا؛ قد تتعطل الآلة كثيرًا لكن تُصلح بسرعة.","en":"High availability does not always mean high reliability; equipment may fail frequently but be repaired quickly."},"formula":"Availability = MTBF / (MTBF + MTTR)","question":{"q":{"ar":"إذا كان MTBF=800 وMTTR=200، فما التوافر التقريبي؟","en":"If MTBF=800 and MTTR=200, what is approximate availability?"},"options":{"ar":["20%","60%","80%","100%"],"en":["20%","60%","80%","100%"]},"answer":2,"rationale":{"ar":"A=800/(800+200)=0.80.","en":"A=800/(800+200)=0.80."}}},{"domain":3,"code":"3.9","title":{"ar":"نماذج الاعتمادية: الأسي وWeibull ومنحنى حوض الاستحمام","en":"Reliability Models: Exponential, Weibull, and Bathtub Curve"},"level":"Apply","ref":"5th ed., Ch. 3; 4th ed., pp. 131–135","concept":{"ar":"النموذج الأسي يفترض معدل فشل ثابتًا ويعطي R(t)=e^-λt. Weibull أكثر مرونة؛ β<1 يدل غالبًا على فشل مبكر، β≈1 معدل ثابت، وβ>1 تآكل. منحنى حوض الاستحمام يجمع مرحلة الفشل المبكر والعمر المفيد والتآكل.","en":"The exponential model assumes a constant failure rate and gives R(t)=e^-λt. Weibull is more flexible: β<1 commonly indicates infant mortality, β≈1 a constant rate, and β>1 wear-out. The bathtub curve combines early failures, useful life, and wear-out."},"steps":{"ar":["حدد هل البيانات أزمنة فشل أو معلّمة Censored.","اختبر ملاءمة النموذج.","قدّر المعلمات وفترات الثقة.","فسر Shape Parameter ومعدل الفشل.","استخدم النتيجة في التصميم أو الضمان أو الصيانة."],"en":["Determine whether data are failures or censored observations.","Assess model fit.","Estimate parameters and confidence intervals.","Interpret shape parameter and hazard behavior.","Use results for design, warranty, or maintenance."]},"example":{"ar":"β=0.7 يشير إلى فشل مبكر وقد يستدعي تحسين المورد أو Burn-in؛ β=3 يشير إلى تآكل وقد يدعم استبدالًا وقائيًا.","en":"β=0.7 suggests early-life failure and may call for supplier improvement or burn-in; β=3 indicates wear-out and may support preventive replacement."},"tip":{"ar":"لا تستخدم المتوسط وحده لبيانات اعتمادية منحرفة أو Censored؛ افحص التوزيع.","en":"Do not rely on the mean alone for skewed or censored reliability data; evaluate the distribution."},"formula":"R(t) = exp(-λt)","question":{"q":{"ar":"ماذا يشير Weibull β>1 غالبًا؟","en":"What does a Weibull β>1 commonly indicate?"},"options":{"ar":["فشل مبكر","معدل فشل ثابت","تآكل متزايد مع العمر","عدم وجود فشل"],"en":["Infant mortality","Constant failure rate","Increasing wear-out with age","No failures"]},"answer":2,"rationale":{"ar":"β أكبر من 1 يعني Hazard يزداد مع الزمن عادة.","en":"A beta greater than 1 generally indicates an increasing hazard with time."}}},{"domain":3,"code":"3.10","title":{"ar":"FMEA وFMECA: التصميم والعملية والاستخدام","en":"FMEA and FMECA: Design, Process, and Use"},"level":"Analyze","ref":"5th ed., Ch. 3 new dFMEA/pFMEA/uFMEA content; 4th ed., pp. 135+","concept":{"ar":"FMEA تحليل استباقي يربط الوظيفة بنمط الفشل والأثر والسبب والضوابط والإجراءات. dFMEA يركز على مخاطر التصميم، pFMEA على خطوات التصنيع أو الخدمة، وuFMEA على الاستخدام وسوء الاستخدام المتوقع. FMECA يضيف تحليلًا للحرجية. RPN التقليدي=S×O×D لكنه لا يكفي وحده للقرار.","en":"FMEA is a proactive analysis linking function, failure mode, effect, cause, controls, and actions. dFMEA addresses design risk, pFMEA manufacturing or service steps, and uFMEA use and foreseeable misuse. FMECA adds criticality analysis. Traditional RPN=S×O×D but should not be the sole decision rule."},"steps":{"ar":["حدد النطاق والوظائف.","اكتب الفشل كفقد أو تدهور للوظيفة.","حدد الأثر ثم السبب.","قيّم الضوابط الوقائية والكشفية.","اختر إجراء يقلل السبب أو الخطر وتحقق بعده."],"en":["Define scope and functions.","Write failure as loss or degradation of function.","Identify effect, then cause.","Evaluate preventive and detective controls.","Select actions that reduce cause or risk and verify afterward."]},"example":{"ar":"زيادة الفحص النهائي تحسن Detection غالبًا، لكنها لا تقلل Occurrence. تعديل Fixture لمنع التركيب بالعكس يقلل حدوث السبب.","en":"Increasing final inspection generally improves Detection but not Occurrence. Redesigning a fixture to prevent reverse assembly reduces the cause's occurrence."},"tip":{"ar":"شدة عالية قد تتطلب إجراء حتى لو كان RPN متوسطًا؛ لا ترتب المخاطر بالضرب وحده.","en":"High severity may require action even with a moderate RPN; do not rank risk by multiplication alone."},"formula":"RPN = Severity × Occurrence × Detection","question":{"q":{"ar":"تحسين الفحص النهائي في FMEA يؤثر غالبًا على أي تقييم؟","en":"Improving final inspection in FMEA most directly affects which rating?"},"options":{"ar":["Severity","Occurrence","Detection","Function"],"en":["Severity","Occurrence","Detection","Function"]},"answer":2,"rationale":{"ar":"الفحص يغير احتمال اكتشاف الفشل ولا يزيل السبب عادة.","en":"Inspection changes the probability of detecting failure and usually does not remove its cause."}}},{"domain":3,"code":"3.11","title":{"ar":"تحليل المخاطر والسلامة وFault Tree","en":"Hazard Analysis, Safety, and Fault Tree Analysis"},"level":"Analyze","ref":"5th ed., Ch. 3 new hazard analysis content; 4th ed., reliability/safety tools","concept":{"ar":"Hazard Analysis يبدأ بالخطر والسيناريو والأشخاص المتعرضين والعواقب والضوابط. FTA يبدأ بحدث علوي غير مرغوب ويحلله Top-down باستخدام بوابات AND وOR إلى أسباب أساسية. FMEA غالبًا Bottom-up من مكونات أو خطوات إلى آثار.","en":"Hazard analysis begins with the hazard, scenario, exposed people, consequences, and controls. FTA starts with an undesired top event and decomposes it top-down through AND and OR gates to basic causes. FMEA generally works bottom-up from components or steps to effects."},"steps":{"ar":["عرّف الحدث أو الخطر بدقة.","حدد الحدود والافتراضات.","ابن شجرة الأسباب أو سيناريو التعرض.","ميز الضوابط الوقائية من التخفيفية.","تحقق من Minimal Cut Sets أو فعالية الحواجز."],"en":["Define the event or hazard precisely.","Set system boundaries and assumptions.","Build the cause tree or exposure scenario.","Separate preventive from mitigating controls.","Evaluate minimal cut sets or barrier effectiveness."]},"example":{"ar":"إذا كان تسرب المادة يحدث فقط عند فشل صمام A وفشل مستشعر B معًا، تستخدم بوابة AND. إذا كان أي منهما منفردًا يسبب التسرب، تستخدم OR.","en":"If a release occurs only when valve A and sensor B both fail, use an AND gate. If either failure alone causes the release, use OR."},"tip":{"ar":"اختر FTA عندما يبدأ السؤال بحدث حرج محدد وتريد معرفة تركيبات الأسباب.","en":"Choose FTA when the analysis begins with a defined critical event and seeks combinations of causes."},"formula":"","question":{"q":{"ar":"أي أداة تبدأ بحدث علوي غير مرغوب وتحلله إلى أسباب؟","en":"Which tool starts with an undesired top event and decomposes it into causes?"},"options":{"ar":["FMEA","FTA","QFD","SIPOC"],"en":["FMEA","FTA","QFD","SIPOC"]},"answer":1,"rationale":{"ar":"Fault Tree Analysis منهج Top-down قائم على منطق الأحداث.","en":"Fault Tree Analysis is a top-down event-logic method."}}}]});


window.CQE_DOMAINS=window.CQE_DOMAINS||[];
window.CQE_DOMAINS.push({"id":4,"title":{"ar":"ضبط المنتج والعملية","en":"Product and Process Control"},"weight":23,"desc":{"ar":"خطط التحكم والمواد والعينات والقياس والمترولوجيا وMSA.","en":"Control plans, material control, sampling, measurement, metrology, and MSA."},"lessons":[{"domain":4,"code":"4.1","title":{"ar":"خطط التحكم ونقاط التحكم الحرجة وتعليمات العمل","en":"Control Plans, Critical Control Points, and Work Instructions"},"level":"Analyze","ref":"5th ed., Ch. 4; 4th ed., pp. 137–142","concept":{"ar":"خطة التحكم تربط تدفق العملية وPFMEA بخصائص المنتج والعملية، طريقة القياس، حجم العينة، التكرار، الحدود، وخطة الاستجابة. نقطة التحكم الحرجة هي خطوة يتطلب فقد السيطرة عليها إجراءً محددًا بسبب أثر كبير. تعليمات العمل تحول الضبط إلى خطوات قابلة للتنفيذ والتحقق.","en":"A control plan connects the process flow and PFMEA to product and process characteristics, measurement method, sample size, frequency, limits, and reaction plan. A critical control point is a step where loss of control requires defined action because of significant impact. Work instructions translate controls into executable, verifiable steps."},"steps":{"ar":["راجع Process Flow وPFMEA.","حدد CTQ والخصائص الحرجة.","اختر وسيلة التحكم والعينة.","اكتب Reaction Plan واضحًا.","تحقق من صلاحية التعليمات مع المستخدم وفي الظروف الفعلية."],"en":["Review the process flow and PFMEA.","Identify CTQs and critical characteristics.","Select control method and sampling.","Write a clear reaction plan.","Validate instructions with users under actual conditions."]},"example":{"ar":"خطة تقول «افحص الأبعاد» ناقصة. الخطة الجيدة تحدد البعد، الأداة، التكرار، المسؤول، حدود المواصفة، وقرار الإيقاف أو العزل عند الانحراف.","en":"A plan that says 'inspect dimensions' is incomplete. A good plan specifies the dimension, instrument, frequency, owner, specification limits, and stop/segregation action for deviation."},"tip":{"ar":"Control Plan ليست بديلًا عن PFMEA؛ الاثنان يجب أن يتسقا مع تدفق العملية.","en":"A control plan is not a substitute for PFMEA; both must align with the process flow."},"formula":"","question":{"q":{"ar":"أي عنصر يجب أن يظهر في Reaction Plan؟","en":"Which element should appear in a reaction plan?"},"options":{"ar":["اسم العميل فقط","الإجراء عند تجاوز الحد ومسؤول التنفيذ","تاريخ تأسيس الشركة","قائمة الموردين كاملة"],"en":["Customer name only","Action when a limit is exceeded and the responsible person","Company founding date","Complete supplier list"]},"answer":1,"rationale":{"ar":"خطة الاستجابة تمنع استمرار إنتاج أو استخدام ناتج غير مسيطر عليه.","en":"The reaction plan prevents continued production or use of uncontrolled output."}}},{"domain":4,"code":"4.2","title":{"ar":"تعريف المادة وحالتها والتتبع","en":"Material Identification, Status, and Traceability"},"level":"Analyze","ref":"5th ed., Ch. 4; 4th ed., pp. 142–146","concept":{"ar":"التعريف يحدد ما هي المادة أو القطعة، والحالة تحدد قبولها أو انتظارها أو رفضها، والتتبع يربطها بالمورد والدفعة والعمليات والاختبارات والعميل. مستوى التتبع يجب أن يتناسب مع الخطر ومتطلبات الاستدعاء والتحقيق.","en":"Identification establishes what the material or item is, status shows whether it is accepted, pending, or rejected, and traceability links it to supplier, lot, processes, tests, and customer. Traceability depth should match risk, recall, and investigation requirements."},"steps":{"ar":["حدد وحدة التتبع: قطعة، دفعة، Batch، أو Serial.","استخدم معرفًا لا يتكرر.","اربط الحالة بنظام يمنع الاستخدام.","حافظ على السلسلة خلال التقسيم والدمج.","اختبر القدرة على تتبع للأمام والخلف."],"en":["Define the traceability unit: item, lot, batch, or serial.","Use a unique identifier.","Link status to a system that prevents unintended use.","Maintain lineage through splitting and merging.","Test forward and backward traceability."]},"example":{"ar":"عند تقسيم لفافة خام إلى ثلاث دفعات إنتاج، يجب الاحتفاظ بعلاقة كل دفعة باللفافة الأصلية وبالعملاء الذين استلموها.","en":"When a raw-material coil is split into three production lots, each lot must retain linkage to the original coil and to customers who received it."},"tip":{"ar":"بطاقة اللون وحدها ضعيفة إذا أمكن سقوطها أو تفسيرها خطأ؛ استخدم معرفًا وسجلًا ونظام منع مادي أو إلكتروني.","en":"A color tag alone is weak if it can fall off or be misread; use identification, records, and physical or electronic prevention."},"formula":"","question":{"q":{"ar":"ما الفرق الأدق بين Status وTraceability؟","en":"What is the most accurate distinction between status and traceability?"},"options":{"ar":["لا فرق","Status يبين قرار القبول الحالي، وTraceability يربط التاريخ والمصدر والوجهة","Status يحدد المورد فقط","Traceability تعني لون البطاقة"],"en":["There is no difference","Status shows current acceptance state; traceability links history, source, and destination","Status identifies only the supplier","Traceability means tag color"]},"answer":1,"rationale":{"ar":"الحالة قرار آني، بينما التتبع سلسلة معلومات عبر دورة الحياة.","en":"Status is a current disposition; traceability is an information chain across the life cycle."}}},{"domain":4,"code":"4.3","title":{"ar":"العزل وتصنيف العيوب وعدم المطابقة","en":"Segregation and Classification of Defects and Nonconformities"},"level":"Evaluate","ref":"5th ed., Ch. 4; 4th ed., pp. 146–147","concept":{"ar":"العزل يمنع الاستخدام أو الشحن غير المقصود، وقد يكون ماديًا أو إلكترونيًا أو بإيقاف العملية. تصنيف العيوب Critical/Major/Minor يعتمد على الأثر لا على سهولة الإصلاح. يجب توحيد التعريفات لضمان اتساق القرارات والعينات.","en":"Segregation prevents unintended use or shipment and may be physical, electronic, or achieved through process hold. Critical, major, and minor classification is based on effect, not ease of repair. Definitions must be standardized for consistent decisions and sampling."},"steps":{"ar":["أوقف الحركة أو الاستخدام فورًا.","عرّف الكمية والنطاق والحالة.","اعزل فعليًا أو إلكترونيًا.","صنف الأثر وفق معايير معتمدة.","راجع المنتجات المشابهة وفترة الخطر."],"en":["Stop movement or use immediately.","Define quantity, scope, and status.","Segregate physically or electronically.","Classify impact using approved criteria.","Review similar product and the risk window."]},"example":{"ar":"خدش تجميلي بسيط قد يكون Minor، لكن نفس الخدش على سطح إحكام قد يسبب تسربًا ويصبح Major أو Critical حسب العاقبة.","en":"A small cosmetic scratch may be minor, but the same scratch on a sealing surface may cause leakage and become major or critical depending on consequence."},"tip":{"ar":"لا تصنف العيب باسم الظاهرة فقط؛ التصنيف يتبع تأثيره في الاستخدام والسلامة.","en":"Do not classify a defect by its visual description alone; classification follows use and safety impact."},"formula":"","question":{"q":{"ar":"ما العامل الأساسي في تصنيف العيب Critical أو Major أو Minor؟","en":"What is the primary basis for classifying a defect as critical, major, or minor?"},"options":{"ar":["تكلفة إعادة العمل فقط","تأثير العيب على السلامة والوظيفة والاستخدام","لون المنتج","خبرة المفتش فقط"],"en":["Rework cost only","Effect on safety, function, and use","Product color","Inspector experience only"]},"answer":1,"rationale":{"ar":"التصنيف مبني على العاقبة والمخاطر.","en":"Classification is based on consequence and risk."}}},{"domain":4,"code":"4.4","title":{"ar":"مجلس مراجعة المواد وقرارات التصرف","en":"Material Review Board and Disposition Decisions"},"level":"Evaluate","ref":"5th ed., Ch. 4; 4th ed., pp. 147–148","concept":{"ar":"MRB فريق مخول متعدد التخصصات يقيّم المنتج غير المطابق ويقرر Rework أو Repair أو Use-as-is/Concession أو Return أو Scrap. Rework يعيد المنتج للمواصفة الأصلية؛ Repair يجعله صالحًا لكن قد لا يعيده للمواصفة ويحتاج قبولًا مخولًا.","en":"The MRB is an authorized cross-functional body that evaluates nonconforming product and decides rework, repair, use-as-is/concession, return, or scrap. Rework restores original conformity; repair makes the item usable but may not restore full specification and requires authorized acceptance."},"steps":{"ar":["ثبت عدم المطابقة ونطاقها.","قيّم أثرها على الوظيفة والسلامة والموثوقية.","حدد السلطة المطلوبة والعميل المتأثر.","اختر التصرف ووثق الأساس.","تحقق من تنفيذ القرار وتحديث المخاطر."],"en":["Confirm the nonconformity and scope.","Evaluate effect on function, safety, and reliability.","Determine required authority and affected customer.","Select disposition and document the basis.","Verify execution and update risk information."]},"example":{"ar":"إعادة تشغيل عملية لحام حتى تحقق المعايير الأصلية Rework. إضافة دعامة غير موجودة في التصميم لجعل الجزء صالحًا Repair وقد تحتاج موافقة هندسية وعميل.","en":"Repeating a welding process until original criteria are met is rework. Adding a brace not in the original design to make the part usable is repair and may require engineering and customer approval."},"tip":{"ar":"Use-as-is ليس قرار المفتش منفردًا؛ يتطلب سلطة فنية وتعاقدية مناسبة.","en":"Use-as-is is not an inspector's unilateral decision; it requires appropriate technical and contractual authority."},"formula":"","question":{"q":{"ar":"أي وصف يمثل Rework؟","en":"Which description represents rework?"},"options":{"ar":["إعادة المنتج إلى المواصفة الأصلية","قبول المنتج دون تغيير","تعديل لا يحقق المواصفة الأصلية لكنه يجعله صالحًا","إتلاف المنتج"],"en":["Restore the product to original specification","Accept without change","Modify it so it is usable but not fully to original specification","Scrap the product"]},"answer":0,"rationale":{"ar":"Rework يعيد المطابقة الكاملة للمواصفة الأصلية.","en":"Rework restores full conformity to the original requirement."}}},{"domain":4,"code":"4.5","title":{"ar":"مفاهيم أخذ العينات ومخاطر المنتج والعميل","en":"Acceptance Sampling Concepts and Producer/Consumer Risks"},"level":"Apply","ref":"5th ed., Ch. 4; 4th ed., pp. 148–158","concept":{"ar":"أخذ العينات للقبول يقرر قبول دفعة أو رفضها؛ ولا يضمن جودة كل وحدة ولا يثبت استقرار العملية. OC Curve تربط نسبة عدم المطابقة باحتمال القبول. Producer's Risk α هو احتمال رفض دفعة جيدة، وConsumer's Risk β احتمال قبول دفعة سيئة. AQL يمثل مستوى عملية يمكن احتماله لسلسلة دفعات، بينما LTPD/RQL مستوى رديء يرغب العميل في رفضه غالبًا.","en":"Acceptance sampling decides whether to accept or reject a lot; it does not guarantee every unit or prove process stability. The OC curve links fraction nonconforming to probability of acceptance. Producer's risk α is the probability of rejecting a good lot, and consumer's risk β is the probability of accepting a bad lot. AQL represents a tolerable process average for a series of lots, while LTPD/RQL is a poor level the customer wants rejected most of the time."},"steps":{"ar":["حدد أن الهدف قرار دفعة لا ضبط عملية.","حدد AQL وLTPD والمخاطر المقبولة.","اختر حجم العينة n وعدد القبول c.","احسب أو اقرأ احتمال القبول.","طبق قواعد التصرف بعد القبول أو الرفض."],"en":["Define the purpose as lot disposition, not process control.","Set AQL, LTPD, and acceptable risks.","Choose sample size n and acceptance number c.","Calculate or read probability of acceptance.","Apply disposition rules after acceptance or rejection."]},"example":{"ar":"خطة n=50,c=1 تقبل الدفعة إذا وجدت وحدة غير مطابقة واحدة أو أقل. رفع c يزيد احتمال القبول ويحمي المنتج أكثر لكنه يزيد خطر العميل.","en":"A plan with n=50,c=1 accepts a lot when one or fewer nonconforming units are found. Increasing c raises acceptance probability, protecting the producer more while increasing consumer risk."},"tip":{"ar":"AQL لا يعني أن الدفعة «جيدة» أو أنها ستقبل دائمًا؛ هو نقطة على OC Curve واحتمال القبول ليس 100%.","en":"AQL does not mean the lot is automatically 'good' or will always be accepted; it is a point on the OC curve and acceptance probability is not 100%."},"formula":"","question":{"q":{"ar":"Producer's Risk هو احتمال:","en":"Producer's risk is the probability of:"},"options":{"ar":["قبول دفعة سيئة","رفض دفعة جيدة","قبول دفعة جيدة","رفض دفعة سيئة"],"en":["Accepting a bad lot","Rejecting a good lot","Accepting a good lot","Rejecting a bad lot"]},"answer":1,"rationale":{"ar":"يرمز له عادة α ويمثل خطر الرفض غير العادل لدفعة جيدة.","en":"It is usually denoted α and represents the risk of rejecting a good lot."}}},{"domain":4,"code":"4.6","title":{"ar":"خطط ANSI/ASQ Z1.4 وZ1.9","en":"ANSI/ASQ Z1.4 and Z1.9 Sampling Plans"},"level":"Analyze","ref":"5th ed., Ch. 4; 4th ed., pp. 158–176","concept":{"ar":"Z1.4 يستخدم بيانات الصفات وعدد الوحدات غير المطابقة، بينما Z1.9 يستخدم بيانات متغيرة عندما تكون القياسات موثوقة والافتراضات مناسبة. تحدد الجداول حجم الدفعة ومستوى الفحص وحرف الكود وحجم العينة وأرقام القبول والرفض، مع Switching Rules بين Normal وTightened وReduced.","en":"Z1.4 uses attribute data and counts of nonconforming units, while Z1.9 uses variable measurements when the measurement system and assumptions are suitable. Tables determine lot size, inspection level, code letter, sample size, acceptance/rejection criteria, and switching rules among normal, tightened, and reduced inspection."},"steps":{"ar":["حدد Attribute أو Variable.","حدد حجم الدفعة ومستوى الفحص وAQL.","استخرج Code Letter.","اختر نوع الخطة وحالة الفحص.","طبق Switching Rules دون انتقاء يدوي."],"en":["Choose attribute or variable sampling.","Set lot size, inspection level, and AQL.","Obtain the code letter.","Select plan type and inspection state.","Apply switching rules without selective override."]},"example":{"ar":"Reduced Inspection لا يُختار لتقليل الجهد فقط؛ الانتقال إليه يحتاج تاريخ قبول وأداء مستقر وشروطًا محددة في المعيار.","en":"Reduced inspection is not chosen merely to reduce effort; transition requires acceptance history, stable performance, and specified conditions."},"tip":{"ar":"خطة Variables قد تحتاج عينة أصغر لكنها تصبح مضللة إذا كان القياس ضعيفًا أو التوزيع غير مناسب.","en":"A variables plan may need a smaller sample but becomes misleading if measurement is poor or distribution assumptions are invalid."},"formula":"","question":{"q":{"ar":"أي معيار يرتبط أساسًا بأخذ العينات بالمتغيرات؟","en":"Which standard is primarily associated with variables sampling?"},"options":{"ar":["Z1.4","Z1.9","ISO 9001 only","FMEA"],"en":["Z1.4","Z1.9","ISO 9001 only","FMEA"]},"answer":1,"rationale":{"ar":"Z1.9 مخصص للمتغيرات، بينما Z1.4 للصفات.","en":"Z1.9 addresses variables sampling, while Z1.4 addresses attributes."}}},{"domain":4,"code":"4.7","title":{"ar":"سلامة العينة وتمثيل الدفعة","en":"Sample Integrity and Lot Representation"},"level":"Apply","ref":"5th ed., Ch. 4; 4th ed., pp. 176–178","concept":{"ar":"العينة الصحيحة يجب أن تمثل الدفعة بلا تحيز وأن تبقى هويتها وحالتها محفوظتين. يتأثر القرار بطريقة تكوين الدفعة، العشوائية، مكان ووقت السحب، التخزين، التلوث، والنقل وسلسلة الحيازة.","en":"A valid sample must represent the lot without bias and retain its identity and condition. Lot formation, randomness, sampling location and time, storage, contamination, transport, and chain of custody all affect the decision."},"steps":{"ar":["عرّف الدفعة وتجانسها.","اختر طريقة عشوائية أو منهجية مبررة.","وزع السحب على المواقع والأزمنة عند الحاجة.","وسم واحم العينة وسجل Chain of Custody.","عالج العينة التالفة أو المفقودة وفق إجراء."],"en":["Define the lot and its homogeneity.","Use a justified random or systematic method.","Spread selection across locations and times as needed.","Label, protect, and document chain of custody.","Handle damaged or missing samples under procedure."]},"example":{"ar":"أخذ أول عشر قطع من أعلى صندوق كبير قد لا يمثل القاع أو الوحدات المنتجة لاحقًا. العشوائية تمنح كل وحدة فرصة معروفة للاختيار.","en":"Taking the first ten pieces from the top of a large container may not represent the bottom or later production. Randomization gives each unit a known chance of selection."},"tip":{"ar":"نتيجة المختبر لا قيمة لها إذا فُقدت هوية العينة أو تغيرت حالتها أثناء النقل.","en":"A laboratory result is not valid if sample identity is lost or condition changes during transport."},"formula":"","question":{"q":{"ar":"ما المشكلة الأساسية في سحب العينة من أول وحدات فقط؟","en":"What is the main problem with sampling only the first units?"},"options":{"ar":["زيادة الدقة دائمًا","تحيز وعدم تمثيل بقية الدفعة","زيادة AQL","تقليل عدم اليقين تلقائيًا"],"en":["It always increases accuracy","Bias and poor representation of the remaining lot","It increases AQL","It automatically reduces uncertainty"]},"answer":1,"rationale":{"ar":"العينة يجب أن تمثل التباين المكاني والزمني للدفعة.","en":"The sample should represent spatial and temporal variation in the lot."}}},{"domain":4,"code":"4.8","title":{"ar":"أدوات القياس وCMM","en":"Inspection Tools and Coordinate Measuring Machines"},"level":"Analyze","ref":"5th ed., Ch. 4 new CMM content; 4th ed., pp. 178–191","concept":{"ar":"اختيار أداة القياس يعتمد على الخاصية والنطاق والتفاوت والدقة المطلوبة والهندسة والبيئة ومعدل الإنتاج. تشمل الأدوات Gage Blocks وCalipers وMicrometers وHeight Gages وOptical Comparators وCMM. في CMM يجب ضبط التثبيت والمحاذاة واستراتيجية النقاط والبرنامج والمراجعة.","en":"Measurement-tool selection depends on characteristic, range, tolerance, required accuracy, geometry, environment, and production rate. Tools include gage blocks, calipers, micrometers, height gages, optical comparators, and CMMs. CMM use requires control of fixturing, alignment, point strategy, software, and revision."},"steps":{"ar":["حدد Measurand والتفاوت.","اختر مبدأ القياس والدقة المناسبة.","تحقق من Resolution والقدرة.","ثبت الجزء دون تشويه.","تحكم في البرنامج والمحاذاة والبيئة."],"en":["Define the measurand and tolerance.","Select the measurement principle and required accuracy.","Verify resolution and capability.","Fixture the part without distortion.","Control program, alignment, and environment."]},"example":{"ar":"قياس تفاوت 0.02 mm بأداة Resolution=0.01 mm يعطي قدرة تمييز ضعيفة. قد يلزم Micrometer أو CMM مناسب حسب الشكل الهندسي.","en":"Measuring a 0.02 mm tolerance with 0.01 mm resolution provides poor discrimination. A micrometer or suitable CMM may be required depending on geometry."},"tip":{"ar":"قاعدة 10:1 إرشادية؛ القرار النهائي يعتمد على عدم اليقين والمخاطر ونظام القياس كاملًا.","en":"The 10:1 rule is guidance; the final decision depends on uncertainty, risk, and the full measurement system."},"formula":"","question":{"q":{"ar":"ما العامل الأساسي لاختيار أداة القياس؟","en":"What is the primary basis for selecting a measurement tool?"},"options":{"ar":["لون الأداة","الخاصية والتفاوت والدقة المطلوبة","تفضيل المفتش فقط","السعر الأقل دائمًا"],"en":["Instrument color","Characteristic, tolerance, and required accuracy","Inspector preference alone","Always the lowest price"]},"answer":1,"rationale":{"ar":"الاختيار يبدأ من متطلبات القياس الفنية.","en":"Selection starts with technical measurement requirements."}}},{"domain":4,"code":"4.9","title":{"ar":"الاختبارات الإتلافية وغير الإتلافية","en":"Destructive and Nondestructive Testing"},"level":"Apply","ref":"5th ed., Ch. 4; 4th ed., pp. 191–193","concept":{"ar":"الاختبار الإتلافي يقيس خصائص مثل الشد أو الانفجار أو العمر حتى الفشل، بينما NDT يكشف العيوب دون تدمير الجزء باستخدام Visual وLiquid Penetrant وMagnetic Particle وUltrasonic وRadiographic وغيرها. الاختيار يعتمد على المادة ونوع العيب وموقعه والحساسية والسلامة والتكلفة.","en":"Destructive testing measures properties such as tensile strength, burst, or life to failure. NDT detects flaws without destroying the part using visual, liquid penetrant, magnetic particle, ultrasonic, radiographic, and other methods. Selection depends on material, flaw type and location, sensitivity, safety, and cost."},"steps":{"ar":["حدد العيب المتوقع وموقعه.","تحقق من توافق الطريقة مع المادة.","حدد الحساسية ومعايير القبول.","استخدم أفرادًا وإجراءات مؤهلة.","وثق القيود والنتائج واحم السلامة."],"en":["Identify the expected flaw and its location.","Confirm method compatibility with the material.","Set sensitivity and acceptance criteria.","Use qualified personnel and procedures.","Document limitations and results and protect safety."]},"example":{"ar":"Magnetic Particle يناسب المواد ferromagnetic ولا يناسب الألومنيوم. Liquid Penetrant يكشف عيوبًا مفتوحة على السطح في مواد غير مسامية.","en":"Magnetic particle testing suits ferromagnetic materials and not aluminum. Liquid penetrant detects surface-breaking flaws in nonporous materials."},"tip":{"ar":"لا توجد طريقة NDT واحدة تكشف كل العيوب؛ افهم قدرة وحدود كل طريقة.","en":"No single NDT method detects every flaw; understand the capability and limitations of each method."},"formula":"","question":{"q":{"ar":"أي طريقة مناسبة عادة لعيب سطحي مفتوح في ألمنيوم غير مسامي؟","en":"Which method is generally suitable for a surface-breaking flaw in nonporous aluminum?"},"options":{"ar":["Magnetic particle","Liquid penetrant","Only tensile testing","Gage blocks"],"en":["Magnetic particle","Liquid penetrant","Only tensile testing","Gage blocks"]},"answer":1,"rationale":{"ar":"PT لا يعتمد على المغناطيسية ويكشف العيوب المفتوحة على السطح.","en":"PT does not require ferromagnetism and detects surface-breaking flaws."}}},{"domain":4,"code":"4.10","title":{"ar":"المترولوجيا والتتبع وعدم اليقين","en":"Metrology, Traceability, and Measurement Uncertainty"},"level":"Apply","ref":"5th ed., Ch. 4; 4th ed., pp. 193–200","concept":{"ar":"المترولوجيا علم القياس. Measurement Traceability هي سلسلة معايرات موثقة غير منقطعة إلى مرجع معترف به، وكل حلقة لها عدم يقين. Measurement Uncertainty يصف تشتت القيم المعقولة للمقاس؛ وهو ليس الخطأ نفسه لكنه يحدد الثقة في النتيجة ويدخل في قرار المطابقة.","en":"Metrology is the science of measurement. Measurement traceability is an unbroken documented chain of calibrations to a recognized reference, with uncertainty at each link. Measurement uncertainty describes the dispersion of values reasonably attributable to the measurand; it is not identical to error but affects confidence and conformity decisions."},"steps":{"ar":["عرّف Measurand وظروف القياس.","حدد مصادر عدم اليقين.","قدّر Type A وType B.","ادمج المكونات وحدد Expanded Uncertainty.","استخدم Decision Rule قرب حدود المواصفة."],"en":["Define the measurand and conditions.","Identify uncertainty sources.","Estimate Type A and Type B components.","Combine components and determine expanded uncertainty.","Use a decision rule near specification limits."]},"example":{"ar":"نتيجة 10.00±0.08 mm مقابل USL=10.05 لا تسمح بقرار بسيط دون قاعدة قرار؛ جزء من نطاق عدم اليقين يتجاوز الحد.","en":"A result of 10.00±0.08 mm against USL=10.05 cannot support a simple decision without a decision rule; part of the uncertainty interval exceeds the limit."},"tip":{"ar":"شهادة معايرة لا تعني تلقائيًا أن الأداة مناسبة للتفاوت؛ افحص عدم اليقين والاستخدام.","en":"A calibration certificate does not automatically mean the instrument is suitable for the tolerance; evaluate uncertainty and use."},"formula":"","question":{"q":{"ar":"ما معنى Measurement Traceability؟","en":"What does measurement traceability mean?"},"options":{"ar":["تكرار القياس فقط","سلسلة موثقة غير منقطعة إلى مرجع معترف به مع عدم يقين","وجود ملصق على الجهاز","أن تكون النتيجة داخل المواصفة"],"en":["Repeating the measurement only","An unbroken documented chain to a recognized reference with uncertainty","Having a label on the instrument","The result being within specification"]},"answer":1,"rationale":{"ar":"التتبع يتعلق بسلسلة المقارنة المرجعية الموثقة وعدم اليقين.","en":"Traceability concerns the documented reference chain and associated uncertainty."}}},{"domain":4,"code":"4.11","title":{"ar":"إدارة المعايرة والأجهزة خارج الحالة","en":"Calibration Management and Out-of-Tolerance Equipment"},"level":"Apply","ref":"5th ed., Ch. 4; 4th ed., pp. 200–202","concept":{"ar":"برنامج المعايرة يضبط التسجيل والفترات والمعايير والبيئة والحماية والحالة والسجلات. فترة المعايرة تعتمد على الاستقرار والاستخدام والخطر والتاريخ، لا على سنة ثابتة لكل جهاز. عند اكتشاف Out-of-Tolerance يجب تقييم أثر القياسات السابقة والمنتج المحتمل تأثره.","en":"A calibration program controls registration, intervals, standards, environment, protection, status, and records. Calibration interval should reflect stability, usage, risk, and history, not a fixed annual rule for every device. When equipment is found out of tolerance, prior measurements and potentially affected product must be assessed."},"steps":{"ar":["احصر جميع الأجهزة ومواقعها.","حدد الفاصل بناءً على المخاطر والتاريخ.","امنع الاستخدام بعد الاستحقاق.","عند OOT حدد آخر حالة معروفة صحيحة.","راجع المنتج المقاس واتخذ تصرفًا موثقًا."],"en":["Maintain an inventory and location of instruments.","Set intervals based on risk and history.","Prevent use after due date.","For OOT, identify the last known valid state.","Review measured product and take documented action."]},"example":{"ar":"ميكرومتر وجد منحازًا +0.05 mm. يجب تحديد متى بدأ الانحراف المحتمل والقطع المقاسة منذ آخر تحقق موثوق، لا الاكتفاء بإعادة المعايرة.","en":"A micrometer is found biased by +0.05 mm. Determine when the deviation may have begun and which parts were measured since the last reliable verification; recalibration alone is insufficient."},"tip":{"ar":"الملصق «معاير» يصف الحالة الإدارية، وليس قدرة النظام على القياس.","en":"A 'calibrated' label describes administrative status, not measurement-system capability."},"formula":"","question":{"q":{"ar":"ما الإجراء الأول بعد اكتشاف جهاز خارج حدود المعايرة؟","en":"What is the first action after finding an instrument out of tolerance?"},"options":{"ar":["إعادة الملصق فقط","عزله ومنع استخدامه ثم تقييم أثر القياسات السابقة","تجاهل الانحراف","تغيير المواصفة"],"en":["Replace the label only","Remove it from use and evaluate the impact of prior measurements","Ignore the deviation","Change the specification"]},"answer":1,"rationale":{"ar":"يجب حماية القياسات الحالية وتقييم المنتج المحتمل تأثره.","en":"Current measurements must be protected and potentially affected product evaluated."}}},{"domain":4,"code":"4.12","title":{"ar":"تحليل نظام القياس وGage R&R","en":"Measurement System Analysis and Gage R&R"},"level":"Evaluate","ref":"5th ed., Ch. 4; 4th ed., pp. 202–216","concept":{"ar":"MSA يقيم النظام الكامل: الجهاز والطريقة والمشغل والجزء والبيئة. Bias فرق المتوسط عن المرجع، Linearity تغير Bias عبر النطاق، Stability تغيره مع الزمن، Repeatability تباين داخل المقيم، وReproducibility تباين بين المقيمين. Gage R&R يقارن تباين القياس بالتباين الكلي أو التفاوت.","en":"MSA evaluates the whole system: instrument, method, appraiser, part, and environment. Bias is average difference from reference, linearity is change in bias across the range, stability is change over time, repeatability is within-appraiser variation, and reproducibility is between-appraiser variation. Gage R&R compares measurement variation with total variation or tolerance."},"steps":{"ar":["اختر أجزاء تمثل نطاق العملية.","استخدم مقيمين وTrials وترتيبًا عشوائيًا.","حلل EV وAV وGRR وPart-to-Part.","افحص الرسومات والتفاعلات لا النسبة فقط.","عالج الجهاز أو الطريقة أو التدريب أو التثبيت حسب المصدر."],"en":["Select parts spanning process variation.","Use multiple appraisers, trials, and randomized order.","Analyze equipment variation, appraiser variation, GRR, and part-to-part.","Review plots and interactions, not only a single percentage.","Address instrument, method, training, or fixturing according to source."]},"example":{"ar":"إذا اتفق كل مقيم مع نفسه لكن اختلف متوسط كل مقيم، فالمشكلة Reproducibility. إذا تذبذبت قراءات الشخص نفسه، فالمشكلة Repeatability.","en":"If each appraiser is internally consistent but their averages differ, the issue is reproducibility. If the same appraiser's repeated readings vary, the issue is repeatability."},"tip":{"ar":"إرشادات 10% و30% ليست قوانين مطلقة؛ القرار يعتمد على الخطر والاستخدام والتكلفة.","en":"The 10% and 30% guidelines are not absolute laws; acceptance depends on risk, use, and cost."},"formula":"","question":{"q":{"ar":"أي مكوّن من Gage R&R يرتبط غالبًا باختلاف المقيمين؟","en":"Which Gage R&R component is commonly associated with differences among appraisers?"},"options":{"ar":["Repeatability","Reproducibility","Part-to-part only","Specification width"],"en":["Repeatability","Reproducibility","Part-to-part only","Specification width"]},"answer":1,"rationale":{"ar":"Reproducibility يقيس الاختلاف بين المقيمين أو الظروف.","en":"Reproducibility measures variation among appraisers or conditions."}}}]});


window.CQE_DOMAINS=window.CQE_DOMAINS||[];
window.CQE_DOMAINS.push({"id":5,"title":{"ar":"التحسين المستمر","en":"Continuous Improvement"},"weight":26,"desc":{"ar":"أدوات الجودة وLean وSix Sigma وRCA والإجراءات التصحيحية والوقاية.","en":"Quality tools, Lean, Six Sigma, RCA, corrective action, and prevention."},"lessons":[{"domain":5,"code":"5.1","title":{"ar":"خرائط التدفق وPareto وCheck Sheets","en":"Flowcharts, Pareto Charts, and Check Sheets"},"level":"Analyze","ref":"5th ed., Ch. 5; 4th ed., pp. 217–225","concept":{"ar":"Flowchart يكشف التسلسل والقرارات وإعادة العمل ونقاط التسليم. Check Sheet يجمع البيانات بطريقة منظمة في موقع الحدث. Pareto يرتب الفئات حسب التكرار أو التكلفة أو الأثر لتحديد القلة المؤثرة، لكنه لا يثبت السبب الجذري.","en":"A flowchart reveals sequence, decisions, rework, and handoffs. A check sheet collects structured data at the point of occurrence. A Pareto chart ranks categories by frequency, cost, or impact to identify the vital few, but it does not prove root cause."},"steps":{"ar":["حدد السؤال الذي تريد إجابته.","عرّف الفئات بصورة غير متداخلة.","اجمع البيانات بالزمن والمكان والمنتج.","ارسم العملية الفعلية لا المفترضة.","استخدم Pareto لتحديد أولوية التحليل التالي."],"en":["Define the question to be answered.","Create mutually exclusive categories.","Collect data by time, location, and product.","Map the actual process, not the assumed one.","Use Pareto to prioritize the next analysis."]},"example":{"ar":"إذا كانت فئة «أخرى» أكبر عمود في Pareto، فالتصنيف ضعيف ويجب تفكيكها قبل اختيار مشروع.","en":"If 'Other' is the largest Pareto category, the classification is weak and should be broken down before selecting a project."},"tip":{"ar":"Pareto يحدد أين نبدأ، لكنه لا يثبت لماذا حدثت المشكلة.","en":"Pareto shows where to start, not why the problem occurred."},"formula":"","question":{"q":{"ar":"ما الاستخدام الأفضل لمخطط Pareto؟","en":"What is the best use of a Pareto chart?"},"options":{"ar":["إثبات السبب الجذري","ترتيب الفئات حسب الأثر لتحديد الأولوية","حساب Cpk","معايرة الجهاز"],"en":["Prove root cause","Rank categories by impact to set priority","Calculate Cpk","Calibrate an instrument"]},"answer":1,"rationale":{"ar":"Pareto أداة ترتيب للأولوية لا أداة إثبات سببي.","en":"Pareto is a prioritization tool, not proof of causation."}}},{"domain":5,"code":"5.2","title":{"ar":"مخطط السبب والأثر وScatter وHistogram وControl Charts","en":"Cause-and-Effect, Scatter, Histogram, and Control Charts"},"level":"Analyze","ref":"5th ed., Ch. 5; 4th ed., pp. 219–229","concept":{"ar":"Cause-and-Effect ينظم الأسباب المحتملة ضمن فئات مثل Man, Machine, Method, Material, Measurement, Environment. Scatter يوضح علاقة بين متغيرين ولا يثبت السببية. Histogram يوضح شكل التوزيع. Control Chart يضع البيانات في الزمن ويميز التباين العام والخاص.","en":"A cause-and-effect diagram organizes possible causes under categories such as man, machine, method, material, measurement, and environment. A scatter plot shows association between two variables but does not prove causality. A histogram displays distribution shape. A control chart orders data over time and distinguishes common from special variation."},"steps":{"ar":["استخدم Fishbone لتوليد فرضيات.","حوّل كل فرع إلى سبب قابل للاختبار.","استخدم Scatter لفحص العلاقة.","استخدم Histogram لفهم الشكل.","استخدم Control Chart لفحص الاستقرار عبر الزمن."],"en":["Use fishbone to generate hypotheses.","Convert each branch into a testable cause.","Use scatter to examine association.","Use histogram to understand shape.","Use a control chart to assess stability over time."]},"example":{"ar":"قد يظهر Scatter علاقة بين الحرارة والعيب، لكن إذا ارتفع كلاهما مع سرعة الخط فالعلاقة قد تكون مربكة Confounded؛ يلزم تحليل أو تجربة.","en":"A scatter plot may show a relationship between temperature and defects, but if both rise with line speed, the relationship may be confounded; further analysis or experimentation is needed."},"tip":{"ar":"Fishbone ينتج قائمة أسباب محتملة، وليس قائمة أسباب جذرية مؤكدة.","en":"A fishbone diagram generates possible causes, not confirmed root causes."},"formula":"","question":{"q":{"ar":"أي أداة تحتفظ بترتيب البيانات الزمني وتكشف أسبابًا خاصة؟","en":"Which tool preserves time order and detects special causes?"},"options":{"ar":["Histogram","Control chart","Pareto chart","Affinity diagram"],"en":["Histogram","Control chart","Pareto chart","Affinity diagram"]},"answer":1,"rationale":{"ar":"Control Chart يجمع الزمن بحدود إحصائية وإشارات عدم الاستقرار.","en":"A control chart combines time order with statistical limits and instability signals."}}},{"domain":5,"code":"5.3","title":{"ar":"أدوات الإدارة والتخطيط السبع","en":"Seven Management and Planning Tools"},"level":"Analyze","ref":"5th ed., Ch. 5; 4th ed., pp. 229–255","concept":{"ar":"تشمل الأدوات Affinity لتنظيم الأفكار، Interrelationship Digraph لفهم التأثيرات، Tree Diagram لتفكيك الهدف، Matrix لربط مجموعات، Prioritization Matrix لاختيار البدائل، PDPC للتنبؤ بما قد يفشل، وActivity Network لتخطيط الأنشطة والمسار الحرج. Force-Field يوازن القوى الدافعة والمقاومة.","en":"The tools include affinity diagrams for organizing ideas, interrelationship digraphs for influence, tree diagrams for decomposing objectives, matrix diagrams for relationships, prioritization matrices for alternative selection, PDPC for anticipating failures, and activity network diagrams for scheduling and critical path. Force-field analysis balances driving and restraining forces."},"steps":{"ar":["اختر الأداة حسب سؤال الفريق.","اجمع مدخلات متعددة التخصصات.","حدد معايير ووزنًا قبل التقييم.","وثق الافتراضات والعلاقات.","حوّل المخرج إلى قرار وخطة."],"en":["Select the tool according to the team's question.","Gather cross-functional input.","Set criteria and weights before scoring.","Document assumptions and relationships.","Convert output into a decision and plan."]},"example":{"ar":"إذا كان الهدف «خفض زمن التسليم»، Tree Diagram يقسمه إلى عوامل فرعية، ثم Prioritization Matrix تقارن الحلول حسب الأثر والتكلفة والمخاطر.","en":"For the objective 'reduce lead time,' a tree diagram breaks it into drivers, then a prioritization matrix compares solutions by impact, cost, and risk."},"tip":{"ar":"لا تغيّر أوزان المعايير بعد رؤية النتيجة لتفضيل حل معين.","en":"Do not change criterion weights after seeing results to favor a preferred solution."},"formula":"","question":{"q":{"ar":"أي أداة تُستخدم لتوقع ما قد يفشل في الخطة ووضع إجراءات مضادة؟","en":"Which tool anticipates what may go wrong in a plan and identifies countermeasures?"},"options":{"ar":["PDPC","Histogram","p-chart","Gage R&R"],"en":["PDPC","Histogram","p-chart","Gage R&R"]},"answer":0,"rationale":{"ar":"Process Decision Program Chart يوسع الخطة إلى مشكلات محتملة وإجراءات بديلة.","en":"PDPC expands a plan into potential problems and countermeasures."}}},{"domain":5,"code":"5.4","title":{"ar":"TQM وKaizen وPDCA","en":"TQM, Kaizen, and PDCA"},"level":"Analyze","ref":"5th ed., Ch. 5; 4th ed., pp. 255–259","concept":{"ar":"TQM فلسفة إدارة شاملة تركز على العميل والقيادة والعمليات والمشاركة. Kaizen تحسينات صغيرة مستمرة يقودها العاملون. PDCA/PDSA دورة تعلم: Plan يبني النظرية والتوقع، Do يجرب، Check/Study يحلل، Act يثبت أو يعدل.","en":"TQM is an organization-wide management philosophy centered on customers, leadership, processes, and participation. Kaizen consists of small continuous improvements led by people doing the work. PDCA/PDSA is a learning cycle: Plan forms a theory and prediction, Do tests it, Check/Study analyzes, and Act standardizes or revises."},"steps":{"ar":["حدد المشكلة والهدف والتوقع.","نفذ تجربة صغيرة آمنة.","اجمع البيانات قبل وبعد.","قارن النتيجة بالتوقع.","ثبت التعلم أو عدّل النظرية وكرر."],"en":["Define the problem, objective, and prediction.","Run a small safe test.","Collect before-and-after data.","Compare results with the prediction.","Standardize learning or revise the theory and repeat."]},"example":{"ar":"تجربة ترتيب جديد لمحطة عمل في وردية واحدة مع قياس الحركة والعيوب PDSA؛ تطبيقه على كل المصنع فورًا دون اختبار ليس تعلمًا منضبطًا.","en":"Testing a new workstation layout for one shift while measuring motion and defects is PDSA; implementing it plant-wide without a test is not disciplined learning."},"tip":{"ar":"Do ليست مرحلة تنفيذ نهائي؛ هي غالبًا تجربة محدودة لجمع المعرفة.","en":"Do is not necessarily full implementation; it is often a limited test to gain knowledge."},"formula":"","question":{"q":{"ar":"في PDSA، أين تقارن النتيجة بالتوقع وتتعلم؟","en":"In PDSA, where are results compared with predictions and learning occurs?"},"options":{"ar":["Plan","Do","Study","Act only"],"en":["Plan","Do","Study","Act only"]},"answer":2,"rationale":{"ar":"Study يحلل البيانات مقابل النظرية والتوقع.","en":"Study analyzes data against the theory and prediction."}}},{"domain":5,"code":"5.5","title":{"ar":"Six Sigma ومنهج DMAIC","en":"Six Sigma and DMAIC"},"level":"Analyze","ref":"5th ed., Ch. 5; 4th ed., pp. 259–271","concept":{"ar":"DMAIC مناسب لتحسين عملية موجودة: Define يحدد العميل والنطاق والمشكلة، Measure يثبت القياس وخط الأساس، Analyze يختبر الأسباب، Improve يطور ويختبر الحل، وControl يثبت المكاسب. المنهج لا يعني استخدام كل أداة إحصائية في كل مشروع.","en":"DMAIC is used to improve an existing process: Define sets customer, scope, and problem; Measure validates measurement and baseline; Analyze tests causes; Improve develops and tests solutions; Control sustains gains. The method does not require every statistical tool in every project."},"steps":{"ar":["اكتب Charter وVOC وCTQ.","تحقق من MSA وحدد Baseline.","اختبر الأسباب بالبيانات.","جرّب الحلول وقيّم المخاطر.","أنشئ Control Plan ومسؤولية الاستدامة."],"en":["Create the charter, VOC, and CTQs.","Validate MSA and establish baseline.","Test causes with data.","Pilot solutions and assess risk.","Create a control plan and sustainment ownership."]},"example":{"ar":"إذا بدأ الفريق بحل قبل تعريف المشكلة والتحقق من القياس، قد يحسن العرض لا السبب. DMAIC يمنع القفز من الانطباع إلى الحل.","en":"If a team starts with a solution before defining the problem and validating measurement, it may improve the symptom rather than the cause. DMAIC prevents jumping from impression to solution."},"tip":{"ar":"لا تستخدم DMAIC لتصميم منتج جديد بلا عملية قائمة؛ DFSS قد يكون أنسب.","en":"Do not use DMAIC to design a new product with no existing process; DFSS may be more appropriate."},"formula":"","question":{"q":{"ar":"في أي مرحلة يجب التحقق من صلاحية نظام القياس؟","en":"In which DMAIC phase should measurement-system suitability be verified?"},"options":{"ar":["Define","Measure","Improve","Control only"],"en":["Define","Measure","Improve","Control only"]},"answer":1,"rationale":{"ar":"Measure يضمن أن خط الأساس والتحليل مبنيان على بيانات موثوقة.","en":"Measure ensures the baseline and analysis use trustworthy data."}}},{"domain":5,"code":"5.6","title":{"ar":"Lean: 5S والهدر الثمانية وValue Stream Mapping","en":"Lean: 5S, Eight Wastes, and Value Stream Mapping"},"level":"Evaluate","ref":"5th ed., Ch. 5; 4th ed., pp. 271–284","concept":{"ar":"Lean يرفع القيمة عبر إزالة الهدر وتحسين التدفق. الهدر الثمانية: Transportation, Inventory, Motion, Waiting, Overproduction, Overprocessing, Defects, Unused Talent. 5S ينظم بيئة العمل، وVSM يرسم تدفق المادة والمعلومة وحالة Current/Future State.","en":"Lean increases value by removing waste and improving flow. The eight wastes are transportation, inventory, motion, waiting, overproduction, overprocessing, defects, and unused talent. 5S organizes the workplace, and VSM maps material and information flow in current and future states."},"steps":{"ar":["حدد القيمة من منظور العميل.","ارسم التدفق الحالي والزمن والمخزون.","حدد الهدر وأسبابه.","صمم Future State مرتبطة بالطلب.","نفذ Kaizen Plan وقس Lead Time وQuality."],"en":["Define value from the customer perspective.","Map current flow, time, and inventory.","Identify waste and causes.","Design a demand-linked future state.","Execute a kaizen plan and measure lead time and quality."]},"example":{"ar":"خفض مسافة مشي المشغل قد يقلل Motion، لكن إذا استمرت دفعات كبيرة وانتظار طويل فلن يتحسن Lead Time الكلي كثيرًا؛ VSM ينظر للنظام.","en":"Reducing operator walking may reduce motion, but large batches and long queues may still dominate total lead time; VSM looks at the system."},"tip":{"ar":"5S ليست حملة تنظيف؛ Sustain يحتاج معايير وملكية وتدقيقًا وسلوكًا.","en":"5S is not a cleaning campaign; sustainment requires standards, ownership, audits, and behavior."},"formula":"","question":{"q":{"ar":"أي هدر يعني إنتاج أكثر أو أبكر من طلب العميل؟","en":"Which waste means producing more or earlier than customer demand?"},"options":{"ar":["Motion","Overproduction","Defects","Transportation"],"en":["Motion","Overproduction","Defects","Transportation"]},"answer":1,"rationale":{"ar":"Overproduction غالبًا يولد مخزونًا وانتظارًا وهدرًا إضافيًا.","en":"Overproduction often creates inventory, waiting, and additional waste."}}},{"domain":5,"code":"5.7","title":{"ar":"Kanban وTakt Time والعمل المعياري وSMED","en":"Kanban, Takt Time, Standard Work, and SMED"},"level":"Evaluate","ref":"5th ed., Ch. 5; 4th ed., pp. 276–284","concept":{"ar":"Kanban إشارة سحب تحد WIP وتربط الإنتاج بالاستهلاك. Takt Time هو الوقت المتاح مقسومًا على طلب العميل. Standard Work يحدد التسلسل والزمن وWIP القياسي. SMED يقلل زمن التغيير بفصل الإعداد الداخلي والخارجي وتحويل ما يمكن إلى خارجي وتبسيط الباقي.","en":"Kanban is a pull signal that limits WIP and links production to consumption. Takt time equals available time divided by customer demand. Standard work defines sequence, time, and standard WIP. SMED reduces changeover by separating internal and external setup, converting what can be external, and simplifying the rest."},"steps":{"ar":["احسب الطلب والوقت الصافي.","قارن Cycle Time مع Takt.","وازن العمل وحدد WIP.","افصل إعداد SMED داخلي/خارجي.","راقب الالتزام والعمل غير القياسي."],"en":["Calculate demand and net available time.","Compare cycle time with takt.","Balance work and define WIP.","Separate SMED internal and external setup.","Monitor adherence and abnormal work."]},"example":{"ar":"إذا كان الوقت المتاح 420 دقيقة والطلب 210 وحدات، Takt=2 دقيقة/وحدة. عملية Cycle Time=2.5 دقيقة لن تلبي الطلب دون تحسين أو سعة.","en":"If available time is 420 minutes and demand is 210 units, takt is 2 minutes/unit. A process cycle time of 2.5 minutes cannot meet demand without improvement or capacity."},"tip":{"ar":"Takt ليس سرعة آلة تلقائية؛ هو إيقاع طلب العميل ويجب استخدام وقت العمل الصافي.","en":"Takt is not an automatic machine speed; it is customer-demand rhythm and uses net available time."},"formula":"Takt Time = Available Production Time / Customer Demand","question":{"q":{"ar":"ما Takt Time عند 480 دقيقة متاحة وطلب 240 وحدة؟","en":"What is takt time with 480 available minutes and demand of 240 units?"},"options":{"ar":["0.5 دقيقة","2 دقيقة","4 دقائق","240 دقيقة"],"en":["0.5 minute","2 minutes","4 minutes","240 minutes"]},"answer":1,"rationale":{"ar":"480/240=2 دقيقة لكل وحدة.","en":"480/240=2 minutes per unit."}}},{"domain":5,"code":"5.8","title":{"ar":"OEE وTPM والتدفق","en":"OEE, TPM, and Flow"},"level":"Evaluate","ref":"5th ed., Ch. 5 new OEE content; 4th ed., Lean sections","concept":{"ar":"OEE=Availability×Performance×Quality ويكشف خسائر التوقف والسرعة والعيوب. TPM يهدف إلى ملكية مشتركة للمعدات وصيانة ذاتية ومخططة وتحسين مركز. يجب تحليل مكونات OEE لا الرقم الإجمالي وحده.","en":"OEE equals Availability × Performance × Quality and exposes downtime, speed, and quality losses. TPM promotes shared equipment ownership, autonomous and planned maintenance, and focused improvement. OEE components should be analyzed, not only the overall number."},"steps":{"ar":["عرّف Planned Production Time.","احسب Availability من Run Time.","احسب Performance من Ideal Cycle.","احسب Quality من Good Count.","صنف الخسائر وركز على الأكبر."],"en":["Define planned production time.","Calculate availability from run time.","Calculate performance from ideal cycle.","Calculate quality from good count.","Classify losses and focus on the largest."]},"example":{"ar":"Availability=0.90 وPerformance=0.95 وQuality=0.98 تعطي OEE≈83.8%. تحسين الجودة إلى 99% وحده لن يعالج توقفات كبيرة.","en":"Availability=0.90, Performance=0.95, and Quality=0.98 give OEE≈83.8%. Raising quality to 99% alone will not fix major downtime."},"tip":{"ar":"OEE منخفض لا يحدد السبب تلقائيًا؛ حلل A وP وQ وسجلات الخسارة.","en":"Low OEE does not automatically identify the cause; analyze A, P, Q, and loss records."},"formula":"OEE = Availability × Performance × Quality","question":{"q":{"ar":"إذا A=90% وP=80% وQ=95%، فما OEE تقريبًا؟","en":"If A=90%, P=80%, and Q=95%, what is approximate OEE?"},"options":{"ar":["68.4%","88.3%","95%","265%"],"en":["68.4%","88.3%","95%","265%"]},"answer":0,"rationale":{"ar":"0.90×0.80×0.95=0.684.","en":"0.90×0.80×0.95=0.684."}}},{"domain":5,"code":"5.9","title":{"ar":"التعريف بالمشكلة وRCA و5 Whys","en":"Problem Definition, Root Cause Analysis, and 5 Whys"},"level":"Evaluate","ref":"5th ed., Ch. 5 new 5 Whys content; 4th ed., pp. 286–294","concept":{"ar":"المشكلة الجيدة تصف What, Where, When, Extent، مع الفرق عن المعيار. RCA يميز سبب الحدوث عن سبب الهروب Escape Cause. 5 Whys مسار استجواب يحتاج دليلًا في كل خطوة، ولا يتوقف تلقائيًا عند خمسة.","en":"A strong problem statement describes what, where, when, and extent relative to a standard. RCA distinguishes occurrence cause from escape cause. The 5 Whys is an evidence-based questioning path and does not automatically stop at exactly five."},"steps":{"ar":["احتوِ الحالة واحفظ الأدلة.","اكتب Problem Statement بلا سبب مفترض.","قارن Is/Is Not.","ابن واختبر سلاسل الأسباب.","حدد Occurrence وEscape وSystemic Causes."],"en":["Contain the condition and preserve evidence.","Write a problem statement without assumed cause.","Perform Is/Is Not comparison.","Build and test causal chains.","Identify occurrence, escape, and systemic causes."]},"example":{"ar":"«المشغل لم يتبع التعليمات» ليس سببًا جذريًا كافيًا. لماذا؟ قد تكون التعليمات غير متاحة، أو واجهة الجهاز تسمح بخطأ، أو التدريب غير فعال، أو الحافز يشجع السرعة.","en":"'The operator did not follow instructions' is not a sufficient root cause. Why? Instructions may be unavailable, the interface may permit error, training may be ineffective, or incentives may reward speed."},"tip":{"ar":"لا تجعل 5 Whys جلسة تخمين؛ كل انتقال يحتاج دليلًا واختبارًا.","en":"Do not turn 5 Whys into speculation; each causal link needs evidence and testing."},"formula":"","question":{"q":{"ar":"ما الفرق بين Occurrence Cause وEscape Cause؟","en":"What is the difference between occurrence cause and escape cause?"},"options":{"ar":["لا فرق","الأول يفسر نشوء العيب والثاني يفسر عدم اكتشافه أو منعه","الأول تكلفة والثاني زمن","الأول للمورد فقط"],"en":["There is no difference","The first explains why the defect was created; the second why it was not detected or prevented","The first is cost and the second is time","The first applies only to suppliers"]},"answer":1,"rationale":{"ar":"معالجة الحدوث وحدها لا تصلح نظام الكشف، والعكس صحيح.","en":"Fixing occurrence alone does not correct the escape system, and vice versa."}}},{"domain":5,"code":"5.10","title":{"ar":"الإجراء التصحيحي ومنع التكرار والتحقق من الفعالية","en":"Corrective Action, Recurrence Control, and Effectiveness"},"level":"Evaluate","ref":"5th ed., Ch. 5; 4th ed., pp. 286–294","concept":{"ar":"Correction يصلح الحالة الحالية، وCorrective Action يزيل سبب عدم المطابقة لمنع التكرار. الإجراء الفعال يطابق السبب، يعالج النطاق النظامي، يحدد المخاطر الجانبية، ويثبت بالبيانات أن التكرار انخفض خلال فترة كافية.","en":"Correction fixes the current condition; corrective action removes the cause of nonconformity to prevent recurrence. An effective action matches the cause, addresses systemic scope, considers side effects, and uses data over a sufficient period to demonstrate reduced recurrence."},"steps":{"ar":["ثبت السبب الجذري.","اختر إجراءً يمنع السبب لا العرض.","قيّم المخاطر والتغييرات.","نفذ وحدث الوثائق والتدريب.","تحقق من الفعالية بمعيار وزمن محددين."],"en":["Confirm root cause.","Select an action that prevents the cause, not merely the symptom.","Assess risks and changes.","Implement and update documents and training.","Verify effectiveness using defined criteria and time."]},"example":{"ar":"إصلاح المنتج Correction. تعديل Fixture لمنع الخطأ وتحديث Control Plan ثم إثبات عدم التكرار في 20 دفعة Corrective Action مع تحقق فعالية.","en":"Repairing the product is correction. Redesigning the fixture, updating the control plan, and demonstrating no recurrence across 20 lots is corrective action with effectiveness verification."},"tip":{"ar":"إغلاق CAR عند تنفيذ الإجراء فقط خطأ؛ التنفيذ لا يثبت الفعالية.","en":"Closing a CAR when action is merely implemented is incorrect; implementation does not prove effectiveness."},"formula":"","question":{"q":{"ar":"أي دليل أقوى على فعالية Corrective Action؟","en":"Which evidence most strongly demonstrates corrective-action effectiveness?"},"options":{"ar":["توقيع إكمال المهمة","شراء جهاز جديد","عدم تكرار المشكلة خلال فترة وحجم إنتاج محددين مع استقرار المؤشر","إرسال بريد"],"en":["Task-completion signature","Purchase of new equipment","No recurrence over a defined time and production volume with stable performance","Sending an email"]},"answer":2,"rationale":{"ar":"الفعالية تتطلب نتيجة مستدامة وفق معيار محدد.","en":"Effectiveness requires a sustained result against defined criteria."}}},{"domain":5,"code":"5.11","title":{"ar":"الإجراء الوقائي وPoka-Yoke والتصميم المتين","en":"Preventive Action, Poka-Yoke, and Robust Design"},"level":"Evaluate","ref":"5th ed., Ch. 5; 4th ed., pp. 294–296","concept":{"ar":"الوقاية تعالج خطرًا قبل عدم المطابقة. Poka-Yoke يمنع الخطأ أو يكشفه فورًا عند المصدر؛ الوقاية الهندسية أقوى من التحذير والتدريب وحدهما. Robust Design يجعل الأداء أقل حساسية للتباين وعوامل الضوضاء.","en":"Prevention addresses risk before nonconformity occurs. Poka-yoke prevents an error or detects it immediately at the source; engineered prevention is generally stronger than warnings and training alone. Robust design makes performance less sensitive to variation and noise factors."},"steps":{"ar":["حدد الخطأ الممكن وعاقبته.","صمم إزالة أو منعًا ماديًا.","إذا تعذر، اجعل الكشف فوريًا قبل القيمة المضافة التالية.","اختبر سيناريوهات الاستخدام وسوء الاستخدام.","راقب فعالية الضبط ولا تعتمد على الانطباع."],"en":["Identify the possible error and consequence.","Design physical elimination or prevention.","If prevention is not possible, detect immediately before the next value-added step.","Test use and foreseeable misuse scenarios.","Monitor control effectiveness rather than relying on belief."]},"example":{"ar":"Connector لا يمكن تركيبه إلا باتجاه واحد Poka-Yoke وقائي. كاميرا تكتشف التركيب بالعكس Detection Poka-Yoke. ملصق تحذير أضعف من الاثنين.","en":"A connector that fits only one way is preventive poka-yoke. A camera detecting reverse assembly is detection poka-yoke. A warning label is weaker than both."},"tip":{"ar":"أفضل Control غالبًا يغير التصميم أو العملية بحيث يصبح الخطأ مستحيلًا، لا يطلب انتباهًا أكبر.","en":"The strongest control generally changes design or process so the error is impossible rather than demanding more attention."},"formula":"","question":{"q":{"ar":"ما أقوى إجراء لمنع تركيب جزء بالعكس؟","en":"What is the strongest action to prevent reverse assembly?"},"options":{"ar":["إعادة التدريب فقط","زيادة التفتيش النهائي","تصميم Connector أو Fixture لا يسمح إلا بالاتجاه الصحيح","إرسال تذكير"],"en":["Retraining only","More final inspection","Design a connector or fixture that permits only the correct orientation","Send a reminder"]},"answer":2,"rationale":{"ar":"المنع الهندسي يزيل فرصة الخطأ عند المصدر.","en":"Engineered prevention removes the opportunity for error at the source."}}}]});


window.CQE_DOMAINS=window.CQE_DOMAINS||[];
window.CQE_DOMAINS.push({"id":6,"title":{"ar":"الطرق الكمية والأدوات","en":"Quantitative Methods and Tools"},"weight":34,"desc":{"ar":"الإحصاء والاحتمالات والفرضيات وSPC والقدرة وDOE.","en":"Statistics, probability, hypothesis tests, SPC, capability, and DOE."},"lessons":[{"domain":6,"code":"6.1","title":{"ar":"أنواع البيانات ومقاييس القياس وطرق الجمع","en":"Data Types, Measurement Scales, and Collection Methods"},"level":"Apply","ref":"5th ed., Ch. 6 new automation content; 4th ed., pp. 299–303","concept":{"ar":"البيانات المتغيرة Continuous تقيس مقدارًا مثل الطول، بينما بيانات الصفات Discrete تعد وحدات أو عيوبًا. المقاييس Nominal أسماء، Ordinal ترتيب، Interval فواصل متساوية بلا صفر حقيقي، وRatio فواصل متساوية وصفر حقيقي. طريقة الجمع قد تكون Check Sheet أو ترميزًا أو Automatic Gaging أو تكامل قواعد بيانات.","en":"Continuous data measure magnitude such as length, while discrete/attribute data count units or defects. Nominal scales name categories, ordinal scales rank, interval scales have equal spacing without a true zero, and ratio scales have equal spacing and a true zero. Collection may use check sheets, coding, automatic gaging, or database integration."},"steps":{"ar":["حدد السؤال والقرار قبل البيانات.","اختر نوع البيانات والمقياس الصحيح.","عرّف Operational Definition.","اختر طريقة جمع تقلل الخطأ والتحيز.","اختبر النظام بحجم صغير قبل التعميم."],"en":["Define the question and decision before collecting data.","Choose the correct data type and scale.","Create an operational definition.","Select a collection method that minimizes error and bias.","Pilot the system before full deployment."]},"example":{"ar":"درجة الحرارة Celsius مقياس Interval لأن الصفر ليس انعدام الحرارة، بينما الكتلة Ratio لأن الصفر يعني غياب الكتلة.","en":"Temperature in Celsius is an interval scale because zero is not absence of temperature; mass is a ratio scale because zero represents absence of mass."},"tip":{"ar":"تحويل قياس مستمر إلى Pass/Fail يفقد معلومات وقد يخفض قوة التحليل.","en":"Converting continuous measurements into pass/fail loses information and may reduce analytical power."},"formula":"","question":{"q":{"ar":"أي مقياس يحتوي صفرًا حقيقيًا ويسمح بتفسير النسب؟","en":"Which scale has a true zero and supports meaningful ratios?"},"options":{"ar":["Nominal","Ordinal","Interval","Ratio"],"en":["Nominal","Ordinal","Interval","Ratio"]},"answer":3,"rationale":{"ar":"Ratio Scale يمتلك صفرًا حقيقيًا وفواصل متساوية.","en":"A ratio scale has equal intervals and a true zero."}}},{"domain":6,"code":"6.2","title":{"ar":"دقة البيانات وسلامتها ولوحات المؤشرات","en":"Data Accuracy, Integrity, and Visualization"},"level":"Apply","ref":"5th ed., Ch. 6 new dashboards/data integration; 4th ed., pp. 300–311","concept":{"ar":"Data Integrity تعني أن البيانات كاملة ومتسقة وقابلة للتتبع ومحمية من التغيير غير المصرح. تشمل الأخطار تكرار السجلات، اختلاف التعريفات، القيم المفقودة، Timestamp خاطئ، دمج قواعد مختلفة، والتحيز في العرض. Dashboard الجيد يعرض مقياسًا مرتبطًا بقرار مع هدف واتجاه وسياق.","en":"Data integrity means data are complete, consistent, traceable, and protected from unauthorized change. Risks include duplicate records, inconsistent definitions, missing values, wrong timestamps, database-merge errors, and presentation bias. A good dashboard displays decision-relevant metrics with target, trend, and context."},"steps":{"ar":["حدد Source of Truth وData Owner.","استخدم Validation Rules وAudit Trail.","وحّد التعريف والوحدة والمنطقة الزمنية.","راجع Missing/Duplicate/Outlier Data.","صمم العرض لتجنب المحاور المضللة والاختيار الانتقائي."],"en":["Define the source of truth and data owner.","Use validation rules and an audit trail.","Standardize definitions, units, and time zones.","Review missing, duplicate, and outlier data.","Design visualization to avoid misleading axes and selective reporting."]},"example":{"ar":"دمج بيانات عيوب من مصنعين دون توحيد تعريف «العيب» يجعل المقارنة خاطئة حتى لو كانت الرسوم دقيقة.","en":"Combining defect data from two plants without standardizing the definition of 'defect' creates an invalid comparison even if charts are mathematically correct."},"tip":{"ar":"جودة الرسم لا تعوض ضعف البيانات؛ ابدأ بصحة المصدر والتعريف.","en":"A polished chart cannot compensate for poor data; start with source and definition integrity."},"formula":"","question":{"q":{"ar":"ما الإجراء الأقوى لمنع اختلاف حساب KPI بين الإدارات؟","en":"What is the strongest action to prevent departments from calculating a KPI differently?"},"options":{"ar":["تغيير لون الرسم","توحيد Data Dictionary ومعادلة المصدر","زيادة الشرائح","عرض المتوسط فقط"],"en":["Change chart color","Standardize the data dictionary and source formula","Add more slides","Display only the average"]},"answer":1,"rationale":{"ar":"التعريف والمعادلة الموحدان يمنعان اختلاف الحساب.","en":"A standard definition and formula prevent inconsistent calculation."}}},{"domain":6,"code":"6.3","title":{"ar":"الإحصاء الوصفي وتوزيعات التكرار","en":"Descriptive Statistics and Frequency Distributions"},"level":"Evaluate","ref":"5th ed., Ch. 6; 4th ed., pp. 303–311","concept":{"ar":"المتوسط حساس للقيم الشاذة، والوسيط أكثر مقاومة، والمنوال الأكثر تكرارًا. التباين والانحراف المعياري يقيسان التشتت، والمدى بسيط لكنه يعتمد على قيمتين. يجب تفسير الإحصاءات مع شكل التوزيع وحجم العينة والسياق.","en":"The mean is sensitive to outliers, the median is more resistant, and the mode is most frequent. Variance and standard deviation measure dispersion; range is simple but depends on only two observations. Statistics should be interpreted with distribution shape, sample size, and context."},"steps":{"ar":["افحص البيانات الخام والرسوم.","اختر مقياس مركز مناسبًا.","احسب التشتت.","قارن مجموعات باستخدام وحدة وسياق متسق.","لا تلخص توزيعًا متعدد القمم بمتوسط واحد فقط."],"en":["Inspect raw data and graphs.","Choose an appropriate center measure.","Calculate dispersion.","Compare groups using consistent units and context.","Do not summarize a multimodal distribution with a single mean alone."]},"example":{"ar":"بيانات زمن الإصلاح 10،11،12،13،90 دقيقة: المتوسط 27.2 لكنه لا يمثل معظم الحالات؛ الوسيط 12 أدق لوصف الحالة النموذجية.","en":"Repair times of 10, 11, 12, 13, and 90 minutes have a mean of 27.2, which does not represent most cases; the median of 12 better describes a typical case."},"tip":{"ar":"الانحراف المعياري له وحدة البيانات، بينما التباين بوحدة مربعة.","en":"Standard deviation uses the original data unit; variance uses squared units."},"formula":"s² = Σ(x - x̄)² / (n - 1); s = √s²","question":{"q":{"ar":"أي مقياس مركز أكثر مقاومة لقيمة شاذة كبيرة؟","en":"Which measure of center is more resistant to a large outlier?"},"options":{"ar":["Mean","Median","Variance","Range"],"en":["Mean","Median","Variance","Range"]},"answer":1,"rationale":{"ar":"الوسيط يعتمد على الترتيب لا مقدار القيمة الشاذة.","en":"The median depends on order, not the magnitude of the outlier."}}},{"domain":6,"code":"6.4","title":{"ar":"مفاهيم الاحتمال والقواعد الأساسية","en":"Probability Concepts and Rules"},"level":"Apply","ref":"5th ed., Ch. 6; 4th ed., pp. 311–321","concept":{"ar":"الاحتمال بين 0 و1. الأحداث Mutually Exclusive لا تقع معًا، بينما Independent لا يغير وقوع أحدها احتمال الآخر. قاعدة المكمل P(Aᶜ)=1−P(A)، وقاعدة الجمع تخص الاتحاد، والضرب للتقاطع مع الانتباه للاستقلال والاحتمال الشرطي.","en":"Probability ranges from 0 to 1. Mutually exclusive events cannot occur together, while independent events do not change each other's probabilities. The complement rule is P(Aᶜ)=1−P(A); addition addresses unions, and multiplication addresses intersections with attention to independence and conditional probability."},"steps":{"ar":["عرّف فضاء العينة والأحداث.","حدد Exclusive أو Independent.","استخدم الرسم أو الشجرة للمسائل المركبة.","طبق الاحتمال الشرطي عند وجود معلومات.","تحقق أن الناتج بين 0 و1."],"en":["Define the sample space and events.","Determine exclusivity or independence.","Use diagrams or trees for compound problems.","Apply conditional probability when information is given.","Check that the result is between 0 and 1."]},"example":{"ar":"إذا احتمال فشل A=0.1 وB=0.2 ومستقلان، احتمال فشلهما معًا=0.02. أما احتمال فشل واحد على الأقل=1−(0.9×0.8)=0.28.","en":"If failure probabilities are P(A)=0.1 and P(B)=0.2 and independent, both fail with probability 0.02. At least one fails with probability 1−(0.9×0.8)=0.28."},"tip":{"ar":"Mutually Exclusive ليست مرادفة لـIndependent؛ إذا كان حدثان غير مستحيلين ومتعارضين فهما غير مستقلين.","en":"Mutually exclusive is not the same as independent; two nonzero mutually exclusive events are not independent."},"formula":"P(A∩B)=P(A)P(B) for independent events","question":{"q":{"ar":"إذا كان حدثان مستقلين، كيف يحسب احتمال وقوعهما معًا؟","en":"For two independent events, how is the probability of both occurring calculated?"},"options":{"ar":["P(A)+P(B)","P(A)×P(B)","1−P(A)","P(A)−P(B)"],"en":["P(A)+P(B)","P(A)×P(B)","1−P(A)","P(A)−P(B)"]},"answer":1,"rationale":{"ar":"للاستقلال، احتمال التقاطع يساوي حاصل ضرب الاحتمالين.","en":"For independent events, intersection probability equals the product."}}},{"domain":6,"code":"6.5","title":{"ar":"التوزيعات المستمرة","en":"Continuous Probability Distributions"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 321–333","concept":{"ar":"التوزيع الطبيعي متناظر ويستخدم كثيرًا للقياسات الناتجة عن عوامل صغيرة متعددة. Uniform يعطي كثافة متساوية ضمن نطاق، Exponential يصف الزمن بين أحداث بمعدل ثابت، Lognormal للمتغيرات الموجبة المضروبة، Weibull مرن للاعتمادية، وt وF للاستدلال مع تقدير التباين.","en":"The normal distribution is symmetric and often models measurements influenced by many small effects. Uniform has constant density over a range, exponential models time between constant-rate events, lognormal fits positive multiplicative variables, Weibull is flexible for reliability, and t and F support inference involving estimated variance."},"steps":{"ar":["حدد طبيعة المتغير وحدوده.","ارسم Histogram وProbability Plot.","اختبر الافتراضات ومصدر البيانات.","استخدم المعلمات الصحيحة.","لا تفرض Normal لمجرد سهولة الحساب."],"en":["Identify variable nature and bounds.","Plot a histogram and probability plot.","Assess assumptions and data source.","Use the appropriate parameters.","Do not force normality merely for convenient calculation."]},"example":{"ar":"زمن الإصلاح الموجب والمنحرف يمينًا قد يناسب Lognormal أكثر من Normal. زمن بين أعطال بمعدل ثابت قد يناسب Exponential.","en":"Positive right-skewed repair time may fit a lognormal distribution better than normal. Time between events at a constant rate may fit exponential."},"tip":{"ar":"اختيار التوزيع قرار تحليلي يؤثر في Capability وReliability وفترات الثقة.","en":"Distribution choice is an analytical decision affecting capability, reliability, and confidence intervals."},"formula":"","question":{"q":{"ar":"أي توزيع يرتبط غالبًا بزمن بين أحداث Poisson عند معدل ثابت؟","en":"Which distribution commonly models time between Poisson events at a constant rate?"},"options":{"ar":["Normal","Exponential","Binomial","Hypergeometric"],"en":["Normal","Exponential","Binomial","Hypergeometric"]},"answer":1,"rationale":{"ar":"التوزيع الأسي يصف زمن الانتظار بين أحداث بمعدل ثابت.","en":"The exponential distribution models waiting time between constant-rate events."}}},{"domain":6,"code":"6.6","title":{"ar":"التوزيعات المتقطعة","en":"Discrete Probability Distributions"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 333–339","concept":{"ar":"Binomial يعد النجاحات في n محاولات مستقلة باحتمال ثابت، Poisson يعد أحداثًا في زمن أو مساحة بمعدل ثابت، Hypergeometric للسحب دون إرجاع من مجتمع محدود، وMultinomial يوسع Binomial لأكثر من فئتين.","en":"Binomial counts successes in n independent trials with constant probability, Poisson counts events over time or space at a constant rate, hypergeometric applies to sampling without replacement from a finite population, and multinomial extends binomial to more than two categories."},"steps":{"ar":["حدد ما إذا كان العدد ثابتًا أو الزمن/المساحة.","تحقق من الاستقلال وثبات p أو λ.","حدد السحب مع أو دون إرجاع.","اختر التوزيع والمعلمات.","قارن الاحتمال بسياق القرار."],"en":["Determine whether trials are fixed or events occur over time/space.","Check independence and constant p or λ.","Determine sampling with or without replacement.","Select distribution and parameters.","Interpret probability in decision context."]},"example":{"ar":"عدد الوحدات المعيبة في عينة 20 مع p ثابت Binomial. عدد المكالمات في ساعة Poisson. اختيار 5 قطع معيبة من دفعة محدودة دون إرجاع Hypergeometric.","en":"Number of defective units in a sample of 20 with constant p is binomial. Calls per hour are Poisson. Selecting defects from a finite lot without replacement is hypergeometric."},"tip":{"ar":"Poisson قد يقرب Binomial عندما n كبير وp صغير، لكن افهم شروط التقريب.","en":"Poisson may approximate binomial when n is large and p is small, but understand the conditions."},"formula":"","question":{"q":{"ar":"أي توزيع يناسب السحب دون إرجاع من دفعة محدودة؟","en":"Which distribution fits sampling without replacement from a finite lot?"},"options":{"ar":["Hypergeometric","Exponential","Normal only","F"],"en":["Hypergeometric","Exponential","Normal only","F"]},"answer":0,"rationale":{"ar":"Hypergeometric يأخذ اعتماد السحوبات الناتج عن عدم الإرجاع.","en":"The hypergeometric distribution accounts for dependent draws without replacement."}}},{"domain":6,"code":"6.7","title":{"ar":"نظرية الحد المركزي وتوزيعات المعاينة وProbability Plots","en":"Central Limit Theorem, Sampling Distributions, and Probability Plots"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 339–347","concept":{"ar":"تنص CLT على أن توزيع متوسطات العينات يقترب من الطبيعي مع زيادة n تحت شروط مناسبة، حتى لو لم يكن المجتمع طبيعيًا. Standard Error يقيس تشتت الإحصاء بين العينات ويقل مع جذر n. Probability Plot يقارن البيانات بتوزيع مفترض؛ الخطية التقريبية تدعم الملاءمة مع مراعاة حجم العينة.","en":"The CLT states that the sampling distribution of the mean approaches normality as n increases under appropriate conditions, even when the population is not normal. Standard error measures sampling-to-sampling variation and decreases with the square root of n. A probability plot compares data with an assumed distribution; approximate linearity supports fit while sample size must be considered."},"steps":{"ar":["ميز توزيع البيانات عن توزيع متوسطات العينات.","احسب Standard Error.","تحقق من الاستقلال وطريقة المعاينة.","استخدم Probability Plot مع اختبار وKnowledge Process.","لا تفسر نقاط الأطراف وحدها دون حجم عينة."],"en":["Distinguish the data distribution from the sampling distribution of the mean.","Calculate standard error.","Check independence and sampling method.","Use a probability plot with tests and process knowledge.","Do not overinterpret tail points without considering sample size."]},"example":{"ar":"إذا تضاعف حجم العينة أربع مرات، ينخفض SE إلى النصف لأن SE=σ/√n.","en":"If sample size is multiplied by four, standard error is halved because SE=σ/√n."},"tip":{"ar":"CLT لا يجعل البيانات الأصلية طبيعية؛ يجعل توزيع الإحصاء أقرب للطبيعي.","en":"The CLT does not make the original data normal; it makes the sampling distribution of the statistic more nearly normal."},"formula":"SE = σ / √n","question":{"q":{"ar":"إذا زاد n من 25 إلى 100، كيف يتغير Standard Error تقريبًا؟","en":"If n increases from 25 to 100, how does standard error change approximately?"},"options":{"ar":["يتضاعف","ينخفض إلى النصف","يبقى نفسه","ينخفض إلى الربع"],"en":["It doubles","It is halved","It stays the same","It drops to one quarter"]},"answer":1,"rationale":{"ar":"SE يتناسب عكسيًا مع √n؛ √25/√100=1/2.","en":"SE is inversely proportional to √n; √25/√100=1/2."}}},{"domain":6,"code":"6.8","title":{"ar":"المقدرات وفترات الثقة والتسامح","en":"Estimators, Confidence Intervals, and Tolerance Intervals"},"level":"Evaluate","ref":"5th ed., Ch. 6; 4th ed., pp. 347–359","concept":{"ar":"Point Estimate قيمة واحدة لمعلم، ويقيم Bias وEfficiency وConsistency جودة المقدّر. Confidence Interval يحتوي المعلم الحقيقي بنسبة نجاح طويلة المدى للمبدأ، ولا يعني احتمالًا مباشرًا للمعلم بعد حساب الفترة في التفسير التقليدي. Tolerance Interval يهدف لتغطية نسبة محددة من المجتمع بثقة محددة.","en":"A point estimate is a single value for a parameter, and bias, efficiency, and consistency describe estimator quality. A confidence interval is produced by a method that covers the true parameter at a stated long-run rate; in classical interpretation it is not a direct posterior probability after calculation. A tolerance interval aims to cover a stated proportion of the population with stated confidence."},"steps":{"ar":["حدد المعلم المطلوب.","اختر Z أو t أو Chi-square حسب الحالة.","تحقق من الافتراضات.","احسب Point Estimate وSE وCritical Value.","فسر الفترة ضمن سياق القرار لا كضمان."],"en":["Identify the parameter.","Select Z, t, or chi-square as appropriate.","Check assumptions.","Calculate the estimate, SE, and critical value.","Interpret the interval in decision context, not as a guarantee."]},"example":{"ar":"CI لمتوسط عمر البطارية يقدر μ، بينما Tolerance Interval قد يقول إن 99% من البطاريات تقع داخل نطاق معين بثقة 95%.","en":"A CI for battery life estimates μ, while a tolerance interval may state that 99% of batteries fall within a range with 95% confidence."},"tip":{"ar":"لا تخلط Confidence Interval للمتوسط مع Prediction Interval لقيمة فردية أو Tolerance Interval للسكان.","en":"Do not confuse a confidence interval for a mean with a prediction interval for an individual or a tolerance interval for the population."},"formula":"","question":{"q":{"ar":"أي فترة تهدف إلى احتواء نسبة محددة من المجتمع؟","en":"Which interval aims to contain a specified proportion of the population?"},"options":{"ar":["Confidence interval only","Tolerance interval","Control limit","Specification limit"],"en":["Confidence interval only","Tolerance interval","Control limit","Specification limit"]},"answer":1,"rationale":{"ar":"Tolerance Interval يربط نسبة تغطية من المجتمع بمستوى ثقة.","en":"A tolerance interval links population coverage with a confidence level."}}},{"domain":6,"code":"6.9","title":{"ar":"اختبار الفرضيات وأخطاء النوع الأول والثاني والقوة","en":"Hypothesis Testing, Type I/II Errors, and Power"},"level":"Evaluate","ref":"5th ed., Ch. 6; 4th ed., pp. 359–383","concept":{"ar":"اختبار الفرضية يبدأ بـH0 وH1 ومستوى α قبل رؤية النتيجة. Type I هو رفض H0 وهي صحيحة، وType II عدم رفضها وهي خاطئة، وPower=1−β. p-value احتمال نتيجة مساوية أو أشد تطرفًا بافتراض صحة H0، وليس احتمال صحة H0. يجب فصل الدلالة الإحصائية عن الأهمية العملية.","en":"Hypothesis testing begins with H0, H1, and α before observing results. Type I error rejects a true H0; Type II error fails to reject a false H0; power equals 1−β. The p-value is the probability of an equally or more extreme result assuming H0 is true, not the probability that H0 is true. Statistical significance must be separated from practical significance."},"steps":{"ar":["حدد المعلم والاتجاه One/Two-sided.","اكتب H0/H1 قبل التحليل.","اختر α وحجم أثر مهم.","تحقق من الافتراضات واحسب الإحصاء.","فسر p-value وفترة الثقة وحجم الأثر معًا."],"en":["Define the parameter and one- or two-sided direction.","Write H0 and H1 before analysis.","Choose α and a practically important effect size.","Check assumptions and calculate the statistic.","Interpret p-value, confidence interval, and effect size together."]},"example":{"ar":"عينة ضخمة قد تجعل فرق 0.01 mm ذا دلالة إحصائية لكنه غير مهم هندسيًا. القرار يحتاج حجم الأثر والمواصفة والتكلفة.","en":"A huge sample may make a 0.01 mm difference statistically significant yet engineering-irrelevant. The decision needs effect size, specification, and cost."},"tip":{"ar":"لا تكتب «نقبل H0» عادة؛ الأدق «لا توجد أدلة كافية لرفضها».","en":"Do not usually write 'accept H0'; more accurately, there is insufficient evidence to reject it."},"formula":"","question":{"q":{"ar":"ما معنى Type I Error؟","en":"What is a Type I error?"},"options":{"ar":["عدم رفض H0 وهي خاطئة","رفض H0 وهي صحيحة","قيمة p كبيرة","قوة عالية"],"en":["Failing to reject a false H0","Rejecting a true H0","A large p-value","High power"]},"answer":1,"rationale":{"ar":"Type I=α وهو False Positive في سياقات كثيرة.","en":"Type I=α and often corresponds to a false positive."}}},{"domain":6,"code":"6.10","title":{"ar":"الاختبارات المزدوجة وGoodness-of-Fit وجداول التوافق","en":"Paired Tests, Goodness-of-Fit, and Contingency Tables"},"level":"Apply","ref":"5th ed., Ch. 6; 4th ed., pp. 380–398","concept":{"ar":"Paired Test يستخدم عندما ترتبط المشاهدات مثل Before/After لنفس الوحدة، ويحلل فروق الأزواج. Goodness-of-Fit يقارن التكرارات المرصودة بالتوزيع المتوقع. Contingency Table يختبر ارتباط متغيرين فئويين، مع الانتباه للتكرارات المتوقعة والاستقلال.","en":"A paired test is used when observations are linked, such as before/after measurements on the same unit, and analyzes within-pair differences. Goodness-of-fit compares observed counts with an expected distribution. A contingency table tests association between categorical variables, with attention to expected counts and independence."},"steps":{"ar":["حدد هل العينات مستقلة أم مزدوجة.","حدد نوع المتغير والفرض.","تحقق من شروط الاختبار.","احسب الإحصاء ودرجات الحرية.","فسر العلاقة دون ادعاء السببية."],"en":["Determine whether samples are independent or paired.","Identify variable type and hypothesis.","Check test conditions.","Calculate the statistic and degrees of freedom.","Interpret association without claiming causation."]},"example":{"ar":"قياس ضغط الدم لنفس العامل قبل وبعد برنامج يحتاج Paired t-test، لا اختبار عينتين مستقلتين؛ الربط يقلل تباين الأشخاص.","en":"Measuring the same worker before and after a program requires a paired t-test, not an independent two-sample test; pairing removes person-to-person variation."},"tip":{"ar":"Chi-square مع خلايا متوقعة صغيرة قد يحتاج دمج فئات أو Fisher's Exact.","en":"Chi-square with small expected counts may require combining categories or using Fisher's exact test."},"formula":"","question":{"q":{"ar":"أي اختبار يناسب Before/After لنفس القطع؟","en":"Which test is appropriate for before/after measurements on the same parts?"},"options":{"ar":["Paired test","Independent two-sample test only","p-chart","FMEA"],"en":["Paired test","Independent two-sample test only","p-chart","FMEA"]},"answer":0,"rationale":{"ar":"المشاهدات مرتبطة داخل كل قطعة ويجب تحليل الفروق المزدوجة.","en":"Observations are linked within each part and paired differences should be analyzed."}}},{"domain":6,"code":"6.11","title":{"ar":"تحليل التباين ANOVA","en":"Analysis of Variance (ANOVA)"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 383–398","concept":{"ar":"ANOVA يقارن ثلاثة متوسطات أو أكثر عبر نسبة التباين بين المجموعات إلى داخلها. H0 تنص على تساوي المتوسطات، ورفضها يعني أن متوسطًا واحدًا على الأقل مختلف، لكنه لا يحدد أيها. تحتاج المقارنات Post-hoc مع ضبط تعدد الاختبارات.","en":"ANOVA compares three or more means using the ratio of between-group to within-group variation. H0 states that means are equal. Rejection indicates at least one mean differs but does not identify which one. Post-hoc comparisons are needed with multiplicity control."},"steps":{"ar":["حدد Factor وLevels وResponse.","تحقق من الاستقلال والطبيعية وتقارب التباين.","احسب SS وMS وF.","افحص Residuals.","استخدم Post-hoc وحجم الأثر عند الرفض."],"en":["Define factor, levels, and response.","Check independence, normality, and similar variance.","Calculate sums of squares, mean squares, and F.","Examine residuals.","Use post-hoc tests and effect size after rejection."]},"example":{"ar":"مقارنة ثلاثة موردين باختبارات t متعددة ترفع خطأ النوع الأول؛ One-way ANOVA يبدأ باختبار شامل ثم مقارنات محكومة.","en":"Comparing three suppliers with multiple t-tests inflates Type I error; one-way ANOVA begins with a global test followed by controlled comparisons."},"tip":{"ar":"p-value صغير لا يخبرك بحجم الفرق أو أهميته العملية؛ راجع Means وIntervals وEffect Size.","en":"A small p-value does not show difference magnitude or practical importance; review means, intervals, and effect size."},"formula":"","question":{"q":{"ar":"رفض H0 في ANOVA يعني:","en":"Rejecting H0 in ANOVA means:"},"options":{"ar":["كل المتوسطات مختلفة","متوسط واحد على الأقل مختلف","التباينات متساوية حتمًا","البيانات طبيعية حتمًا"],"en":["All means are different","At least one mean differs","Variances are certainly equal","Data are certainly normal"]},"answer":1,"rationale":{"ar":"الاختبار الشامل لا يحدد الأزواج المختلفة دون تحليل إضافي.","en":"The omnibus test does not identify differing pairs without further analysis."}}},{"domain":6,"code":"6.12","title":{"ar":"الانحدار والارتباط والسلاسل الزمنية","en":"Regression, Correlation, and Time-Series Analysis"},"level":"Apply","ref":"5th ed., Ch. 6; 4th ed., pp. 398–414","concept":{"ar":"Correlation يقيس قوة واتجاه العلاقة الخطية ولا يثبت السببية. Regression يقدر علاقة ويستخدم للتفسير والتنبؤ مع فحص البواقي والخطية والاستقلال وتجانس التباين. Time Series تميز Trend وSeasonality وCycles وNoise، وتستخدم Moving Average وغيرها.","en":"Correlation measures the strength and direction of linear association and does not establish causality. Regression estimates relationships for explanation and prediction, requiring checks of residuals, linearity, independence, and constant variance. Time-series analysis separates trend, seasonality, cycles, and noise and may use moving averages."},"steps":{"ar":["ارسم البيانات أولًا.","تحقق من Outliers والعلاقة غير الخطية.","ابن النموذج وافحص Residuals.","لا تستقرئ خارج النطاق بلا مبرر.","في الزمن احفظ الترتيب وتحقق من Autocorrelation."],"en":["Plot data first.","Check outliers and nonlinear patterns.","Fit the model and inspect residuals.","Avoid extrapolation without justification.","For time data, preserve order and assess autocorrelation."]},"example":{"ar":"r=0.9 بين سرعة الخط والعيوب لا يثبت أن السرعة هي السبب؛ قد تكون الحرارة أو المنتج متغيرًا ثالثًا. DOE أو تحليل متعدد قد يلزم.","en":"A correlation of r=0.9 between line speed and defects does not prove speed is causal; temperature or product mix may be a third variable. DOE or multivariable analysis may be needed."},"tip":{"ar":"R² مرتفع لا يضمن صحة النموذج إذا كانت البواقي تظهر نمطًا أو العلاقة غير مستقرة مع الزمن.","en":"High R² does not guarantee a valid model if residuals show patterns or the relationship changes over time."},"formula":"","question":{"q":{"ar":"أي عبارة صحيحة عن Correlation؟","en":"Which statement about correlation is correct?"},"options":{"ar":["يثبت السببية","لا يتأثر بالقيم الشاذة","يقيس علاقة ولا يثبت السببية","يصلح لأي علاقة دون رسم"],"en":["It proves causation","It is unaffected by outliers","It measures association but not causation","It fits any relationship without plotting"]},"answer":2,"rationale":{"ar":"الارتباط وصف للعلاقة الإحصائية وليس دليلًا سببيًا.","en":"Correlation describes statistical association, not causal proof."}}},{"domain":6,"code":"6.13","title":{"ar":"أساسيات SPC والتباين والتجميع المنطقي","en":"SPC Fundamentals, Variation, and Rational Subgrouping"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 414–416","concept":{"ar":"SPC يهدف إلى فهم سلوك العملية وفصل Common Causes الموجودة في النظام عن Special Causes غير المعتادة. Rational Subgrouping يجمع مشاهدات تكون متشابهة داخل المجموعة لالتقاط التباين قصير المدى، بينما تكشف الفروق بين المجموعات التغير عبر الزمن.","en":"SPC aims to understand process behavior and distinguish common causes inherent in the system from unusual special causes. Rational subgrouping groups observations expected to be similar within a subgroup to estimate short-term variation, while differences between subgroups reveal change over time."},"steps":{"ar":["حدد الخاصية وسبب مراقبتها.","اختر Sampling Frequency وحجم Subgroup وفق ديناميكية العملية.","حافظ على تجانس داخل المجموعة.","اجمع بيانات زمنية كافية.","لا تعدل العملية للأسباب العامة كأنها أحداث خاصة."],"en":["Define the characteristic and why it matters.","Choose sampling frequency and subgroup size based on process dynamics.","Maintain within-subgroup homogeneity.","Collect sufficient time-ordered data.","Do not adjust the process for common causes as if they were special events."]},"example":{"ar":"أخذ خمس قطع متتالية كل ساعة قد يعكس تباينًا قصيرًا داخل الساعة وتغيرًا بين الساعات. خلط قطعة من كل وردية في مجموعة واحدة يدمر المعنى الزمني.","en":"Taking five consecutive pieces every hour may capture short-term within-hour variation and between-hour change. Mixing one piece from each shift in a single subgroup destroys time meaning."},"tip":{"ar":"Tampering هو تعديل العملية بناءً على تباين عام، وغالبًا يزيد التباين.","en":"Tampering is adjusting a process in response to common variation and often increases variation."},"formula":"","question":{"q":{"ar":"ما الهدف الأساسي من Rational Subgrouping؟","en":"What is the primary purpose of rational subgrouping?"},"options":{"ar":["زيادة عدد الرسومات","فصل التباين داخل المجموعة عن التغير بين المجموعات بطريقة ذات معنى","ضمان المطابقة","إلغاء الحاجة إلى MSA"],"en":["Increase the number of charts","Meaningfully separate within-subgroup variation from between-subgroup change","Guarantee conformity","Eliminate MSA"]},"answer":1,"rationale":{"ar":"التجميع المنطقي يجعل تقدير التباين والإشارات مرتبطًا بديناميكية العملية.","en":"Rational subgrouping aligns variation estimates and signals with process dynamics."}}},{"domain":6,"code":"6.14","title":{"ar":"مخططات المتغيرات X-bar/R وX-bar/S وI-MR","en":"Variable Control Charts: X-bar/R, X-bar/S, and I-MR"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 416–443","concept":{"ar":"X-bar/R يستخدم عادة لمجموعات صغيرة من القياسات المتغيرة، وX-bar/S لمجموعات أكبر حيث S أكثر استقرارًا، وI-MR عندما توجد قراءة واحدة في كل فترة. يجب تحليل مخطط التشتت R أو S أو MR قبل الاعتماد على مخطط المتوسط.","en":"X-bar/R is commonly used for small subgroups of variable data, X-bar/S for larger subgroups where S is a better dispersion estimate, and I-MR when only one observation is available per time period. The dispersion chart R, S, or MR should be analyzed before relying on the mean or individuals chart."},"steps":{"ar":["حدد حجم Subgroup وتواتر السحب.","احسب إحصاء المركز والتشتت.","استخدم الثوابت الصحيحة A2/D3/D4 أو A3/B3/B4.","حلل مخطط التشتت أولًا.","حقق الإشارات وأعد الحدود فقط بعد تغيير مستقر مثبت."],"en":["Set subgroup size and sampling frequency.","Calculate center and dispersion statistics.","Use the correct constants A2/D3/D4 or A3/B3/B4.","Analyze the dispersion chart first.","Investigate signals and recalculate limits only after a demonstrated stable change."]},"example":{"ar":"إذا كان R Chart خارج السيطرة، فإن حدود X-bar المبنية على تشتت غير مستقر تصبح موضع شك؛ عالج التشتت أولًا.","en":"If the R chart is out of control, X-bar limits based on unstable dispersion are questionable; address dispersion first."},"tip":{"ar":"لا تحذف نقطة خارج السيطرة فقط لتجميل الرسم؛ تحتاج سببًا موثقًا وتصرفًا.","en":"Do not delete an out-of-control point merely to improve the chart; a documented assignable cause and action are needed."},"formula":"","question":{"q":{"ar":"أي مخطط يناسب قراءة واحدة كل ساعة؟","en":"Which chart is appropriate for one observation per hour?"},"options":{"ar":["X-bar/R","I-MR","np","c"],"en":["X-bar/R","I-MR","np","c"]},"answer":1,"rationale":{"ar":"I-MR يستخدم للأفراد والمدى المتحرك عندما n=1.","en":"I-MR is used for individual observations and moving ranges when n=1."}}},{"domain":6,"code":"6.15","title":{"ar":"مخططات الصفات p وnp وc وu","en":"Attribute Control Charts: p, np, c, and u"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 416–443","concept":{"ar":"p Chart يراقب نسبة الوحدات غير المطابقة ويمكن أن يتغير حجم العينة، np يراقب عدد الوحدات غير المطابقة مع n ثابت، c يراقب عدد العيوب عندما تكون فرصة العيب ثابتة، وu يراقب العيوب لكل وحدة عندما تختلف فرصة الفحص أو الحجم.","en":"A p chart monitors fraction nonconforming and can accommodate varying sample size. An np chart monitors the count of nonconforming units with constant n. A c chart monitors number of defects when opportunity is constant, while a u chart monitors defects per unit when opportunity or unit size varies."},"steps":{"ar":["ميز Defective Unit عن Defect.","حدد هل حجم العينة أو فرصة العيب ثابتة.","اختر p/np/c/u.","احسب الحدود المتغيرة عند الحاجة.","راجع Overdispersion أو تعريف فرصة غير ثابت."],"en":["Distinguish a nonconforming unit from a defect.","Determine whether sample size or opportunity is constant.","Choose p, np, c, or u.","Calculate varying limits when needed.","Evaluate overdispersion or inconsistent opportunity definitions."]},"example":{"ar":"لوحة واحدة قد تحتوي ثلاثة خدوش؛ هي وحدة غير مطابقة واحدة لكن ثلاثة عيوب. لذلك p/np يختلفان عن c/u.","en":"One panel may contain three scratches; it is one nonconforming unit but three defects. Therefore p/np differ from c/u."},"tip":{"ar":"لا تستخدم c Chart عندما يختلف حجم المنطقة المفحوصة دون تطبيع؛ استخدم u أو نموذجًا مناسبًا.","en":"Do not use a c chart when inspected area varies without normalization; use u or an appropriate model."},"formula":"","question":{"q":{"ar":"أي مخطط يناسب نسبة الوحدات غير المطابقة مع تغير حجم العينة؟","en":"Which chart is appropriate for fraction nonconforming with varying sample size?"},"options":{"ar":["np","p","c","u"],"en":["np","p","c","u"]},"answer":1,"rationale":{"ar":"p Chart يراقب النسبة ويعدل الحدود حسب n.","en":"A p chart monitors the proportion and adjusts limits for n."}}},{"domain":6,"code":"6.16","title":{"ar":"تحليل إشارات السيطرة وShort-Run SPC","en":"Control-Chart Signals and Short-Run SPC"},"level":"Evaluate","ref":"5th ed., Ch. 6; 4th ed., pp. 443–449","concept":{"ar":"عدم السيطرة قد يظهر بنقطة خارج 3σ أو أنماط غير عشوائية مثل Run على جانب واحد أو Trend أو Cycles. القواعد الإضافية ترفع الحساسية لكنها تزيد الإنذارات الكاذبة، لذلك يجب تحديدها مسبقًا. Short-Run SPC يستخدم تحويلات أو فروقًا عن Target لمراقبة منتجات متعددة بكميات قليلة.","en":"Lack of control may appear as a point beyond 3σ or nonrandom patterns such as a long run on one side, a trend, or cycles. Additional rules increase sensitivity but also false alarms, so they should be preselected. Short-run SPC uses transformations or deviations from target to monitor multiple low-volume products."},"steps":{"ar":["حدد قواعد الإشارة قبل المراقبة.","حقق التوقيت والمواد والمشغل والمعدات.","لا تعدل العملية قبل فهم السبب.","وثق السبب والتصرف والنتيجة.","استخدم Standardized Values للمنتجات المختلفة عند الحاجة."],"en":["Define signal rules before monitoring.","Investigate timing, material, operator, and equipment.","Do not adjust before understanding the cause.","Document cause, action, and result.","Use standardized values for different products when needed."]},"example":{"ar":"ثماني نقاط متتالية فوق Center Line قد تشير إلى Shift حتى لو لم تتجاوز الحدود. لكنها لا تعني أن المنتج غير مطابق؛ إنها إشارة سلوك العملية.","en":"Eight consecutive points above the center line may indicate a shift even if none exceeds limits. It does not automatically mean product is nonconforming; it signals process behavior."},"tip":{"ar":"Control Limit ليست Specification Limit، والإشارة الإحصائية ليست حكم قبول منتج.","en":"A control limit is not a specification limit, and a statistical signal is not a product-acceptance decision."},"formula":"","question":{"q":{"ar":"ما معنى نقطة خارج UCL في Control Chart؟","en":"What does a point above the UCL indicate?"},"options":{"ar":["المنتج غير مطابق حتمًا","إشارة سبب خاص محتمل تحتاج تحقيقًا","يجب تغيير المواصفة","العملية قادرة حتمًا"],"en":["The product is certainly nonconforming","A potential special-cause signal requiring investigation","The specification must change","The process is certainly capable"]},"answer":1,"rationale":{"ar":"حدود السيطرة تتعلق بالسلوك الإحصائي لا بالمطابقة الفردية.","en":"Control limits describe statistical behavior, not individual conformity."}}},{"domain":6,"code":"6.17","title":{"ar":"قدرة وأداء العملية Cp وCpk وPp وPpk","en":"Process Capability and Performance Indices"},"level":"Evaluate","ref":"5th ed., Ch. 6; 4th ed., pp. 449–457","concept":{"ar":"يجب أن تكون العملية مستقرة ونظام القياس مناسبًا قبل تفسير القدرة. Cp يقارن عرض المواصفة بـ6σ قصير المدى دون تمركز، وCpk يأخذ أقرب حد. Pp/Ppk يستخدمان التباين الكلي طويل المدى. إذا Cp مرتفع وCpk منخفض فالعملية ضيقة لكنها غير متمركزة.","en":"The process should be stable and measurement suitable before interpreting capability. Cp compares specification width with six short-term standard deviations without centering. Cpk uses the nearest specification side. Pp/Ppk use overall long-term variation. High Cp with low Cpk indicates a narrow but off-center process."},"steps":{"ar":["تحقق من Stability وMSA.","تحقق من التوزيع أو استخدم طريقة Non-normal.","احسب Cp/Cpk وPp/Ppk.","قارن المركز والتشتت.","ترجم المؤشرات إلى خطر عيب ولا تعتمد على رقم وحده."],"en":["Verify stability and MSA.","Assess distribution or use a nonnormal method.","Calculate Cp/Cpk and Pp/Ppk.","Compare centering and spread.","Translate indices into defect risk rather than relying on one number."]},"example":{"ar":"USL=10.6، LSL=9.4، σ=0.1، المتوسط=10.2: Cp=1.2/(0.6)=2.0، لكن Cpk=min(0.4/0.3,0.8/0.3)=1.33 بسبب عدم التمركز.","en":"USL=10.6, LSL=9.4, σ=0.1, mean=10.2: Cp=1.2/0.6=2.0, but Cpk=min(0.4/0.3,0.8/0.3)=1.33 because the process is off center."},"tip":{"ar":"العملية غير المستقرة قد تعطي Cpk يبدو جيدًا تاريخيًا لكنه لا يتنبأ بالمستقبل.","en":"An unstable process may show an apparently good historical Cpk but is not predictably capable."},"formula":"Cp=(USL-LSL)/(6σ); Cpk=min[(USL-μ)/(3σ),(μ-LSL)/(3σ)]","question":{"q":{"ar":"إذا Cp=1.67 وCpk=0.85، فما التفسير الأقرب؟","en":"If Cp=1.67 and Cpk=0.85, what is the most likely interpretation?"},"options":{"ar":["العملية متمركزة تمامًا","قدرة محتملة جيدة لكن العملية غير متمركزة","لا يوجد تباين","المواصفات غير موجودة"],"en":["The process is perfectly centered","Good potential capability but poor centering","There is no variation","Specifications do not exist"]},"answer":1,"rationale":{"ar":"الفجوة بين Cp وCpk تكشف أثر ابتعاد المتوسط عن المركز.","en":"The difference between Cp and Cpk reveals the effect of off-centering."}}},{"domain":6,"code":"6.18","title":{"ar":"تصميم وتحليل التجارب DOE","en":"Design and Analysis of Experiments"},"level":"Analyze","ref":"5th ed., Ch. 6; 4th ed., pp. 457–492","concept":{"ar":"DOE يغير عوامل متعددة بطريقة منظمة لقياس Main Effects وInteractions. تشمل المبادئ Randomization لتقليل تحيز الترتيب، Replication لتقدير الخطأ، Blocking لعزل مصدر معروف، وFactorial Designs لدراسة التفاعلات. Fractional Factorial يقلل Runs مقابل Confounding.","en":"DOE changes multiple factors systematically to estimate main effects and interactions. Principles include randomization to reduce order bias, replication to estimate error, blocking to isolate known nuisance variation, and factorial designs to study interactions. Fractional factorial designs reduce runs at the cost of confounding."},"steps":{"ar":["حدد الهدف وResponse والعوامل والنطاق.","اختر تصميمًا وResolution مناسبين.","Randomize وReplicate وBlock.","نفذ مع ثبات طرق القياس.","حلل Effects/Interactions/Residuals ثم Confirmatory Run."],"en":["Define objective, response, factors, and ranges.","Select a design and suitable resolution.","Randomize, replicate, and block.","Execute with consistent measurement.","Analyze effects, interactions, and residuals, then run confirmation."]},"example":{"ar":"في 2² Design لعامل الحرارة والضغط، قد يكون تأثير الحرارة موجبًا عند ضغط منخفض وسالبًا عند ضغط مرتفع؛ هذا Interaction لا يكشفه OFAT بوضوح.","en":"In a 2² design of temperature and pressure, temperature may have a positive effect at low pressure and a negative effect at high pressure; this interaction is not revealed efficiently by OFAT."},"tip":{"ar":"النموذج الإحصائي بلا Confirmation Run قد يصف البيانات الحالية ولا يثبت التحسين في التشغيل.","en":"A statistical model without a confirmation run may fit current data but does not demonstrate improvement in operation."},"formula":"","question":{"q":{"ar":"أي مبدأ في DOE يقلل أثر ترتيب التجارب والعوامل الزمنية الخفية؟","en":"Which DOE principle reduces the effect of run order and hidden time-related factors?"},"options":{"ar":["Randomization","Acceptance sampling","Calibration interval","Pareto ranking"],"en":["Randomization","Acceptance sampling","Calibration interval","Pareto ranking"]},"answer":0,"rationale":{"ar":"Randomization توزع أثر العوامل غير المسيطر عليها على التجارب.","en":"Randomization spreads uncontrolled effects across experimental runs."}}}]});


window.CQE_DOMAINS=window.CQE_DOMAINS||[];
window.CQE_DOMAINS.push({"id":7,"title":{"ar":"إدارة المخاطر","en":"Risk Management"},"weight":21,"desc":{"ar":"تحديد المخاطر وتقييمها ومعالجتها ومراقبتها واستمرارية الأعمال.","en":"Risk identification, assessment, treatment, monitoring, and business continuity."},"lessons":[{"domain":7,"code":"7.1","title":{"ar":"أساسيات المخاطر وأنواعها","en":"Risk Fundamentals and Types"},"level":"Analyze","ref":"5th ed., Ch. 7 new chapter; 2022 CQE BoK","concept":{"ar":"الخطر هو أثر عدم اليقين على الأهداف، ويمكن أن يكون تهديدًا أو فرصة. يجب التمييز بين Severity وOccurrence وDetection، وبين Inherent Risk قبل الضوابط وResidual Risk بعدها. تشمل الأنواع Enterprise وOperational وProduct Risk مثل الاستراتيجي والتنظيمي والمورد والتصنيع والتصميم والاستخدام.","en":"Risk is the effect of uncertainty on objectives and may be a threat or opportunity. Distinguish severity, occurrence, and detection, as well as inherent risk before controls and residual risk after controls. Types include enterprise, operational, and product risks such as strategic, regulatory, supplier, manufacturing, design, and use risk."},"steps":{"ar":["حدد الهدف المتأثر.","اكتب السبب والحدث والعاقبة.","حدد نوع الخطر ومالكه.","افصل الخطر الأصلي عن المتبقي.","تجنب وصف المشكلة الحالية كخطر مستقبلي بلا توضيح."],"en":["Identify the affected objective.","Write cause, event, and consequence.","Classify the risk and owner.","Separate inherent from residual risk.","Avoid describing a current issue as a future risk without clarity."]},"example":{"ar":"صياغة ضعيفة: «المورد سيئ». صياغة أقوى: «بسبب الاعتماد على مورد وحيد، قد يتأخر المكون الحرج فيتوقف الخط ويؤخر التسليم أسبوعين».","en":"Weak wording: 'the supplier is bad.' Stronger wording: 'because of single-source dependency, a critical component may be delayed, stopping the line and delaying delivery by two weeks.'"},"tip":{"ar":"الخطر ليس مجرد احتمال؛ يحتاج أثرًا على هدف محدد.","en":"Risk is not merely probability; it needs an effect on a defined objective."},"formula":"","question":{"q":{"ar":"ما تعريف Residual Risk؟","en":"What is residual risk?"},"options":{"ar":["الخطر قبل أي ضوابط","الخطر المتبقي بعد تطبيق الضوابط","الفرصة فقط","تكلفة الجودة"],"en":["Risk before any controls","Risk remaining after controls are applied","Opportunity only","Cost of quality"]},"answer":1,"rationale":{"ar":"Residual Risk هو ما يبقى بعد الوقاية أو التخفيف أو النقل.","en":"Residual risk remains after prevention, mitigation, or transfer."}}},{"domain":7,"code":"7.2","title":{"ar":"خطة إدارة المخاطر والمعايير وأصحاب المصلحة","en":"Risk Management Plan, Criteria, and Stakeholders"},"level":"Analyze","ref":"5th ed., Ch. 7; 2022 CQE BoK","concept":{"ar":"خطة المخاطر تحدد الأهداف والنطاق والمنهج والمقاييس ومعايير القبول والأدوار والتصعيد والتوثيق والمراجعة. يجب أن تحدد Risk Appetite وTolerance وطرق التقييم، وأن تشرك أصحاب المصلحة المتأثرين بدل أن تكون تمرينًا لقسم الجودة فقط.","en":"A risk management plan defines objectives, scope, methodology, metrics, acceptance criteria, roles, escalation, documentation, and review. It should define risk appetite, tolerance, and assessment methods and involve affected stakeholders rather than remaining a quality-department exercise."},"steps":{"ar":["حدد السياق والأهداف.","حدد معايير Severity/Occurrence/Acceptability.","عين المالك والفريق وRACI.","اختر أدوات التقييم والتوثيق.","حدد دورية المراجعة والتصعيد."],"en":["Define context and objectives.","Set severity, occurrence, and acceptability criteria.","Assign owner, team, and RACI.","Select assessment and documentation tools.","Define review and escalation frequency."]},"example":{"ar":"خطر أمان عالي الشدة قد يكون غير مقبول مهما كان الاحتمال منخفضًا، بينما خطر تكلفة صغير قد يقبل بموافقة مالك مناسب.","en":"A high-severity safety risk may be unacceptable even at low probability, while a small cost risk may be accepted by the appropriate owner."},"tip":{"ar":"لا تغيّر حدود القبول بعد ظهور النتيجة لتجنب الإجراء؛ حددها مسبقًا.","en":"Do not change acceptance thresholds after seeing results to avoid action; define them in advance."},"formula":"","question":{"q":{"ar":"ما العنصر الذي يجب تحديده قبل تقييم المخاطر لضمان اتساق القرارات؟","en":"What should be defined before risk assessment to ensure consistent decisions?"},"options":{"ar":["ألوان العرض فقط","معايير التقييم والقبول","اسم المدقق فقط","عدد الشرائح"],"en":["Presentation colors only","Assessment and acceptance criteria","Auditor name only","Number of slides"]},"answer":1,"rationale":{"ar":"المعايير المسبقة تمنع تغيير القرار حسب النتيجة أو الشخص.","en":"Predefined criteria prevent decisions from shifting with the result or evaluator."}}},{"domain":7,"code":"7.3","title":{"ar":"تحديد المخاطر وRisk Register","en":"Risk Identification and the Risk Register"},"level":"Analyze","ref":"5th ed., Ch. 7; 2022 CQE BoK","concept":{"ar":"تحديد المخاطر يستخدم البيانات والشكاوى والتدقيق وFMEA وLessons Learned وProcess Mapping وSWOT وورش الخبراء. Risk Register يوثق الوصف والسبب والعاقبة والتقييم والضوابط والمالك والإجراء والموعد والحالة والخطر المتبقي.","en":"Risk identification uses data, complaints, audits, FMEA, lessons learned, process mapping, SWOT, and expert workshops. A risk register records description, cause, consequence, rating, controls, owner, action, due date, status, and residual risk."},"steps":{"ar":["استخدم مصادر تاريخية ومستقبلية.","اكتب كل خطر Cause–Event–Effect.","تجنب دمج مخاطر مختلفة في سطر واحد.","حدد الضوابط الحالية قبل الإجراء الجديد.","راجع السجل عند التغيير والشكاوى والإشارات."],"en":["Use historical and forward-looking sources.","Write each risk as cause-event-effect.","Avoid combining different risks in one line.","Identify existing controls before new actions.","Review the register after changes, complaints, and signals."]},"example":{"ar":"«فشل النظام» واسع جدًا. يجب تقسيمه إلى أسباب مثل انقطاع الطاقة، فساد البيانات، فشل واجهة، أو خطأ استخدام، لأن كل سبب يحتاج ضبطًا مختلفًا.","en":"'System failure' is too broad. Split it into power loss, data corruption, interface failure, or use error because each requires different controls."},"tip":{"ar":"سجل المخاطر وثيقة حية، وليس قائمة تُغلق بعد ورشة واحدة.","en":"A risk register is a living document, not a list completed after one workshop."},"formula":"","question":{"q":{"ar":"أي وصف للمخاطر هو الأفضل؟","en":"Which risk statement is best?"},"options":{"ar":["الجودة ضعيفة","المورد مشكلة","بسبب مورد وحيد قد يتأخر الجزء الحرج، ما يوقف الإنتاج ويؤخر التسليم","نحتاج اجتماعًا"],"en":["Quality is poor","The supplier is a problem","Because of a single source, the critical part may be delayed, stopping production and delaying delivery","We need a meeting"]},"answer":2,"rationale":{"ar":"يتضمن السبب والحدث والأثر على الهدف.","en":"It includes cause, event, and effect on the objective."}}},{"domain":7,"code":"7.4","title":{"ar":"تقييم المخاطر: المصفوفة وRPN وFMEA","en":"Risk Assessment: Matrices, RPN, and FMEA"},"level":"Analyze","ref":"5th ed., Ch. 7; 2022 CQE BoK","concept":{"ar":"يقيّم الخطر عادة عبر Severity وLikelihood وقد يضيف Detection. Risk Matrix تسهل التصنيف لكنها قد تخفي اختلافات عددية؛ RPN=S×O×D أداة ترتيب تقليدية لكنها غير خطية ويمكن أن تعطي نفس الرقم لتركيبات مختلفة. يجب استخدام الحكم والمعايير والشدة الحرجة بجانب الرقم.","en":"Risk is often assessed through severity and likelihood and may include detection. A risk matrix simplifies classification but can hide numeric differences. RPN=S×O×D is a traditional prioritization tool, but it is nonlinear and can give the same score to very different combinations. Judgment, criteria, and critical severity must accompany the number."},"steps":{"ar":["حدد المقاييس وأوصاف كل مستوى.","قيّم الضوابط الحالية لا الإجراءات المخططة.","سجل مبرر التقييم.","راجع المخاطر عالية الشدة منفصلة عن RPN.","استخدم الفريق والبيانات لتقليل التحيز."],"en":["Define scales and descriptors for each level.","Rate current controls, not planned actions.","Document the rationale.","Review high-severity risks separately from RPN.","Use a team and data to reduce bias."]},"example":{"ar":"RPN=200 قد يأتي من S=10,O=2,D=10 أو S=5,O=8,D=5؛ المعنى والإجراء مختلفان رغم الرقم نفسه.","en":"An RPN of 200 may come from S=10,O=2,D=10 or S=5,O=8,D=5; meaning and action differ despite the same number."},"tip":{"ar":"لا تخفض Severity بتدريب أو فحص إذا لم تتغير عاقبة الفشل نفسها.","en":"Do not reduce severity because of training or inspection if the failure consequence itself has not changed."},"formula":"RPN = Severity × Occurrence × Detection","question":{"q":{"ar":"ما القيد الأساسي في استخدام RPN وحده؟","en":"What is a key limitation of using RPN alone?"},"options":{"ar":["لا يحتوي أرقامًا","قد يعطي الرقم نفسه لتركيبات مخاطر مختلفة ويخفي الشدة العالية","لا يمكن حسابه","يستخدم التكلفة فقط"],"en":["It contains no numbers","It can give the same score to different risk combinations and hide high severity","It cannot be calculated","It uses cost only"]},"answer":1,"rationale":{"ar":"الرقم الواحد لا يحفظ بنية الشدة والحدوث والكشف.","en":"A single number does not preserve the structure of severity, occurrence, and detection."}}},{"domain":7,"code":"7.5","title":{"ar":"تقييم القبول والخطر المتبقي","en":"Risk Evaluation, Acceptability, and Residual Risk"},"level":"Analyze","ref":"5th ed., Ch. 7; 2022 CQE BoK","concept":{"ar":"بعد التحليل تُقارن النتيجة بمعايير القبول لتحديد الحاجة إلى معالجة أو تصعيد. يجب تقييم Inherent Risk ثم فعالية الضوابط وResidual Risk. قبول الخطر قرار واعٍ ومخول ومبرر، ولا يعني تجاهله.","en":"After analysis, results are compared with acceptance criteria to determine treatment or escalation. Inherent risk is evaluated first, then control effectiveness and residual risk. Risk acceptance is a conscious, authorized, justified decision and does not mean ignoring the risk."},"steps":{"ar":["قارن النتيجة بالمعايير.","راجع المتطلبات القانونية أو السلامة التي تمنع القبول.","قيّم فعالية الضوابط بالأدلة.","احسب أو صنف Residual Risk.","احصل على موافقة المالك المناسب وراقب."],"en":["Compare the result with criteria.","Review legal or safety requirements that prohibit acceptance.","Evaluate control effectiveness using evidence.","Calculate or classify residual risk.","Obtain appropriate owner approval and monitor."]},"example":{"ar":"خطر متوسط بعد ضبط مثبت قد يُقبل مؤقتًا مع Monitoring، لكن خطر أمان غير مقبول لا يصبح مقبولًا لأن تكلفة الحل عالية.","en":"A medium risk after a proven control may be temporarily accepted with monitoring, but an unacceptable safety risk does not become acceptable simply because mitigation is costly."},"tip":{"ar":"استخدام كلمة «مقبول» يحتاج ذكر من قبل القرار وعلى أي معيار.","en":"Calling a risk 'acceptable' requires identifying who approved it and against which criteria."},"formula":"","question":{"q":{"ar":"متى يمكن اعتبار الخطر مقبولًا؟","en":"When can a risk be considered acceptable?"},"options":{"ar":["عندما لا يرغب الفريق في العمل عليه","عندما يحقق معايير القبول ويوافق عليه المالك المخول مع مراقبة مناسبة","عندما يكون RPN منخفضًا فقط","عندما لا توجد بيانات"],"en":["When the team does not want to address it","When it meets acceptance criteria and is approved by the authorized owner with appropriate monitoring","When RPN alone is low","When data are unavailable"]},"answer":1,"rationale":{"ar":"القبول قرار قائم على معيار وسلطة ومراقبة، لا على التجاهل.","en":"Acceptance is based on criteria, authority, and monitoring, not neglect."}}},{"domain":7,"code":"7.6","title":{"ar":"استراتيجيات معالجة المخاطر","en":"Risk Treatment Strategies"},"level":"Analyze","ref":"5th ed., Ch. 7; 2022 CQE BoK","concept":{"ar":"استراتيجيات التهديدات تشمل Avoid بإلغاء النشاط أو التصميم، Mitigate بخفض الاحتمال أو الأثر، Transfer/Share بالعقد أو التأمين أو الشريك، وAccept بقرار واعٍ. ترتيب الضوابط يفضل الإزالة والتصميم الوقائي قبل الإجراءات الإدارية والكشف المتأخر.","en":"Threat-treatment strategies include avoidance by eliminating the activity or design, mitigation by reducing likelihood or impact, transfer/share through contract, insurance, or partner, and acceptance by conscious decision. Control hierarchy generally favors elimination and engineered prevention before administrative controls and late detection."},"steps":{"ar":["حدد الهدف من المعالجة.","اختر استراتيجية تناسب السبب والعاقبة.","قيّم التكلفة والمخاطر الجانبية.","حدد المالك والموعد ومؤشر الإنجاز.","أعد تقييم Residual Risk بعد التنفيذ."],"en":["Define treatment objective.","Choose a strategy appropriate to cause and consequence.","Evaluate cost and secondary risks.","Assign owner, due date, and completion measure.","Reassess residual risk after implementation."]},"example":{"ar":"الاعتماد على موردين بدل مورد واحد Mitigate/Share، شراء تأمين Transfer مالي، وإلغاء مادة خطرة Avoid. لا تنتقل المخاطر التشغيلية بالكامل لمجرد وجود عقد.","en":"Using two suppliers instead of one mitigates/shares risk, insurance transfers financial consequence, and eliminating a hazardous material avoids risk. Operational risk is not fully transferred merely because a contract exists."},"tip":{"ar":"Transfer ينقل جزءًا من الأثر أو المسؤولية لكنه لا يلغي واجب الرقابة.","en":"Transfer moves part of consequence or responsibility but does not eliminate oversight."},"formula":"","question":{"q":{"ar":"أي مثال يمثل Avoidance؟","en":"Which example represents risk avoidance?"},"options":{"ar":["شراء تأمين","إلغاء استخدام مادة خطرة من التصميم","زيادة الفحص","قبول الخطر"],"en":["Buy insurance","Eliminate use of a hazardous material from the design","Increase inspection","Accept the risk"]},"answer":1,"rationale":{"ar":"الإلغاء يزيل النشاط أو المصدر الذي ينشئ الخطر.","en":"Avoidance removes the activity or source creating the risk."}}},{"domain":7,"code":"7.7","title":{"ar":"اختبار الضوابط والتدقيق والمراقبة","en":"Control Testing, Auditing, and Risk Monitoring"},"level":"Apply","ref":"5th ed., Ch. 7; 2022 CQE BoK","concept":{"ar":"يجب اختبار تصميم الضبط وتنفيذه وفعاليته التشغيلية. التدقيق يراجع النظام والأدلة، بينما Monitoring يتابع مؤشرات مثل الشكاوى والاتجاهات وNear Miss وSupplier Performance وPost-Market Surveillance. الضبط المكتوب غير الفعال لا يخفض الخطر فعليًا.","en":"Control evaluation should test design, implementation, and operating effectiveness. Auditing reviews the system and evidence, while monitoring tracks complaints, trends, near misses, supplier performance, and post-market surveillance. A documented but ineffective control does not truly reduce risk."},"steps":{"ar":["حدد هدف الضبط وطريقة عمله.","اختبر Design Adequacy.","خذ عينة من التشغيل الفعلي.","قارن النتائج بمعيار الفعالية.","تابع المؤشرات وحدد Trigger للتصعيد."],"en":["Define the control objective and mechanism.","Test design adequacy.","Sample actual operation.","Compare results with effectiveness criteria.","Monitor indicators and define escalation triggers."]},"example":{"ar":"إجراء يتطلب مراجعة شهرية موجود، لكن السجلات تظهر أن المراجعة لا تحدث ولا تُكتشف الانحرافات؛ الضبط مصمم لكنه غير فعال تشغيليًا.","en":"A procedure requires monthly review, but records show the review does not occur and deviations are not detected; the control exists in design but is not operationally effective."},"tip":{"ar":"وجود Policy أو Checklist لا يثبت فعالية الضبط؛ ابحث عن التنفيذ والنتيجة.","en":"A policy or checklist does not prove control effectiveness; verify operation and outcome."},"formula":"","question":{"q":{"ar":"ما الدليل الأقوى على فعالية ضبط خطر؟","en":"What is the strongest evidence that a risk control is effective?"},"options":{"ar":["وجود الإجراء فقط","توقيع المدير فقط","تنفيذ الضبط باستمرار وتحقيق مؤشر النتيجة دون تكرار غير مقبول","لون النموذج"],"en":["The procedure exists","Manager signature only","Consistent control operation and achievement of outcome measures without unacceptable recurrence","Form color"]},"answer":2,"rationale":{"ar":"الفعالية تحتاج تشغيلًا ونتيجة قابلة للقياس.","en":"Effectiveness requires operation and measurable outcome."}}},{"domain":7,"code":"7.8","title":{"ar":"استمرارية الأعمال والمرونة وخطط الطوارئ","en":"Business Continuity, Resilience, and Contingency Planning"},"level":"Analyze","ref":"5th ed., Ch. 7 and supplier-risk additions; 2022 CQE BoK","concept":{"ar":"Business Continuity يحدد العمليات الحرجة والموارد والحد الأدنى المقبول وRTO/RPO ومسارات الاستعادة. Resilience هي قدرة النظام على الامتصاص والتكيف والتعافي. Contingency Plan يحدد ما يحدث عند Trigger محدد، والمسؤول والاتصال والبدائل والاختبار.","en":"Business continuity identifies critical processes, resources, minimum acceptable operation, RTO/RPO, and recovery paths. Resilience is the ability to absorb, adapt, and recover. A contingency plan defines actions, owners, communications, alternatives, and testing for a specific trigger."},"steps":{"ar":["نفذ Business Impact Analysis.","حدد العمليات والموارد الحرجة.","حدد RTO وRPO والبدائل.","اكتب سيناريوهات وTriggers وخطط اتصال.","اختبر Tabletop وSimulation وحدّث الخطة."],"en":["Perform a business impact analysis.","Identify critical processes and resources.","Set RTO, RPO, and alternatives.","Write scenarios, triggers, and communications.","Test through tabletop and simulation and update the plan."]},"example":{"ar":"نسخة Backup غير مختبرة ليست خطة استمرارية. يجب إثبات القدرة على الاستعادة ضمن RTO وبفقد بيانات لا يتجاوز RPO.","en":"An untested backup is not a continuity plan. Recovery must be demonstrated within RTO and with data loss no greater than RPO."},"tip":{"ar":"الخطة التي لم تُختبر قد تفشل بسبب أرقام اتصال قديمة أو صلاحيات غير متاحة أو مورد بديل غير مؤهل.","en":"An untested plan may fail because of outdated contacts, unavailable permissions, or an unqualified alternative supplier."},"formula":"","question":{"q":{"ar":"ما الفرق بين RTO وRPO؟","en":"What is the difference between RTO and RPO?"},"options":{"ar":["RTO زمن الاستعادة المستهدف وRPO مقدار فقد البيانات الزمني المقبول","لا فرق","RTO للمورد وRPO للجودة فقط","كلاهما مؤشر عيوب"],"en":["RTO is target recovery time; RPO is acceptable data-loss time window","There is no difference","RTO is only for suppliers and RPO only for quality","Both are defect metrics"]},"answer":0,"rationale":{"ar":"RTO يركز على مدة استعادة الخدمة وRPO على نقطة البيانات التي يجب استعادتها.","en":"RTO focuses on service restoration time; RPO on the data recovery point."}}}]});



